47	/* Return the size consumed from the allocator, for the specified SDS string,
48	 * including internal fragmentation. This function is used in order to compute
49	 * the client output buffer size. */
50	size_t sdsZmallocSize(sds s) {
51	    void *sh = sdsAllocPtr(s);
52	    return zmalloc_size(sh);
53	}
54	
55	/* Return the amount of memory used by the sds string at object->ptr
56	 * for a string object. This includes internal fragmentation. */
57	size_t getStringObjectSdsUsedMemory(robj *o) {
58	    serverAssertWithInfo(NULL,o,o->type == OBJ_STRING);
59	    switch(o->encoding) {
60	    case OBJ_ENCODING_RAW: return sdsZmallocSize(o->ptr);
61	    case OBJ_ENCODING_EMBSTR: return zmalloc_size(o)-sizeof(robj);
62	    default: return 0; /* Just integer encoding for now. */
63	    }
64	}
65	
66	/* Return the length of a string object.
67	 * This does NOT includes internal fragmentation or sds unused space. */
68	size_t getStringObjectLen(robj *o) {
69	    serverAssertWithInfo(NULL,o,o->type == OBJ_STRING);
70	    switch(o->encoding) {
71	    case OBJ_ENCODING_RAW: return sdslen(o->ptr);
72	    case OBJ_ENCODING_EMBSTR: return sdslen(o->ptr);
73	    default: return 0; /* Just integer encoding for now. */
74	    }
75	}
