78	void *dupClientReplyValue(void *o) {
79	    clientReplyBlock *old = o;
80	    clientReplyBlock *buf = zmalloc(sizeof(clientReplyBlock) + old->size);
81	    memcpy(buf, o, sizeof(clientReplyBlock) + old->size);
82	    return buf;
