2114	/* Release references to string objects inside an encoded buffer.
2115	 * If running in IO thread, defer the free to main thread via io_deferred_objects. */
2116	static void releaseBufReferences(client *c, char *buf, size_t bufpos) {
2117	    int in_io_thread = (c && c->running_tid != IOTHREAD_MAIN_THREAD_ID);
2118	    char *ptr = buf;
2119	    while (ptr < buf + bufpos) {
2120	        payloadHeader *header = (payloadHeader *)ptr;
2121	        ptr += sizeof(payloadHeader);
2122	
2123	        if (header->payload_type == BULK_STR_REF) {
2124	            bulkStrRef *str_ref = (bulkStrRef *)ptr;
2125	            /* Only release if not already released. */
2126	            if (str_ref->obj != NULL) {
2127	                c->reply_bytes_shared -= sdslen(str_ref->obj->ptr);
2128	                if (in_io_thread)
2129	                    ioDeferFreeRobj(c, str_ref->obj);
2130	                else
2131	                    decrRefCount(str_ref->obj);
2132	                str_ref->obj = NULL;
2133	            }
2134	        } else {
2135	            serverAssert(header->payload_type == PLAIN_REPLY);
2136	        }
2137	
2138	        ptr += header->payload_len;
2139	    }
2140	}
