2159	void freeClient(client *c) {
2160	    listNode *ln;
2161	
2162	    /* If a client is protected, yet we need to free it right now, make sure
2163	     * to at least use asynchronous freeing. */
2164	    if (c->flags & CLIENT_PROTECTED) {
2165	        freeClientAsync(c);
2166	        return;
2167	    }
2168	
2169	    /* If the client is running in io thread, we can't free it directly. */
2170	    if (c->running_tid != IOTHREAD_MAIN_THREAD_ID) {
2171	        fetchClientFromIOThread(c);
2172	    }
2173	
2174	    /* We need to unbind connection of client from io thread event loop first. */
2175	    if (c->tid != IOTHREAD_MAIN_THREAD_ID) {
2176	        keepClientInMainThread(c);
2177	    }
2178	
2179	    /* Update the number of clients in the IO thread. */
2180	    if (c->conn) server.io_threads_clients_num[c->tid]--;
2181	
2182	    /* For connected clients, call the disconnection event of modules hooks. */
2183	    if (c->conn) {
2184	        moduleFireServerEvent(REDISMODULE_EVENT_CLIENT_CHANGE,
2185	                              REDISMODULE_SUBEVENT_CLIENT_CHANGE_DISCONNECTED,
2186	                              c);
2187	    }
2188	
2189	    asmCallbackOnFreeClient(c);
2190	
2191	    /* Notify module system that this client auth status changed. */
2192	    moduleNotifyUserChanged(c);
2193	
2194	    /* Free the RedisModuleBlockedClient held onto for reprocessing if not already freed. */
2195	    zfree(c->module_blocked_client);
2196	
2197	    /* If this client was scheduled for async freeing we need to remove it
2198	     * from the queue. Note that we need to do this here, because later
2199	     * we may call replicationCacheMaster() and the client should already
2200	     * be removed from the list of clients to free. */
2201	    if (c->flags & CLIENT_CLOSE_ASAP) {
2202	        ln = listSearchKey(server.clients_to_close,c);
2203	        serverAssert(ln != NULL);
2204	        listDelNode(server.clients_to_close,ln);
2205	    }
2206	
2207	    /* If it is our master that's being disconnected we should make sure
2208	     * to cache the state to try a partial resynchronization later.
2209	     *
2210	     * Note that before doing this we make sure that the client is not in
2211	     * some unexpected state, by checking its flags. */
2212	    if (server.master && c->flags & CLIENT_MASTER) {
2213	        serverLog(LL_NOTICE,"Connection with master lost.");
2214	        if (!(c->flags & (CLIENT_PROTOCOL_ERROR|CLIENT_BLOCKED))) {
2215	            c->flags &= ~(CLIENT_CLOSE_ASAP|CLIENT_CLOSE_AFTER_REPLY);
2216	            c->io_flags &= ~CLIENT_IO_CLOSE_ASAP;
2217	            replicationCacheMaster(c);
2218	            return;
2219	        }
2220	    }
2221	
2222	    /* Log link disconnection with slave */
2223	    if (clientTypeIsSlave(c)) {
2224	        const char *type = c->flags & CLIENT_REPL_RDB_CHANNEL ? " (rdbchannel)" : "";
2225	        serverLog(LL_NOTICE,"Connection with replica%s %s lost.", type,
2226	            replicationGetSlaveName(c));
2227	    }
2228	
2229	    /* Free the query buffer */
2230	    if (c->io_flags & CLIENT_IO_REUSABLE_QUERYBUFFER)
2231	        resetReusableQueryBuf(c);
2232	    sdsfree(c->querybuf);
2233	    c->querybuf = NULL;
2234	
2235	    /* Deallocate structures used to block on blocking ops. */
2236	    /* If there is any in-flight command, we don't record their duration. */
2237	    c->duration = 0;
2238	    if (c->flags & CLIENT_BLOCKED) unblockClient(c, 1);
2239	    dictRelease(c->bstate.keys);
2240	
2241	    /* UNWATCH all the keys */
2242	    unwatchAllKeys(c);
2243	    listRelease(c->watched_keys);
2244	
2245	    /* Unsubscribe from all the pubsub channels */
2246	    pubsubUnsubscribeAllChannels(c,0);
2247	    pubsubUnsubscribeShardAllChannels(c, 0);
2248	    pubsubUnsubscribeAllPatterns(c,0);
2249	    unmarkClientAsPubSub(c);
2250	    dictRelease(c->pubsub_channels);
2251	    dictRelease(c->pubsub_patterns);
2252	    dictRelease(c->pubsubshard_channels);
2253	
2254	    /* Free data structures. */
2255	    releaseAllBufReferences(c); /* Release all references to string objects in encoded buffers before freeing */
2256	    listRelease(c->reply);
2257	    zfree(c->buf);
2258	    freeReplicaReferencedReplBuffer(c);
2259	    freeClientOriginalArgv(c);
2260	    freeClientDeferredObjects(c, 1);
2261	    freeClientIODeferredObjects(c, 1);
2262	    tryUnlinkClientFromPendingRefReply(c, 1);
2263	    if (c->deferred_reply_errors)
2264	        listRelease(c->deferred_reply_errors);
2265	#ifdef LOG_REQ_RES
2266	    reqresReset(c, 1);
2267	#endif
2268	
2269	    /* Remove the contribution that this client gave to our incrementally
2270	     * computed memory usage. The cached master must be included too: its conn
2271	     * was already detached by replicationCacheMaster(), so gating on c->conn
2272	     * alone would skip the subtraction and leak its size from
2273	     * mem_clients_normal on every discarded partial resync. */
2274	    if (c->conn || c == server.cached_master)
2275	        server.stat_clients_type_memory[c->last_memory_type] -=
2276	            c->last_memory_usage;
2277	
2278	    /* Unlink the client: this will close the socket, remove the I/O
2279	     * handlers, and remove references of the client from different
2280	     * places where active clients may be referenced.
2281	     * This will also clean all remaining pending commands in the client,
2282	     * as they are no longer valid.
2283	     */
2284	    unlinkClient(c);
2285	
2286	    freeClientMultiState(c);
2287	    serverAssert(c->pending_cmds.len == 0);
2288	
2289	    /* Master/slave cleanup Case 1:
2290	     * we lost the connection with a slave. */
2291	    if (c->flags & CLIENT_SLAVE) {
2292	        /* If there is no any other slave waiting dumping RDB finished, the
2293	         * current child process need not continue to dump RDB, then we kill it.
2294	         * So child process won't use more memory, and we also can fork a new
2295	         * child process asap to dump rdb for next full synchronization or bgsave.
2296	         * But we also need to check if users enable 'save' RDB, if enable, we
2297	         * should not remove directly since that means RDB is important for users
2298	         * to keep data safe and we may delay configured 'save' for full sync. */
2299	        if (server.saveparamslen == 0 &&
2300	            c->replstate == SLAVE_STATE_WAIT_BGSAVE_END &&
2301	            server.child_type == CHILD_TYPE_RDB &&
2302	            server.rdb_child_type == RDB_CHILD_TYPE_DISK &&
2303	            anyOtherSlaveWaitRdb(c) == 0)
2304	        {
2305	            killRDBChild();
2306	        }
2307	        if (c->replstate == SLAVE_STATE_SEND_BULK) {
2308	            if (c->repldbfd != -1) close(c->repldbfd);
2309	            if (c->replpreamble) sdsfree(c->replpreamble);
2310	        }
2311	        list *l = (c->flags & CLIENT_MONITOR) ? server.monitors : server.slaves;
2312	        ln = listSearchKey(l,c);
2313	        serverAssert(ln != NULL);
2314	        listDelNode(l,ln);
2315	        /* We need to remember the time when we started to have zero
2316	         * attached slaves, as after some time we'll free the replication
2317	         * backlog. */
2318	        if (clientTypeIsSlave(c) && listLength(server.slaves) == 0)
2319	            server.repl_no_slaves_since = server.unixtime;
2320	        refreshGoodSlavesCount();
2321	        /* Fire the replica change modules event. */
2322	        if (c->replstate == SLAVE_STATE_ONLINE)
2323	            moduleFireServerEvent(REDISMODULE_EVENT_REPLICA_CHANGE,
2324	                                  REDISMODULE_SUBEVENT_REPLICA_CHANGE_OFFLINE,
2325	                                  NULL);
2326	    }
2327	
2328	    /* Master/slave cleanup Case 2:
2329	     * we lost the connection with the master. */
2330	    if (c->flags & CLIENT_MASTER) replicationHandleMasterDisconnection();
2331	
2332	    /* Remove client from memory usage buckets */
2333	    if (c->mem_usage_bucket) {
2334	        c->mem_usage_bucket->mem_usage_sum -= c->last_memory_usage;
2335	        listDelNode(c->mem_usage_bucket->clients, c->mem_usage_bucket_node);
2336	    }
2337	
2338	    /* Release other dynamically allocated client structure fields,
2339	     * and finally release the client structure itself. */
2340	    if (c->name) decrRefCount(c->name);
2341	    if (c->lib_name) decrRefCount(c->lib_name);
2342	    if (c->lib_ver) decrRefCount(c->lib_ver);
2343	    serverAssert(c->all_argv_len_sum == 0);
2344	    sdsfree(c->peerid);
2345	    sdsfree(c->sockname);
2346	    sdsfree(c->slave_addr);
2347	    sdsfree(c->node_id);
2348	    zfree(c);
2349	}
