2351	/* Schedule a client to free it at a safe time in the beforeSleep() function.
2352	 * This function is useful when we need to terminate a client but we are in
2353	 * a context where calling freeClient() is not possible, because the client
2354	 * should be valid for the continuation of the flow of the program. */
2355	void freeClientAsync(client *c) {
2356	    if (c->running_tid != IOTHREAD_MAIN_THREAD_ID) {
2357	        int main_thread = pthread_equal(pthread_self(), server.main_thread_id);
2358	        /* Make sure the main thread can access IO thread data safely. */
2359	        if (main_thread) pauseIOThread(c->tid);
2360	        if (!(c->io_flags & CLIENT_IO_CLOSE_ASAP)) {
2361	            c->io_flags |= CLIENT_IO_CLOSE_ASAP;
2362	            enqueuePendingClientsToMainThread(c, 1);
2363	        }
2364	        if (main_thread) resumeIOThread(c->tid);
2365	        return;
2366	    }
2367	
2368	    if (c->flags & CLIENT_CLOSE_ASAP || c->flags & CLIENT_SCRIPT) return;
2369	    c->flags |= CLIENT_CLOSE_ASAP;
2370	    /* Replicas that was marked as CLIENT_CLOSE_ASAP should not keep the
2371	     * replication backlog from been trimmed. */
2372	    if (c->flags & CLIENT_SLAVE) freeReplicaReferencedReplBuffer(c);
2373	    listAddNodeTail(server.clients_to_close,c);
2374	}
