2392	/* Perform processing of the client before moving on to processing the next client
2393	 * this is useful for performing operations that affect the global state but can't
2394	 * wait until we're done with all clients. In other words can't wait until beforeSleep()
2395	 * return C_ERR in case client is no longer valid after call.
2396	 * The input client argument: c, may be NULL in case the previous client was
2397	 * freed before the call. */
2398	int beforeNextClient(client *c) {
2399	    /* Notice, this code is also called from 'processUnblockedClients'.
2400	     * But in case of a module blocked client (see RM_Call 'K' flag) we do not reach this code path.
2401	     * So whenever we change the code here we need to consider if we need this change on module
2402	     * blocked client as well */
2403	
2404	    /* Skip the client processing if we're in an IO thread, in that case we'll perform
2405	       this operation later (this function is called again) in the fan-in stage of the threading mechanism */
2406	    if (c && c->running_tid != IOTHREAD_MAIN_THREAD_ID)
2407	        return C_OK;
2408	    /* Handle async frees */
2409	    /* Note: this doesn't make the server.clients_to_close list redundant because of
2410	     * cases where we want an async free of a client other than myself. For example
2411	     * in ACL modifications we disconnect clients authenticated to non-existent
2412	     * users (see ACL LOAD). */
2413	    if (c && (c->flags & CLIENT_CLOSE_ASAP)) {
2414	        freeClient(c);
2415	        return C_ERR;
2416	    }
2417	    return C_OK;
2418	}
