2422	int freeClientsInAsyncFreeQueue(void) {
2423	    int freed = 0;
2424	    listIter li;
2425	    listNode *ln;
2426	
2427	    listRewind(server.clients_to_close,&li);
2428	    while ((ln = listNext(&li)) != NULL) {
2429	        client *c = listNodeValue(ln);
