2431	        if (c->flags & CLIENT_PROTECTED) continue;
2432	
2433	        c->flags &= ~CLIENT_CLOSE_ASAP;
2434	        freeClient(c);
2435	        listDelNode(server.clients_to_close,ln);
2436	        freed++;
