2451	/* This struct is used by writevToClient to prepare iovec array for submitting to connWritev */
2452	typedef struct ReplyIOV {
2453	    struct iovec *iov;      /* Array of iovec structures for writev() */
2454	    int iovmax;             /* Maximum number of iovec entries allocated */
2455	    int iovcnt;             /* Current number of iovec entries in use */
2456	    size_t iov_bytes_len;   /* Total bytes across all iovec entries */
2457	} ReplyIOV;
2458	
2459	/* Check if the reply IOV has reached its limit yet. */
2460	static int replyIOVReachLimit(ReplyIOV *reply_iov) {
2461	    return reply_iov->iovcnt >= reply_iov->iovmax || reply_iov->iov_bytes_len >= NET_MAX_WRITES_PER_EVENT;
2462	}
2463	
2464	/* Helper function to process encoded buffer and build iov array. */
2465	static void processEncodedBufferForWrite(ReplyIOV *reply_iov, char *start_ptr, char *end_ptr, size_t offset) {
2466	    char *ptr = start_ptr;
2467	    while (ptr < end_ptr && !replyIOVReachLimit(reply_iov)) {
2468	        payloadHeader *head = (payloadHeader *)ptr;
2469	
2470	        if (head->payload_type == PLAIN_REPLY) {
2471	            /* Plain data - add directly */
2472	            reply_iov->iov[reply_iov->iovcnt].iov_base = ptr + sizeof(payloadHeader) + offset;
2473	            reply_iov->iov[reply_iov->iovcnt].iov_len = head->payload_len - offset;
2474	            reply_iov->iov_bytes_len += reply_iov->iov[reply_iov->iovcnt++].iov_len;
2475	        } else {
2476	            /* BULK_STR_REF - expand to prefix + string + crlf (format prefix at write time) */
2477	            bulkStrRef *str_ref = (bulkStrRef *)(ptr + sizeof(payloadHeader));
2478	            size_t prefix_len = formatBulkStrRefPrefix(str_ref);
2479	            size_t str_len = sdslen(str_ref->obj->ptr);
2480	
2481	            /* Add prefix */
2482	            if (offset < prefix_len) {
2483	                if (replyIOVReachLimit(reply_iov)) return;
2484	                reply_iov->iov[reply_iov->iovcnt].iov_base = str_ref->prefix + offset;
2485	                reply_iov->iov[reply_iov->iovcnt].iov_len = prefix_len - offset;
2486	                reply_iov->iov_bytes_len += reply_iov->iov[reply_iov->iovcnt++].iov_len;
2487	                offset = 0;
2488	            } else {
2489	                offset -= prefix_len;
2490	            }
2491	
2492	            /* Add string data */
2493	            if (offset < str_len) {
2494	                if (replyIOVReachLimit(reply_iov)) return;
2495	                reply_iov->iov[reply_iov->iovcnt].iov_base = (char *)str_ref->obj->ptr + offset;
2496	                reply_iov->iov[reply_iov->iovcnt].iov_len = str_len - offset;
2497	                reply_iov->iov_bytes_len += reply_iov->iov[(reply_iov->iovcnt)++].iov_len;
2498	                offset = 0;
2499	            } else {
2500	                offset -= str_len;
2501	            }
2502	
2503	            /* Add crlf */
2504	            if (offset < 2) {
2505	                if (replyIOVReachLimit(reply_iov)) return;
2506	                reply_iov->iov[reply_iov->iovcnt].iov_base = str_ref->crlf + offset;
2507	                reply_iov->iov[reply_iov->iovcnt].iov_len = 2 - offset;
2508	                reply_iov->iov_bytes_len += reply_iov->iov[reply_iov->iovcnt++].iov_len;
2509	            }
2510	        }
2511	
2512	        offset = 0;
2513	        ptr += sizeof(payloadHeader) + head->payload_len;
2514	    }
2515	}
2516	
2517	/* Process sent data in the encoded buffer.
2518	 * Returns pointer to the current payload header being processed, or NULL if all data is processed.
2519	 * If running in IO thread, defer the free to main thread via io_deferred_objects. */
2520	static payloadHeader *processSentDataInEncodedBuffer(client *c, char *start_ptr, char *end_ptr,
2521	                                                     size_t *sentlen, ssize_t *remaining)
2522	{
2523	    int in_io_thread = (c && c->running_tid != IOTHREAD_MAIN_THREAD_ID);
2524	    char *ptr = start_ptr;
2525	    while (ptr < end_ptr && *remaining > 0) {
2526	        payloadHeader *head = (payloadHeader *)ptr;
2527	
2528	        if (head->payload_type == PLAIN_REPLY) {
2529	            if (*remaining < (ssize_t)(head->payload_len - *sentlen)) {
2530	                *sentlen += *remaining;
2531	                *remaining = 0;
2532	                return head;
2533	            }
2534	            *remaining -= (head->payload_len - *sentlen);
2535	            *sentlen = 0;
2536	        } else {
2537	            /* BULK_STR_REF - release object references */
2538	            bulkStrRef *str_ref = (bulkStrRef *)(ptr + sizeof(payloadHeader));
2539	            formatBulkStrRefPrefix(str_ref); /* ensure prefix_cnt is set for writen_len */
2540	
2541	            size_t writen_len = str_ref->prefix_cnt + sdslen(str_ref->obj->ptr) + 2;
2542	            if (*remaining < (ssize_t)(writen_len - *sentlen)) {
2543	                *sentlen += *remaining;
2544	                *remaining = 0;
2545	                return head;
2546	            }
2547	            *remaining -= (writen_len - *sentlen);
2548	            c->reply_bytes_shared -= sdslen(str_ref->obj->ptr);
2549	            if (in_io_thread) {
2550	                ioDeferFreeRobj(c, str_ref->obj);
2551	            } else {
2552	                decrRefCount(str_ref->obj);
2553	            }
2554	            str_ref->obj = NULL; /* Mark as released to prevent double free */
2555	            *sentlen = 0;
2556	        }
2557	
2558	        ptr += sizeof(payloadHeader) + head->payload_len;
2559	    }
2560	
2561	    return (ptr == end_ptr) ? NULL : (payloadHeader *)ptr;
2562	}
