2564	/* This function should be called from _writeToClient when the reply list is not empty,
2565	 * it gathers the scattered buffers from reply list and sends them away with connWritev.
2566	 * If we write successfully, it returns C_OK, otherwise, C_ERR is returned,
2567	 * and 'nwritten' is an output parameter, it means how many bytes server write
2568	 * to client. */
2569	static int _writevToClient(client *c, ssize_t *nwritten) {
2570	    int iovmax = min(IOV_MAX, c->conn->iovcnt);
2571	    struct iovec iov[iovmax];
2572	    ReplyIOV reply_iov = {iov, iovmax};
2573	
2574	    /* Add c->buf to iov array */
2575	    if (c->bufpos > 0) {
2576	        if (likely(!c->buf_encoded)) {
2577	            /* Non-encoded buffer - add directly */
2578	            iov[reply_iov.iovcnt].iov_base = c->buf + c->sentlen;
2579	            iov[reply_iov.iovcnt].iov_len = c->bufpos - c->sentlen;
2580	            reply_iov.iov_bytes_len += iov[reply_iov.iovcnt++].iov_len;
2581	        } else {
2582	            /* Encoded buffer */
2583	            char *start_ptr = c->last_header ? (char *)c->last_header : c->buf;
2584	            serverAssert(start_ptr >= c->buf && start_ptr < (c->buf + c->bufpos));
2585	            processEncodedBufferForWrite(&reply_iov, start_ptr, c->buf + c->bufpos, c->sentlen);
2586	        }
2587	    }
2588	
2589	    /* Add c->reply list nodes to iov array */
2590	    if (!replyIOVReachLimit(&reply_iov)) {
2591	        /* The first node of reply list might be incomplete from the last call,
2592	         * thus it needs to be calibrated to get the actual data address and length. */
2593	        size_t offset = c->bufpos > 0 ? 0 : c->sentlen;
2594	        payloadHeader *last_header = c->bufpos > 0 ? NULL : c->last_header;
2595	        listIter iter;
2596	        listNode *next;
2597	        listRewind(c->reply, &iter);
2598	        while ((next = listNext(&iter)) && !replyIOVReachLimit(&reply_iov)) {
2599	            clientReplyBlock *o = listNodeValue(next);
2600	            if (o->used == 0) { /* empty node, just release it and skip. */
2601	                c->reply_bytes -= o->size;
2602	                listDelNode(c->reply, next);
2603	                offset = 0;
2604	                last_header = NULL;
2605	                continue;
2606	            }
2607	
2608	            if (!o->buf_encoded) {
2609	                serverAssert(!last_header);
2610	                /* Non-encoded reply block - add directly */
2611	                iov[reply_iov.iovcnt].iov_base = o->buf + offset;
2612	                iov[reply_iov.iovcnt].iov_len = o->used - offset;
2613	                reply_iov.iov_bytes_len += iov[reply_iov.iovcnt++].iov_len;
2614	                offset = 0;
2615	            } else {
2616	                /* Encoded reply block */
2617	                char *start_ptr = last_header ? (char *)last_header : o->buf;
2618	                processEncodedBufferForWrite(&reply_iov, start_ptr, o->buf + o->used, offset);
2619	                offset = 0;
2620	                last_header = NULL;
2621	            }
2622	        }
2623	    }
2624	
2625	    if (reply_iov.iovcnt == 0) return C_OK;
2626	    *nwritten = connWritev(c->conn, iov, reply_iov.iovcnt);
2627	    if (*nwritten <= 0) return C_ERR;
2628	
2629	    /* Locate the new node which has leftover data and
2630	     * release all nodes in front of it. */
2631	    ssize_t remaining = *nwritten;
2632	    if (c->bufpos > 0) {
2633	        if (likely(!c->buf_encoded)) {
2634	            int buf_len = c->bufpos - c->sentlen;
2635	            c->sentlen += remaining;
2636	            /* If the buffer was sent, set bufpos to zero to continue with
2637	            * the remainder of the reply. */
2638	            if (remaining >= buf_len) {
2639	                c->bufpos = 0;
2640	                c->sentlen = 0;
2641	            }
2642	            remaining -= buf_len;
2643	        } else {
2644	            /* For encoded buffers */
2645	            char *start_ptr = c->last_header ? (char *)c->last_header : c->buf;
2646	            c->last_header = processSentDataInEncodedBuffer(c, start_ptr, c->buf + c->bufpos, &c->sentlen, &remaining);
2647	            if (!c->last_header) { /* reach end */
2648	                c->bufpos = 0;
2649	                c->buf_encoded = 0;
2650	                c->sentlen = 0;
2651	            }
2652	        }
2653	    }
2654	
2655	    /* Process c->reply list nodes */
2656	    listIter iter;
2657	    listNode *next;
2658	    listRewind(c->reply, &iter);
2659	    while (remaining > 0) {
2660	        next = listNext(&iter);
2661	        clientReplyBlock *o = listNodeValue(next);
2662	
2663	        if (!o->buf_encoded) {
2664	            if (remaining < (ssize_t)(o->used - c->sentlen)) {
2665	                c->sentlen += remaining;
2666	                break;
2667	            }
2668	            remaining -= (ssize_t)(o->used - c->sentlen);
2669	            c->reply_bytes -= o->size;
2670	            listDelNode(c->reply, next);
2671	            c->sentlen = 0;
2672	        } else {
2673	            /* Encoded reply block */
2674	            char *start_ptr = c->last_header ? (char *)c->last_header : o->buf;
2675	            c->last_header = processSentDataInEncodedBuffer(c, start_ptr, o->buf + o->used, &c->sentlen, &remaining);
2676	            if (!c->last_header) { /* reach end */
2677	                /* Block fully consumed, remove it */
2678	                c->reply_bytes -= o->size;
2679	                listDelNode(c->reply, next);
2680	                c->sentlen = 0;
2681	            } else {
2682	                /* Partial write, c->sentlen and o->last_header already updated, stop processing */
2683	                break;
2684	            }
2685	        }
2686	    }
2687	
2688	    return C_OK;
2689	}
2690	
2691	/* This function does actual writing output buffers for non slave client types,
2692	 * it is called by writeToClient.
2693	 * If we write successfully, it returns C_OK, otherwise, C_ERR is returned,
2694	 * and 'nwritten' is an output parameter, it means how many bytes server write
2695	 * to client. */
2696	static inline int _writeToClientNonSlave(client *c, ssize_t *nwritten) {
2697	    *nwritten = 0;
2698	    /* When the reply list is not empty, it's better to use writev to save us some
2699	     * system calls and TCP packets. */
2700	    if (listLength(c->reply) > 0) {
2701	        int ret = _writevToClient(c, nwritten);
2702	        if (ret != C_OK) return ret;
2703	
2704	        /* If there are no longer objects in the list, we expect
2705	         * the count of reply bytes to be exactly zero. */
2706	        if (listLength(c->reply) == 0)
2707	            serverAssert(c->reply_bytes == 0 && c->reply_bytes_shared == 0);
2708	    } else if (c->bufpos > 0) {
2709	        /* For encoded buffers, we need to use writev to handle bulk string references */
2710	        if (c->buf_encoded) {
2711	            int ret = _writevToClient(c, nwritten);
2712	            return ret;
2713	        }
2714	
2715	        *nwritten = connWrite(c->conn, c->buf + c->sentlen, c->bufpos - c->sentlen);
2716	        if (*nwritten <= 0) return C_ERR;
2717	        c->sentlen += *nwritten;
2718	
2719	        /* If the buffer was sent, set bufpos to zero to continue with
2720	         * the remainder of the reply. */
2721	        if (c->sentlen == c->bufpos) {
2722	            c->bufpos = 0;
2723	            c->sentlen = 0;
2724	        }
2725	    }
2726	    return C_OK;
2727	}
2728	
2729	/* This function does actual writing output buffers for slave client types,
2730	 * it is called by writeToClient.
2731	 * If we write successfully, it returns C_OK, otherwise, C_ERR is returned,
2732	 * and 'nwritten' is an output parameter, it means how many bytes server write
2733	 * to client. */
2734	static inline int _writeToClientSlave(client *c, ssize_t *nwritten) {
2735	    *nwritten = 0;
2736	    serverAssert(c->bufpos == 0 && listLength(c->reply) == 0);
2737	
2738	    if (c->running_tid != IOTHREAD_MAIN_THREAD_ID) {
2739	        replBufBlock *o = listNodeValue(c->io_curr_repl_node);
2740	        /* The IO thread must not send data beyond the bound position. */
2741	        size_t pos = c->io_curr_repl_node == c->io_bound_repl_node ?
2742	                     c->io_bound_block_pos : o->used;
2743	        if (pos > c->io_curr_block_pos) {
2744	            *nwritten = connWrite(c->conn, o->buf+c->io_curr_block_pos,
2745	                                  pos-c->io_curr_block_pos);
2746	            if (*nwritten <= 0) return C_ERR;
2747	            c->io_curr_block_pos += *nwritten;
2748	        }
2749	        /* If we fully sent the object and there are more nodes to send, go to the next one. */
2750	        if (c->io_curr_block_pos == pos && c->io_curr_repl_node != c->io_bound_repl_node) {
2751	            c->io_curr_repl_node = listNextNode(c->io_curr_repl_node);
2752	            c->io_curr_block_pos = 0;
2753	        }
2754	        return C_OK;
2755	    }
2756	
2757	    replBufBlock *o = listNodeValue(c->ref_repl_buf_node);
2758	    serverAssert(o->used >= c->ref_block_pos);
2759	    /* Send current block if it is not fully sent. */
2760	    if (o->used > c->ref_block_pos) {
2761	        *nwritten = connWrite(c->conn, o->buf+c->ref_block_pos,
2762	                                o->used-c->ref_block_pos);
2763	        if (*nwritten <= 0) return C_ERR;
2764	        c->ref_block_pos += *nwritten;
2765	    }
2766	    /* If we fully sent the object on head, go to the next one. */
2767	    listNode *next = listNextNode(c->ref_repl_buf_node);
2768	    if (next && c->ref_block_pos == o->used) {
2769	        o->refcount--;
2770	        ((replBufBlock *)(listNodeValue(next)))->refcount++;
2771	        c->ref_repl_buf_node = next;
2772	        c->ref_block_pos = 0;
2773	        incrementalTrimReplicationBacklog(REPL_BACKLOG_TRIM_BLOCKS_PER_CALL);
2774	    }
2775	    return C_OK;
2776	}
2777	
2778	/* Write data in output buffers to client. Return C_OK if the client
2779	 * is still valid after the call, C_ERR if it was freed because of some
2780	 * error.  If handler_installed is set, it will attempt to clear the
2781	 * write event.
2782	 *
2783	 * This function is called by threads, but always with handler_installed
2784	 * set to 0. So when handler_installed is set to 0 the function must be
2785	 * thread safe. */
2786	int writeToClient(client *c, int handler_installed) {
2787	    if (!(c->io_flags & CLIENT_IO_WRITE_ENABLED)) return C_OK;
2788	    /* Update the number of writes of io threads on server */
2789	    atomicIncr(IOThreads[c->running_tid].io_writes_processed, 1);
2790	
2791	    ssize_t nwritten = 0, totwritten = 0;
2792	    const int is_slave = clientTypeIsSlave(c);
2793	
2794	    if (unlikely(is_slave)) {
2795	        /* We send as much as possible if the client is
2796	         * a slave (otherwise, on high-speed traffic, the
2797	         * replication buffer will grow indefinitely) */
2798	        while(_clientHasPendingRepliesSlave(c)) {
2799	            int ret = _writeToClientSlave(c, &nwritten);
2800	            if (ret == C_ERR) break;
2801	            totwritten += nwritten;
2802	        }
2803	        atomicIncr(server.stat_net_repl_output_bytes, totwritten);
2804	    } else {
2805	        /* If we reach this block and client is marked with CLIENT_SLAVE flag
2806	         * it's because it's a MONITOR/slot-migration client, which are marked
2807	         * as replicas, but exposed as normal clients */
2808	        const int is_normal_client = !(c->flags & CLIENT_SLAVE);
2809	        while (_clientHasPendingRepliesNonSlave(c)) {
2810	            int ret = _writeToClientNonSlave(c, &nwritten);
2811	            if (ret == C_ERR) break;
2812	            totwritten += nwritten;
2813	            /* Note that we avoid to send more than NET_MAX_WRITES_PER_EVENT
2814	             * bytes, in a single threaded server it's a good idea to serve
2815	             * other clients as well, even if a very large request comes from
2816	             * super fast link that is always able to accept data (in real world
2817	             * scenario think about 'KEYS *' against the loopback interface).
2818	             *
2819	             * However if we are over the maxmemory limit we ignore that and
2820	             * just deliver as much data as it is possible to deliver.
2821	             *
2822	             * Moreover, we also send as much as possible if the client is
2823	             * a slave (covered above) or a monitor (covered here).
2824	             * (otherwise, on high-speed traffic, the
2825	             * output buffer will grow indefinitely) */
2826	            if (totwritten > NET_MAX_WRITES_PER_EVENT &&
2827	                (server.maxmemory == 0 ||
2828	                zmalloc_used_memory() < server.maxmemory) &&
2829	                is_normal_client) break;
2830	        }
2831	        atomicIncr(server.stat_net_output_bytes, totwritten);
2832	    }
2833	    c->net_output_bytes += totwritten;
2834	
2835	    if (nwritten == -1) {
2836	        if (connGetState(c->conn) != CONN_STATE_CONNECTED) {
2837	            serverLog(LL_VERBOSE,
2838	                "Error writing to client: %s", connGetLastError(c->conn));
2839	            freeClientAsync(c);
2840	            return C_ERR;
2841	        }
2842	    }
2843	    if (totwritten > 0) {
2844	        /* For clients representing masters we don't count sending data
2845	         * as an interaction, since we always send REPLCONF ACK commands
2846	         * that take some time to just fill the socket output buffer.
2847	         * We just rely on data / pings received for timeout detection. */
2848	        if (!(c->flags & CLIENT_MASTER)) c->lastinteraction = server.unixtime;
2849	    }
2850	    if (!clientHasPendingReplies(c)) {
2851	        c->sentlen = 0;
2852	        /* Note that writeToClient() is called in a threaded way, but
2853	         * aeDeleteFileEvent() is not thread safe: however writeToClient()
2854	         * is always called with handler_installed set to 0 from threads
2855	         * so we are fine. */
2856	        if (handler_installed) {
2857	            /* IO Thread also can do that now. */
2858	            connSetWriteHandler(c->conn, NULL);
2859	        }
2860	
2861	        /* Close connection after entire reply has been sent. */
2862	        if (c->flags & CLIENT_CLOSE_AFTER_REPLY) {
2863	            freeClientAsync(c);
2864	            return C_ERR;
2865	        }
2866	
2867	        /* Remove client from pending referenced reply clients list. */
2868	        if (c->running_tid == IOTHREAD_MAIN_THREAD_ID)
2869	            tryUnlinkClientFromPendingRefReply(c, 1);
2870	
2871	        /* If replica client has sent all the replication data it knows about
2872	         * we send it to main thread so it can pick up new repl data ASAP.
2873	         * Note, that we keep it in IO thread in case we have a pending ACK read. */
2874	        if (c->flags & CLIENT_SLAVE && c->running_tid != IOTHREAD_MAIN_THREAD_ID) {
2875	            if (!replicaFromIOThreadHasPendingRead(c))
2876	                enqueuePendingClientsToMainThread(c, 0);
2877	        }
2878	    }
2879	    /* Update client's memory usage after writing.
2880	     * Since this isn't thread safe we do this conditionally. */
2881	    if (c->running_tid == IOTHREAD_MAIN_THREAD_ID) {
2882	        updateClientMemUsageAndBucket(c);
2883	    }
2884	    return C_OK;
2885	}
