2887	/* Write event handler. Just send data to the client. */
2888	void sendReplyToClient(connection *conn) {
2889	    client *c = connGetPrivateData(conn);
2890	    writeToClient(c,1);
2891	}
2892	
2893	/* This function is called just before entering the event loop, in the hope
2894	 * we can just write the replies to the client output buffer without any
2895	 * need to use a syscall in order to install the writable event handler,
2896	 * get it called, and so forth. */
2897	int handleClientsWithPendingWrites(void) {
2898	    listIter li;
2899	    listNode *ln;
2900	    int processed = listLength(server.clients_pending_write);
2901	
2902	    listRewind(server.clients_pending_write,&li);
2903	    while((ln = listNext(&li))) {
2904	        client *c = listNodeValue(ln);
2905	
2906	        /* We handle IO thread replicas in putReplicasInPendingClientsToIOThreads */
2907	        if (c->flags & CLIENT_SLAVE && c->tid != IOTHREAD_MAIN_THREAD_ID)
2908	            continue;
2909	
2910	        c->flags &= ~CLIENT_PENDING_WRITE;
2911	        listUnlinkNode(server.clients_pending_write,ln);
2912	
2913	        /* If a client is protected, don't do anything,
2914	         * that may trigger write error or recreate handler. */
2915	        if (c->flags & CLIENT_PROTECTED) continue;
2916	
2917	        /* Don't write to clients that are going to be closed anyway. */
2918	        if (c->flags & CLIENT_CLOSE_ASAP) continue;
2919	
2920	        /* Let IO thread handle the client if possible. */
2921	        if (server.io_threads_num > 1 &&
2922	            !(c->flags & CLIENT_CLOSE_AFTER_REPLY) &&
2923	            c->tid == IOTHREAD_MAIN_THREAD_ID &&
2924	            !isClientMustHandledByMainThread(c))
2925	        {
2926	            assignClientToIOThread(c);
2927	            continue;
2928	        }
2929	
2930	        /* Try to write buffers to the client socket. */
2931	        if (writeToClient(c,0) == C_ERR) continue;
2932	
2933	        /* If after the synchronous writes above we still have data to
2934	         * output to the client, we need to install the writable handler. */
2935	        if (clientHasPendingReplies(c)) {
2936	            installClientWriteHandler(c);
2937	        }
2938	    }
2939	    return processed;
2940	}
