3621	/* This function is called every time, in the client structure 'c', there is
3622	 * more query buffer to process, because we read more data from the socket
3623	 * or because a client was blocked and later reactivated, so there could be
3624	 * pending query buffer, already representing a full command, to process.
3625	 * return C_ERR in case the client was freed during the processing */
3626	int processInputBuffer(client *c) {
3627	    atomicIncr(server.stat_total_client_process_input_buff_events, 1);
3628	
3629	    /* Keep active-client window updates on main-thread paths only (here and
3630	     * in IO-thread handoff processing) to avoid races with serverCron()
3631	     * maintenance of the circular slots. */
3632	    if (c->running_tid == IOTHREAD_MAIN_THREAD_ID)
3633	        statsUpdateActiveClients(c);
3634	
3635	    /* We limit the lookahead for unauthenticated connections to 1.
3636	     * This is both to reduce memory overhead, and to prevent errors: AUTH can
3637	     * affect the handling of succeeding commands. Parsing of "large"
3638	     * unauthenticated multibulk commands is rejected, which would cause those
3639	     * commands to incorrectly return an error to the client. */
3640	    const int lookahead = authRequired(c) ? 1 : server.lookahead;
3641	
3642	    /* Keep processing while there is something in the input buffer */
3643	    while ((c->querybuf && c->qb_pos < sdslen(c->querybuf)) ||
3644	           c->pending_cmds.ready_len > 0)
3645	    {
3646	        /* Immediately abort if the client is in the middle of something. */
3647	        if (c->flags & CLIENT_BLOCKED || c->flags & CLIENT_UNBLOCKED) break;
3648	
3649	        /* Don't process more buffers from clients that have already pending
3650	         * commands to execute in c->argv. */
3651	        if (c->flags & CLIENT_PENDING_COMMAND) break;
3652	
3653	        /* Don't process input from the master while there is a busy script
3654	         * condition on the slave. We want just to accumulate the replication
3655	         * stream (instead of replying -BUSY like we do with other clients) and
3656	         * later resume the processing. */
3657	        if (c->flags & CLIENT_MASTER && isInsideYieldingLongCommand()) break;
3658	
3659	        /* CLIENT_CLOSE_AFTER_REPLY closes the connection once the reply is
3660	         * written to the client. Make sure to not let the reply grow after
3661	         * this flag has been set (i.e. don't process more commands).
3662	         *
3663	         * The same applies for clients we want to terminate ASAP. */
3664	        if (c->flags & (CLIENT_CLOSE_AFTER_REPLY|CLIENT_CLOSE_ASAP)) break;
3665	
3666	        /* Determine if we need to parse more commands from the query buffer.
3667	         * Only parse when there are no ready commands waiting to be processed. */
3668	        const int parse_more = !c->pending_cmds.ready_len;
3669	        int pending_cmd_before_reading = c->pending_cmds.ready_len;
3670	
3671	        /* Parse up to lookahead commands only if we don't have enough ready commands */
3672	        while (parse_more && c->pending_cmds.ready_len < lookahead &&
3673	               c->querybuf && c->qb_pos < sdslen(c->querybuf))
3674	        {
3675	            /* Determine request type when unknown. */
3676	            if (!c->reqtype) {
3677	                if (c->querybuf[c->qb_pos] == '*') {
3678	                    c->reqtype = PROTO_REQ_MULTIBULK;
3679	                } else {
3680	                    c->reqtype = PROTO_REQ_INLINE;
3681	                }
3682	            }
3683	
3684	            pendingCommand *pcmd = NULL;
3685	            if (c->reqtype == PROTO_REQ_INLINE) {
3686	                pcmd = acquirePendingCommand();
3687	                if (processInlineBuffer(c, pcmd) == C_ERR && !pcmd->read_error) {
3688	                    /* If it fails but there are no errors, it means that it might just be
3689	                     * that the desired content cannot be parsed. At this point, we exit and wait for the next time. */
3690	                    freePendingCommand(c, pcmd);
3691	                    break;
3692	                }
3693	            } else if (c->reqtype == PROTO_REQ_MULTIBULK) {
3694	                int incomplete = (c->pending_cmds.len != c->pending_cmds.ready_len);
3695	                if (unlikely(incomplete)) {
3696	                    pcmd = popPendingCommandFromTail(&c->pending_cmds);
3697	                } else {
3698	                    pcmd = acquirePendingCommand();
3699	                }
3700	
3701	                if (processMultibulkBuffer(c, pcmd) == C_ERR && !pcmd->read_error) {
3702	                    /* If it fails but there are no errors, it means that it might just be
3703	                     * that the desired content cannot be parsed. At this point, we exit and wait for the next time. */
3704	                    freePendingCommand(c, pcmd);
3705	                    break;
3706	                }
3707	            } else {
3708	                serverPanic("Unknown request type");
3709	            }
3710	
3711	            addPendingCommand(&c->pending_cmds, pcmd);
3712	            if (unlikely(pcmd->read_error || (pcmd->flags & PENDING_CMD_FLAG_INCOMPLETE)))
3713	                break;
3714	
3715	            if (c->running_tid == IOTHREAD_MAIN_THREAD_ID)
3716	                pcmd->reploff = c->read_reploff - sdslen(c->querybuf) + c->qb_pos;
3717	            else
3718	                pcmd->reploff = c->io_read_reploff - sdslen(c->querybuf) + c->qb_pos;
3719	
3720	            preprocessCommand(c, pcmd);
3721	            pcmd->flags |= PENDING_CMD_FLAG_PREPROCESSED;
3722	            resetClientQbufState(c);
3723	        }
3724	
3725	        if (c->pending_cmds.ready_len != pending_cmd_before_reading) {
3726	            int newly_parsed_cmds = c->pending_cmds.ready_len - pending_cmd_before_reading;
3727	            atomicIncr(server.stat_avg_pipeline_length_sum, newly_parsed_cmds);
3728	            atomicIncr(server.stat_avg_pipeline_length_cnt, 1);
3729	
3730	            c->stat_avg_pipeline_length_sum += newly_parsed_cmds;
3731	            c->stat_avg_pipeline_length_cnt++;
3732	        }
3733	
3734	        /* Try to consume the next ready command from the pending command list. */
3735	        if (!c->pending_cmds.ready_len)
3736	            break;
3737	        pendingCommand *curcmd = c->pending_cmds.head;
3738	
3739	        /* We populate the old client fields so we don't have to modify all existing logic to work with pendingCommands */
3740	        c->argc = curcmd->argc;
3741	        c->argv = curcmd->argv;
3742	        c->argv_len = curcmd->argv_len;
3743	        c->net_input_bytes_curr_cmd += curcmd->input_bytes;
3744	        c->reploff_next = curcmd->reploff;
3745	        c->slot = curcmd->slot;
3746	        c->lookedcmd = curcmd->cmd;
3747	        c->read_error = curcmd->read_error;
3748	        c->current_pending_cmd = curcmd;
3749	
3750	        /* Prefetch the command only when more commands have been parsed and we
3751	         * are in the main thread. If running in an IO thread, prefetch will be
3752	         * deferred until the client is processed by the main thread. Skip prefetch
3753	         * if there are too few commands to avoid meaningless prefetching. */
3754	        if (parse_more && c->running_tid == IOTHREAD_MAIN_THREAD_ID &&
3755	            c->pending_cmds.ready_len > 1)
3756	        {
3757	            /* Prefetch the commands. */
3758	            resetCommandsBatch();
3759	            addCommandToBatch(c);
3760	            prefetchCommands();
3761	        }
3762	
3763	        /* Check if the client has a fatal read error that requires stopping processing. */
3764	        if (isClientReadErrorFatal(c)) {
3765	            if (c->running_tid != IOTHREAD_MAIN_THREAD_ID) {
3766	                enqueuePendingClientsToMainThread(c, 0);
3767	            }
3768	            break;
3769	        }
3770	
3771	        /* Multibulk processing could see a <= 0 length. */
3772	        if (!c->argc) {
3773	            /* A naked newline can be sent from masters as a keep-alive, or from slaves to refresh
3774	             * the last ACK time. In that case there's no command to actually execute. */
3775	            prepareForNextCommand(c, 0);
3776	        } else {
3777	            /* If we are in the context of an I/O thread, we can't really
3778	             * execute the command here. All we can do is to flag the client
3779	             * as one that needs to process the command. */
3780	            if (c->running_tid != IOTHREAD_MAIN_THREAD_ID) {
3781	                c->io_flags |= CLIENT_IO_PENDING_COMMAND;
3782	                enqueuePendingClientsToMainThread(c, 0);
3783	                break;
3784	            }
3785	
3786	            /* We are finally ready to execute the command. */
3787	            if (processCommandAndResetClient(c) == C_ERR) {
3788	                /* If the client is no longer valid, we avoid exiting this
3789	                 * loop and trimming the client buffer later. So we return
3790	                 * ASAP in that case. */
3791	                return C_ERR;
3792	            }
3793	        }
3794	    }
3795	
3796	    if (c->flags & CLIENT_MASTER) {
3797	        /* If the client is a master, trim the querybuf to repl_applied,
3798	         * since master client is very special, its querybuf not only
3799	         * used to parse command, but also proxy to sub-replicas.
3800	         *
3801	         * Here are some scenarios we cannot trim to qb_pos:
3802	         * 1. we don't receive complete command from master
3803	         * 2. master client blocked cause of client pause
3804	         * 3. io threads operate read, master client flagged with CLIENT_PENDING_COMMAND
3805	         *
3806	         * In these scenarios, qb_pos points to the part of the current command
3807	         * or the beginning of next command, and the current command is not applied yet,
3808	         * so the repl_applied is not equal to qb_pos. */
3809	        if (c->repl_applied) {
3810	            sdsrange(c->querybuf,c->repl_applied,-1);
3811	            serverAssert(c->qb_pos >= (size_t)c->repl_applied);
3812	            c->qb_pos -= c->repl_applied;
3813	            c->repl_applied = 0;
3814	        }
3815	    } else if (c->qb_pos) {
3816	        /* Trim to pos */
3817	        sdsrange(c->querybuf,c->qb_pos,-1);
3818	        c->qb_pos = 0;
3819	    }
3820	
3821	    /* Update client memory usage after processing the query buffer, this is
3822	     * important in case the query buffer is big and wasn't drained during
3823	     * the above loop (because of partially sent big commands). */
3824	    if (c->running_tid == IOTHREAD_MAIN_THREAD_ID)
3825	        updateClientMemUsageAndBucket(c);
3826	
3827	    return C_OK;
3828	}
