3988	/* A Redis "Address String" is a colon separated ip:port pair.
3989	 * For IPv4 it's in the form x.y.z.k:port, example: "127.0.0.1:1234".
3990	 * For IPv6 addresses we use [] around the IP part, like in "[::1]:1234".
3991	 * For Unix sockets we use path:0, like in "/tmp/redis:0".
3992	 *
3993	 * An Address String always fits inside a buffer of NET_ADDR_STR_LEN bytes,
3994	 * including the null term.
3995	 *
3996	 * On failure the function still populates 'addr' with the "?:0" string in case
3997	 * you want to relax error checking or need to display something anyway (see
3998	 * anetFdToString implementation for more info). */
3999	void genClientAddrString(client *client, char *addr,
4000	                         size_t addr_len, int remote) {
4001	    if (client->flags & CLIENT_UNIX_SOCKET) {
4002	        /* Unix socket client. */
4003	        snprintf(addr,addr_len,"%s:0",server.unixsocket);
4004	    } else {
4005	        /* TCP client. */
4006	        connFormatAddr(client->conn,addr,addr_len,remote);
4007	    }
4008	}
