4010	/* This function returns the client peer id, by creating and caching it
4011	 * if client->peerid is NULL, otherwise returning the cached value.
4012	 * The Peer ID never changes during the life of the client, however it
4013	 * is expensive to compute. */
4014	char *getClientPeerId(client *c) {
4015	    char peerid[NET_ADDR_STR_LEN] = {0};
4016	
4017	    if (c->peerid == NULL) {
4018	        genClientAddrString(c,peerid,sizeof(peerid),1);
4019	        c->peerid = sdsnew(peerid);
4020	    }
4021	    return c->peerid;
4022	}
