4044	/* Concatenate a string representing the state of a client in a human
4045	 * readable format, into the sds string 's'. */
4046	sds catClientInfoString(sds s, client *client) {
4047	    char flags[17], events[3], conninfo[CONN_INFO_LEN], *p;
4048	
4049	    /* Pause IO thread to access data of the client safely. */
4050	    int paused = 0;
4051	    if (client->running_tid != IOTHREAD_MAIN_THREAD_ID &&
4052	        pthread_equal(server.main_thread_id, pthread_self()) &&
4053	        !isCrashing())
4054	    {
4055	        paused = 1;
4056	        pauseIOThread(client->running_tid);
4057	    }
4058	
4059	    p = flags;
4060	    if (client->flags & CLIENT_SLAVE) {
4061	        if (client->flags & CLIENT_MONITOR)
4062	            *p++ = 'O';
4063	        else if (client->flags & CLIENT_ASM_MIGRATING)
4064	            *p++ = 'g';
4065	        else
4066	            *p++ = 'S';
4067	    }
4068	    if (client->flags & CLIENT_MASTER) {
4069	        if (client->flags & CLIENT_ASM_IMPORTING)
4070	            *p++ = 'o';
4071	        else
4072	            *p++ = 'M';
4073	    }
4074	    if (client->flags & CLIENT_PUBSUB) *p++ = 'P';
4075	    if (client->flags & CLIENT_MULTI) *p++ = 'x';
4076	    if (client->flags & CLIENT_BLOCKED) *p++ = 'b';
4077	    if (client->flags & CLIENT_TRACKING) *p++ = 't';
4078	    if (client->flags & CLIENT_TRACKING_BROKEN_REDIR) *p++ = 'R';
4079	    if (client->flags & CLIENT_TRACKING_BCAST) *p++ = 'B';
4080	    if (client->flags & CLIENT_DIRTY_CAS) *p++ = 'd';
4081	    if (client->flags & CLIENT_CLOSE_AFTER_REPLY) *p++ = 'c';
4082	    if (client->flags & CLIENT_UNBLOCKED) *p++ = 'u';
4083	    if (client->flags & CLIENT_CLOSE_ASAP) *p++ = 'A';
4084	    if (client->flags & CLIENT_UNIX_SOCKET) *p++ = 'U';
4085	    if (client->flags & CLIENT_READONLY) *p++ = 'r';
4086	    if (client->flags & CLIENT_NO_EVICT) *p++ = 'e';
4087	    if (client->flags & CLIENT_NO_TOUCH) *p++ = 'T';
4088	    if (client->flags & CLIENT_REPL_RDB_CHANNEL) *p++ = 'C';
4089	    if (client->flags & CLIENT_INTERNAL) *p++ = 'I';
4090	    if (p == flags) *p++ = 'N';
4091	    *p++ = '\0';
4092	
4093	    p = events;
4094	    if (client->conn) {
4095	        if (connHasReadHandler(client->conn)) *p++ = 'r';
4096	        if (connHasWriteHandler(client->conn)) *p++ = 'w';
4097	    }
4098	    *p = '\0';
4099	
4100	    /* Refresh the cached unshared reply bytes before computing memory stats below. */
4101	    updateClientUnsharedReplyBytes(client);
4102	
4103	    /* Compute the total memory consumed by this client. */
4104	    size_t obufmem = getClientOutputBufferLogicalSize(client);
4105	    size_t total_mem = getClientMemoryUsage(client);
4106	
4107	    size_t used_blocks_of_repl_buf = 0;
4108	    if (client->ref_repl_buf_node) {
4109	        replBufBlock *last = listNodeValue(listLast(server.repl_buffer_blocks));
4110	        replBufBlock *cur = listNodeValue(client->ref_repl_buf_node);
4111	        used_blocks_of_repl_buf = last->id - cur->id + 1;
4112	    }
4113	
4114	    sds ret = sdscatfmt(s, FMTARGS(
4115	        "id=%U", (unsigned long long) client->id,
4116	        " addr=%s", getClientPeerId(client),
4117	        " laddr=%s", getClientSockname(client),
4118	        " %s", connGetInfo(client->conn, conninfo, sizeof(conninfo)),
4119	        " name=%s", client->name ? (char*)client->name->ptr : "",
4120	        " age=%I", (long long)(commandTimeSnapshot() / 1000 - client->ctime),
4121	        " idle=%I", (long long)(server.unixtime - client->lastinteraction),
4122	        " flags=%s", flags,
4123	        " db=%i", client->db->id,
4124	        " sub=%i", (int) dictSize(client->pubsub_channels),
4125	        " psub=%i", (int) dictSize(client->pubsub_patterns),
4126	        " ssub=%i", (int) dictSize(client->pubsubshard_channels),
4127	        " multi=%i", (client->flags & CLIENT_MULTI) ? client->mstate.count : -1,
4128	        " watch=%i", (int) listLength(client->watched_keys),
4129	        " qbuf=%U", client->querybuf ? (unsigned long long) sdslen(client->querybuf) : 0,
4130	        " qbuf-free=%U", client->querybuf ? (unsigned long long) sdsavail(client->querybuf) : 0,
4131	        " argv-mem=%U", (unsigned long long) client->all_argv_len_sum,
4132	        " multi-mem=%U", (unsigned long long) client->mstate.argv_len_sums,
4133	        " rbs=%U", (unsigned long long) client->buf_usable_size,
4134	        " rbp=%U", (unsigned long long) client->buf_peak,
4135	        " obl=%U", (unsigned long long) client->bufpos,
4136	        " oll=%U", (unsigned long long) listLength(client->reply) + used_blocks_of_repl_buf,
4137	        " omem=%U", (unsigned long long) obufmem, /* logical output buffer memory (includes shared memory; excludes client->buf so static clients show 0) */
4138	        " omem-shared=%U", (unsigned long long) client->reply_bytes_shared, /* shared memory (not solely owned by this client) */
4139	        " omem-unshared=%U", (unsigned long long) client->reply_bytes_unshared, /* unshared memory (solely owned by this client) */
4140	        " tot-mem=%U", (unsigned long long) total_mem, /* actual memory usage (includes unshared memory, excludes shared memory) */
4141	        " events=%s", events,
4142	        " cmd=%s", client->lastcmd ? client->lastcmd->fullname : "NULL",
4143	        " user=%s", client->user ? client->user->name : "(superuser)",
4144	        " redir=%I", (client->flags & CLIENT_TRACKING) ? (long long) client->client_tracking_redirection : -1,
4145	        " resp=%i", client->resp,
4146	        " lib-name=%s", client->lib_name ? (char*)client->lib_name->ptr : "",
4147	        " lib-ver=%s", client->lib_ver ? (char*)client->lib_ver->ptr : "",
4148	        " io-thread=%i", client->tid,
4149	        " tot-net-in=%U", client->net_input_bytes,
4150	        " tot-net-out=%U", client->net_output_bytes,
4151	        " tot-cmds=%U", client->commands_processed,
4152	        " read-events=%U", (unsigned long long)client->stat_total_read_events,
4153	        " avg-pipeline-len-sum=%U", (unsigned long long)client->stat_avg_pipeline_length_sum,
4154	        " avg-pipeline-len-cnt=%U", (unsigned long long)client->stat_avg_pipeline_length_cnt));
4155	
4156	    if (paused) resumeIOThread(client->running_tid);
4157	    return ret;
4158	}
