4160	sds getAllClientsInfoString(int type) {
4161	    listNode *ln;
4162	    listIter li;
4163	    client *client;
4164	    sds o = sdsnewlen(SDS_NOINIT,200*listLength(server.clients));
4165	    sdsclear(o);
4166	
4167	    /* Pause all IO threads to access data of clients safely, and pausing the
4168	     * specific IO thread will not repeatedly execute in catClientInfoString. */
4169	    int allpaused = 0;
4170	    if (server.io_threads_num > 1 && !isCrashing() &&
4171	        pthread_equal(server.main_thread_id, pthread_self()))
4172	    {
4173	        allpaused = 1;
4174	        pauseAllIOThreads();
4175	    }
4176	
4177	    listRewind(server.clients,&li);
4178	    while ((ln = listNext(&li)) != NULL) {
4179	        client = listNodeValue(ln);
4180	        if (type != -1 && getClientType(client) != type) continue;
4181	        o = catClientInfoString(o,client);
4182	        o = sdscatlen(o,"\n",1);
4183	    }
4184	
4185	    if (allpaused) resumeAllIOThreads();
4186	    return o;
4187	}
