4189	/* Check validity of an attribute that's gonna be shown in CLIENT LIST. */
4190	int validateClientAttr(const char *val) {
4191	    /* Check if the charset is ok. We need to do this otherwise
4192	     * CLIENT LIST format will break. You should always be able to
4193	     * split by space to get the different fields. */
4194	    while (*val) {
4195	        if (*val < '!' || *val > '~') { /* ASCII is assumed. */
4196	            return C_ERR;
4197	        }
4198	        val++;
4199	    }
4200	    return C_OK;
4201	}
