4203	/* Returns C_OK if the name is valid. Returns C_ERR & sets `err` (when provided) otherwise. */
4204	int validateClientName(robj *name, const char **err) {
4205	    const char *err_msg = "Client names cannot contain spaces, newlines or special characters.";
4206	    int len = (name != NULL) ? sdslen(name->ptr) : 0;
4207	    /* We allow setting the client name to an empty string. */
4208	    if (len == 0)
4209	        return C_OK;
4210	    if (validateClientAttr(name->ptr) == C_ERR) {
4211	        if (err) *err = err_msg;
4212	        return C_ERR;
4213	    }
4214	    return C_OK;
4215	}
