4217	/* Returns C_OK if the name has been set or C_ERR if the name is invalid. */
4218	int clientSetName(client *c, robj *name, const char **err) {
4219	    if (validateClientName(name, err) == C_ERR) {
4220	        return C_ERR;
4221	    }
4222	    int len = (name != NULL) ? sdslen(name->ptr) : 0;
4223	    /* Setting the client name to an empty string actually removes
4224	     * the current name. */
4225	    if (len == 0) {
4226	        if (c->name) decrRefCount(c->name);
4227	        c->name = NULL;
4228	        return C_OK;
4229	    }
4230	    if (c->name) decrRefCount(c->name);
4231	    c->name = name;
4232	    incrRefCount(name);
4233	    return C_OK;
4234	}
