4968	/* This callback is bound to POST and "Host:" command names. Those are not
4969	 * really commands, but are used in security attacks in order to talk to
4970	 * Redis instances via HTTP, with a technique called "cross protocol scripting"
4971	 * which exploits the fact that services like Redis will discard invalid
4972	 * HTTP headers and will process what follows.
4973	 *
4974	 * As a protection against this attack, Redis will terminate the connection
4975	 * when a POST or "Host:" header is seen, and will log the event from
4976	 * time to time (to avoid creating a DOS as a result of too many logs). */
4977	void securityWarningCommand(client *c) {
4978	    static time_t logged_time = 0;
4979	    time_t now = time(NULL);
4980	
4981	    if (llabs(now-logged_time) > 60) {
4982	        char ip[NET_IP_STR_LEN];
4983	        int port;
4984	        if (connAddrPeerName(c->conn, ip, sizeof(ip), &port) == -1) {
4985	            serverLog(LL_WARNING,"Possible SECURITY ATTACK detected. It looks like somebody is sending POST or Host: commands to Redis. This is likely due to an attacker attempting to use Cross Protocol Scripting to compromise your Redis instance. Connection aborted.");
4986	        } else {
4987	            serverLog(LL_WARNING,"Possible SECURITY ATTACK detected. It looks like somebody is sending POST or Host: commands to Redis. This is likely due to an attacker attempting to use Cross Protocol Scripting to compromise your Redis instance. Connection from %s:%d aborted.", ip, port);
4988	        }
4989	        logged_time = now;
4990	    }
4991	    freeClientAsync(c);
4992	}
