4238	    if (c->cmd && c->cmd->proc == execCommand) {
4239	        execCommandAbort(c, reply->ptr);
4240	    } else {
4241	        /* using addReplyError* rather than addReply so that the error can be logged. */
4242	        addReplyErrorObject(c, reply);
4243	    }
4244	}
