4555	            &c->slot,getClientCachedKeyResult(c),c->read_error,cmd_flags,&error_code);
4556	        if (n == NULL || !clusterNodeIsMyself(n)) {
4557	            if (c->cmd->proc == execCommand) {
4558	                discardTransaction(c);
4559	            } else {
4560	                flagTransaction(c);
4561	            }
4562	            clusterRedirectClient(c,n,c->slot,error_code);
