4660	        rejectCommand(c, shared.noreplicaserr);
4661	        return C_OK;
4662	    }
4663	
4664	    /* Don't accept write commands if this is a read only slave. But
4665	     * accept write commands if this is our master. */
4666	    if (server.masterhost && server.repl_slave_ro &&
4667	        !obey_client &&
4668	        is_write_command)
4669	    {
4670	        rejectCommand(c, shared.roslaveerr);
4671	        return C_OK;
4672	    }
4673	
4674	    /* If this node is a replica and there is a trim job due to slot migration,
4675	     * we cannot process commands from the master for the slot being trimmed.
4676	     * Otherwise, the trim cycle could mistakenly delete newly added keys.
4677	     * In this case, the master will be blocked until the trim job finishes.
4678	     * This is supposed to be a rare event as it needs to migrate slots and
4679	     * import them back before the trim job is done. */
4680	    if ((c->flags & CLIENT_MASTER) && is_write_command && server.cluster_enabled) {
4681	        /* Check if the command is accessing keys in a slot being trimmed. */
4682	        int slot_in_trim = asmGetTrimmingSlotForCommand(c->cmd, c->argv, c->argc);
4683	        if (slot_in_trim != -1) {
4684	            serverLog(LL_WARNING, "Master is sending command for slot %d. "
4685	                                  "There is an trim job in progress for this slot. "
4686	                                  "This replica cannot process this command right now. "
4687	                                  "Blocking master client until trim job is done. ", slot_in_trim);
4688	            /* Block master client */
4689	            blockPostponeClientWithType(c, BLOCKED_POSTPONE_TRIM);
4690	            return C_OK;
4691	        }
4692	    }
4693	
4694	    /* Only allow a subset of commands in the context of Pub/Sub if the
4695	     * connection is in RESP2 mode. With RESP3 there are no limits. */
4696	    if ((c->flags & CLIENT_PUBSUB && c->resp == 2) &&
4697	        c->cmd->proc != pingCommand &&
4698	        c->cmd->proc != subscribeCommand &&
4699	        c->cmd->proc != ssubscribeCommand &&
4700	        c->cmd->proc != unsubscribeCommand &&
4701	        c->cmd->proc != sunsubscribeCommand &&
4702	        c->cmd->proc != psubscribeCommand &&
4703	        c->cmd->proc != punsubscribeCommand &&
4704	        c->cmd->proc != quitCommand &&
4705	        c->cmd->proc != resetCommand) {
4706	        rejectCommandFormat(c,
4707	            "Can't execute '%s': only (P|S)SUBSCRIBE / "
4708	            "(P|S)UNSUBSCRIBE / PING / QUIT / RESET are allowed in this context",
4709	            c->cmd->fullname);
4710	        return C_OK;
4711	    }
4712	
4713	    /* Only allow commands with flag "t", such as INFO, REPLICAOF and so on,
4714	     * when replica-serve-stale-data is no and we are a replica with a broken
4715	     * link with master. */
4716	    if (server.masterhost && server.repl_state != REPL_STATE_CONNECTED &&
4717	        server.repl_serve_stale_data == 0 &&
4718	        is_denystale_command)
4719	    {
4720	        rejectCommand(c, shared.masterdownerr);
4721	        return C_OK;
4722	    }
4723	
4724	    /* Loading DB? Return an error if the command has not the
4725	     * CMD_LOADING flag. */
4726	    if (server.loading && !server.async_loading && is_denyloading_command) {
4727	        rejectCommand(c, shared.loadingerr);
4728	        return C_OK;
4729	    }
4730	
4731	    /* During async-loading, block certain commands. */
4732	    if (server.async_loading && is_deny_async_loading_command) {
4733	        rejectCommand(c,shared.loadingerr);
4734	        return C_OK;
4735	    }
4736	
4737	    /* when a busy job is being done (script / module)
4738	     * Only allow a limited number of commands.
4739	     * Note that we need to allow the transactions commands, otherwise clients
4740	     * sending a transaction with pipelining without error checking, may have
4741	     * the MULTI plus a few initial commands refused, then the timeout
4742	     * condition resolves, and the bottom-half of the transaction gets
4743	     * executed, see Github PR #7022. */
4744	    if (isInsideYieldingLongCommand() && !(c->cmd->flags & CMD_ALLOW_BUSY)) {
4745	        if (server.busy_module_yield_flags && server.busy_module_yield_reply) {
4746	            rejectCommandFormat(c, "-BUSY %s", server.busy_module_yield_reply);
4747	        } else if (server.busy_module_yield_flags) {
4748	            rejectCommand(c, shared.slowmoduleerr);
4749	        } else if (scriptIsEval()) {
4750	            rejectCommand(c, shared.slowevalerr);
4751	        } else {
4752	            rejectCommand(c, shared.slowscripterr);
4753	        }
4754	        return C_OK;
4755	    }
4756	
4757	    /* Prevent a replica from sending commands that access the keyspace.
4758	     * The main objective here is to prevent abuse of client pause check
4759	     * from which replicas are exempt. */
4760	    if ((c->flags & CLIENT_SLAVE) && (is_may_replicate_command || is_write_command || is_read_command)) {
4761	        rejectCommandFormat(c, "Replica can't interact with the keyspace");
4762	        return C_OK;
4763	    }
4764	
4765	    /* If the server is paused, block the client until
4766	     * the pause has ended. Replicas are never paused. */
4767	    if (!(c->flags & CLIENT_SLAVE) && 
4768	        ((isPausedActions(PAUSE_ACTION_CLIENT_ALL)) ||
