4775	    /* Exec the command */
4776	    if (c->flags & CLIENT_MULTI &&
4777	        c->cmd->proc != execCommand &&
4778	        c->cmd->proc != discardCommand &&
4779	        c->cmd->proc != multiCommand &&
4780	        c->cmd->proc != watchCommand &&
4781	        c->cmd->proc != quitCommand &&
4782	        c->cmd->proc != resetCommand)
4783	    {
4784	        queueMultiCommand(c, cmd_flags);
4785	        addReply(c,shared.queued);
