4835	/* ====================== Error lookup and execution ===================== */
4836	
4837	/* Users who abuse lua error_reply will generate a new error object on each
4838	 * error call, which can make server.errors get bigger and bigger. This will
4839	 * cause the server to block when calling INFO (we also return errorstats by
4840	 * default). To prevent the damage it can cause, when a misuse is detected,
4841	 * we will print the warning log and disable the errorstats to avoid adding
4842	 * more new errors. It can be re-enabled via CONFIG RESETSTAT. */
4843	#define ERROR_STATS_NUMBER 128
4844	void incrementErrorCount(const char *fullerr, size_t namelen) {
4845	    /* errorstats is disabled, return ASAP. */
4846	    if (!server.errors_enabled) return;
4847	
4848	    void *result;
4849	    if (!raxFind(server.errors,(unsigned char*)fullerr,namelen,&result)) {
4850	        if (server.errors->numele >= ERROR_STATS_NUMBER) {
4851	            sds errors = sdsempty();
4852	            raxIterator ri;
4853	            raxStart(&ri, server.errors);
4854	            raxSeek(&ri, "^", NULL, 0);
4855	            while (raxNext(&ri)) {
4856	                char *tmpsafe;
4857	                errors = sdscatlen(errors, getSafeInfoString((char *)ri.key, ri.key_len, &tmpsafe), ri.key_len);
4858	                errors = sdscatlen(errors, ", ", 2);
4859	                if (tmpsafe != NULL) zfree(tmpsafe);
4860	            }
4861	            sdsrange(errors, 0, -3); /* Remove final ", ". */
4862	            raxStop(&ri);
4863	
4864	            /* Print the warning log and the contents of server.errors to the log. */
4865	            serverLog(LL_WARNING,
4866	                      "Errorstats stopped adding new errors because the number of "
4867	                      "errors reached the limit, may be misuse of lua error_reply, "
4868	                      "please check INFO ERRORSTATS, this can be re-enabled via "
4869	                      "CONFIG RESETSTAT.");
4870	            serverLog(LL_WARNING, "Current errors code list: %s", errors);
4871	            sdsfree(errors);
4872	
4873	            /* Reset the errors and add a single element to indicate that it is disabled. */
4874	            resetErrorTableStats();
4875	            incrementErrorCount("ERRORSTATS_DISABLED", 19);
4876	            server.errors_enabled = 0;
4877	            return;
4878	        }
4879	
4880	        struct redisError *error = zmalloc(sizeof(*error));
4881	        error->count = 1;
4882	        raxInsert(server.errors,(unsigned char*)fullerr,namelen,error,NULL);
4883	    } else {
4884	        struct redisError *error = result;
4885	        error->count++;
4886	    }
4887	}
