4890	
4891	/* Close listening sockets. Also unlink the unix domain socket if
4892	 * unlink_unix_socket is non-zero. */
4893	void closeListeningSockets(int unlink_unix_socket) {
4894	    int j;
4895	
4896	    for (int i = 0; i < CONN_TYPE_MAX; i++) {
4897	        connListener *listener = &server.listeners[i];
4898	        if (listener->ct == NULL)
4899	            continue;
4900	
4901	        for (j = 0; j < listener->count; j++) close(listener->fd[j]);
4902	    }
4903	
4904	    if (server.cluster_enabled)
4905	        for (j = 0; j < server.clistener.count; j++) close(server.clistener.fd[j]);
4906	    if (unlink_unix_socket && server.unixsocket) {
4907	        serverLog(LL_NOTICE,"Removing the unix socket file.");
4908	        if (unlink(server.unixsocket) != 0)
4909	            serverLog(LL_WARNING,"Error removing the unix socket file: %s",strerror(errno));
4910	    }
4911	}
