4913	/* Prepare for shutting down the server. Flags:
4914	 *
4915	 * - SHUTDOWN_SAVE: Save a database dump even if the server is configured not to
4916	 *   save any dump.
4917	 *
4918	 * - SHUTDOWN_NOSAVE: Don't save any database dump even if the server is
4919	 *   configured to save one.
4920	 *
4921	 * - SHUTDOWN_NOW: Don't wait for replicas to catch up before shutting down.
4922	 *
4923	 * - SHUTDOWN_FORCE: Ignore errors writing AOF and RDB files on disk, which
4924	 *   would normally prevent a shutdown.
4925	 *
4926	 * Unless SHUTDOWN_NOW is set and if any replicas are lagging behind, C_ERR is
4927	 * returned and server.shutdown_mstime is set to a timestamp to allow a grace
4928	 * period for the replicas to catch up. This is checked and handled by
4929	 * serverCron() which completes the shutdown as soon as possible.
4930	 *
4931	 * If shutting down fails due to errors writing RDB or AOF files, C_ERR is
4932	 * returned and an error is logged. If the flag SHUTDOWN_FORCE is set, these
4933	 * errors are logged but ignored and C_OK is returned.
4934	 *
4935	 * On success, this function returns C_OK and then it's OK to call exit(0). */
4936	int prepareForShutdown(int flags) {
4937	    if (isShutdownInitiated()) return C_ERR;
4938	
4939	    /* When SHUTDOWN is called while the server is loading a dataset in
4940	     * memory we need to make sure no attempt is performed to save
4941	     * the dataset on shutdown (otherwise it could overwrite the current DB
4942	     * with half-read data).
4943	     *
4944	     * Also when in Sentinel mode clear the SAVE flag and force NOSAVE. */
4945	    if (server.loading || server.sentinel_mode)
4946	        flags = (flags & ~SHUTDOWN_SAVE) | SHUTDOWN_NOSAVE;
4947	
4948	    server.shutdown_flags = flags;
4949	
4950	    serverLog(LL_NOTICE,"User requested shutdown...");
4951	    if (server.supervised_mode == SUPERVISED_SYSTEMD)
4952	        redisCommunicateSystemd("STOPPING=1\n");
4953	
4954	    /* Cancel all ASM tasks before shutting down. */
4955	    clusterAsmCancel(NULL, "server shutdown");
4956	
4957	    /* If we have any replicas, let them catch up the replication offset before
4958	     * we shut down, to avoid data loss. */
4959	    if (!(flags & SHUTDOWN_NOW) &&
4960	        server.shutdown_timeout != 0 &&
4961	        !isReadyToShutdown())
4962	    {
4963	        server.shutdown_mstime = server.mstime + server.shutdown_timeout * 1000;
4964	        if (!isPausedActions(PAUSE_ACTION_REPLICA)) sendGetackToReplicas();
4965	        pauseActions(PAUSE_DURING_SHUTDOWN,
4966	                      LLONG_MAX,
4967	                     PAUSE_ACTIONS_CLIENT_WRITE_SET);
4968	        serverLog(LL_NOTICE, "Waiting for replicas before shutting down.");
4969	        return C_ERR;
4970	    }
4971	
4972	    return finishShutdown();
4973	}
4974	
4975	static inline int isShutdownInitiated(void) {
4976	    return server.shutdown_mstime != 0;
4977	}
4978	
4979	/* Returns 0 if there are any replicas which are lagging in replication which we
4980	 * need to wait for before shutting down. Returns 1 if we're ready to shut
4981	 * down now. */
4982	int isReadyToShutdown(void) {
4983	    if (listLength(server.slaves) == 0) return 1;  /* No replicas. */
4984	
4985	    listIter li;
4986	    listNode *ln;
4987	    listRewind(server.slaves, &li);
4988	    while ((ln = listNext(&li)) != NULL) {
4989	        client *replica = listNodeValue(ln);
4990	        /* Don't count migration destination replicas. */
4991	        if (replica->flags & CLIENT_ASM_MIGRATING) continue;
4992	        if (replica->repl_ack_off != server.master_repl_offset) return 0;
4993	    }
4994	    return 1;
4995	}
4996	
4997	static void cancelShutdown(void) {
4998	    atomicSet(server.shutdown_asap, 0);
4999	    server.shutdown_flags = 0;
5000	    server.shutdown_mstime = 0;
5001	    atomicSet(server.last_sig_received, 0);
5002	    replyToClientsBlockedOnShutdown();
5003	    unpauseActions(PAUSE_DURING_SHUTDOWN);
5004	}
5005	
5006	/* Returns C_OK if shutdown was aborted and C_ERR if shutdown wasn't ongoing. */
5007	int abortShutdown(void) {
5008	    if (isShutdownInitiated()) {
5009	        cancelShutdown();
5010	    } else if (shouldShutdownAsap()) {
5011	        /* Signal handler has requested shutdown, but it hasn't been initiated
5012	         * yet. Just clear the flag. */
5013	        atomicSet(server.shutdown_asap, 0);
5014	    } else {
5015	        /* Shutdown neither initiated nor requested. */
5016	        return C_ERR;
5017	    }
5018	    serverLog(LL_NOTICE, "Shutdown manually aborted.");
5019	    return C_OK;
5020	}
5021	
5022	/* The final step of the shutdown sequence. Returns C_OK if the shutdown
5023	 * sequence was successful and it's OK to call exit(). If C_ERR is returned,
5024	 * it's not safe to call exit(). */
5025	int finishShutdown(void) {
5026	
5027	    int save = server.shutdown_flags & SHUTDOWN_SAVE;
5028	    int nosave = server.shutdown_flags & SHUTDOWN_NOSAVE;
5029	    int force = server.shutdown_flags & SHUTDOWN_FORCE;
5030	
5031	    /* Log a warning for each replica that is lagging. */
5032	    listIter replicas_iter;
5033	    listNode *replicas_list_node;
5034	    int num_replicas = 0, num_lagging_replicas = 0;
5035	    listRewind(server.slaves, &replicas_iter);
5036	    while ((replicas_list_node = listNext(&replicas_iter)) != NULL) {
5037	        client *replica = listNodeValue(replicas_list_node);
5038	        /* Don't count migration destination replicas. */
5039	        if (replica->flags & CLIENT_ASM_MIGRATING) continue;
5040	        num_replicas++;
5041	
5042	        /* We pause the IO thread this replica is running on so we avoid data
5043	         * races. */
5044	        int paused = 0;
5045	        if (replica->running_tid != IOTHREAD_MAIN_THREAD_ID) {
5046	            pauseIOThread(replica->tid);
5047	            paused = 1;
5048	        }
5049	
5050	        if (replica->repl_ack_off != server.master_repl_offset) {
5051	            num_lagging_replicas++;
5052	            long lag = replica->replstate == SLAVE_STATE_ONLINE ?
5053	                time(NULL) - replica->repl_ack_time : 0;
5054	            serverLog(LL_NOTICE,
5055	                      "Lagging replica %s reported offset %lld behind master, lag=%ld, state=%s.",
5056	                      replicationGetSlaveName(replica),
5057	                      server.master_repl_offset - replica->repl_ack_off,
5058	                      lag,
5059	                      replstateToString(replica->replstate));
5060	        }
5061	
5062	        if (paused) resumeIOThread(replica->tid);
5063	    }
5064	    if (num_replicas > 0) {
5065	        serverLog(LL_NOTICE,
5066	                  "%d of %d replicas are in sync when shutting down.",
5067	                  num_replicas - num_lagging_replicas,
5068	                  num_replicas);
5069	    }
5070	
5071	    /* Kill all the Lua debugger forked sessions. */
5072	    ldbKillForkedSessions();
5073	
5074	    /* Kill the saving child if there is a background saving in progress.
5075	       We want to avoid race conditions, for instance our saving child may
5076	       overwrite the synchronous saving did by SHUTDOWN. */
5077	    if (server.child_type == CHILD_TYPE_RDB) {
5078	        serverLog(LL_WARNING,"There is a child saving an .rdb. Killing it!");
5079	        killRDBChild();
5080	        /* Note that, in killRDBChild normally has backgroundSaveDoneHandler
5081	         * doing it's cleanup, but in this case this code will not be reached,
5082	         * so we need to call rdbRemoveTempFile which will close fd(in order
5083	         * to unlink file actually) in background thread.
5084	         * The temp rdb file fd may won't be closed when redis exits quickly,
5085	         * but OS will close this fd when process exits. */
5086	        rdbRemoveTempFile(server.child_pid, 0);
5087	        resetChildState();
5088	    }
5089	
5090	    /* Kill module child if there is one. */
5091	    if (server.child_type == CHILD_TYPE_MODULE) {
5092	        serverLog(LL_WARNING,"There is a module fork child. Killing it!");
5093	        TerminateModuleForkChild(server.child_pid,0);
5094	    }
5095	
5096	    /* Kill the AOF saving child as the AOF we already have may be longer
5097	     * but contains the full dataset anyway. */
5098	    if (server.child_type == CHILD_TYPE_AOF) {
5099	        /* If we have AOF enabled but haven't written the AOF yet, don't
5100	         * shutdown or else the dataset will be lost. */
5101	        if (server.aof_state == AOF_WAIT_REWRITE) {
5102	            if (force) {
5103	                serverLog(LL_WARNING, "Writing initial AOF. Exit anyway.");
5104	            } else {
5105	                serverLog(LL_WARNING, "Writing initial AOF, can't exit.");
5106	                if (server.supervised_mode == SUPERVISED_SYSTEMD)
5107	                    redisCommunicateSystemd("STATUS=Writing initial AOF, can't exit.\n");
5108	                goto error;
5109	            }
5110	        }
5111	        serverLog(LL_WARNING,
5112	                  "There is a child rewriting the AOF. Killing it!");
5113	        killAppendOnlyChild();
5114	    }
5115	    if (server.aof_state != AOF_OFF) {
5116	        /* Append only file: flush buffers and fsync() the AOF at exit */
5117	        serverLog(LL_NOTICE,"Calling fsync() on the AOF file.");
5118	        flushAppendOnlyFile(1);
5119	        if (redis_fsync(server.aof_fd) == -1) {
5120	            serverLog(LL_WARNING,"Fail to fsync the AOF file: %s.",
5121	                                 strerror(errno));
5122	        }
5123	    }
5124	
5125	    /* Create a new RDB file before exiting. */
5126	    if ((server.saveparamslen > 0 && !nosave) || save) {
5127	        serverLog(LL_NOTICE,"Saving the final RDB snapshot before exiting.");
5128	        if (server.supervised_mode == SUPERVISED_SYSTEMD)
5129	            redisCommunicateSystemd("STATUS=Saving the final RDB snapshot\n");
5130	        /* Snapshotting. Perform a SYNC SAVE and exit */
5131	        rdbSaveInfo rsi, *rsiptr;
5132	        rsiptr = rdbPopulateSaveInfo(&rsi);
5133	        /* Keep the page cache since it's likely to restart soon */
5134	        if (rdbSave(SLAVE_REQ_NONE,server.rdb_filename,rsiptr,RDBFLAGS_KEEP_CACHE) != C_OK) {
5135	            /* Ooops.. error saving! The best we can do is to continue
5136	             * operating. Note that if there was a background saving process,
5137	             * in the next cron() Redis will be notified that the background
5138	             * saving aborted, handling special stuff like slaves pending for
5139	             * synchronization... */
5140	            if (force) {
5141	                serverLog(LL_WARNING,"Error trying to save the DB. Exit anyway.");
5142	            } else {
5143	                serverLog(LL_WARNING,"Error trying to save the DB, can't exit.");
5144	                if (server.supervised_mode == SUPERVISED_SYSTEMD)
5145	                    redisCommunicateSystemd("STATUS=Error trying to save the DB, can't exit.\n");
5146	                goto error;
5147	            }
5148	        }
5149	    }
5150	
5151	    /* Update the end offset of current INCR AOF if possible. */
5152	    updateCurIncrAofEndOffset();
5153	
5154	    /* Free the AOF manifest. */
5155	    if (server.aof_manifest) aofManifestFree(server.aof_manifest);
5156	
5157	    /* Fire the shutdown modules event. */
5158	    moduleFireServerEvent(REDISMODULE_EVENT_SHUTDOWN,0,NULL);
5159	
5160	    /* Remove the pid file if possible and needed. */
5161	    if (server.daemonize || server.pidfile) {
5162	        serverLog(LL_NOTICE,"Removing the pid file.");
5163	        unlink(server.pidfile);
5164	    }
5165	
5166	    /* Best effort flush of slave output buffers, so that we hopefully
5167	     * send them pending writes. */
5168	    flushSlavesOutputBuffers();
5169	
5170	    /* Close the listening sockets. Apparently this allows faster restarts. */
5171	    closeListeningSockets(1);
5172	
5173	#if !defined(__sun)
5174	    /* Unlock the cluster config file before shutdown */
5175	    if (server.cluster_enabled && server.cluster_config_file_lock_fd != -1) {
5176	        flock(server.cluster_config_file_lock_fd, LOCK_UN|LOCK_NB);
5177	    }
5178	#endif /* __sun */
5179	
5180	
5181	    serverLog(LL_WARNING,"%s is now ready to exit, bye bye...",
5182	        server.sentinel_mode ? "Sentinel" : "Redis");
5183	    return C_OK;
5184	
5185	error:
5186	    serverLog(LL_WARNING, "Errors trying to shut down the server. Check the logs for more information.");
5187	    cancelShutdown();
5188	    return C_ERR;
5189	}
