5192	
5193	/* Sometimes Redis cannot accept write commands because there is a persistence
5194	 * error with the RDB or AOF file, and Redis is configured in order to stop
5195	 * accepting writes in such situation. This function returns if such a
5196	 * condition is active, and the type of the condition.
5197	 *
5198	 * Function return values:
5199	 *
5200	 * DISK_ERROR_TYPE_NONE:    No problems, we can accept writes.
5201	 * DISK_ERROR_TYPE_AOF:     Don't accept writes: AOF errors.
5202	 * DISK_ERROR_TYPE_RDB:     Don't accept writes: RDB errors.
5203	 */
5204	int writeCommandsDeniedByDiskError(void) {
5205	    if (server.stop_writes_on_bgsave_err &&
5206	        server.saveparamslen > 0 &&
5207	        server.lastbgsave_status == C_ERR)
5208	    {
5209	        return DISK_ERROR_TYPE_RDB;
5210	    } else if (server.aof_state != AOF_OFF) {
5211	        if (server.aof_last_write_status == C_ERR) {
5212	            return DISK_ERROR_TYPE_AOF;
5213	        }
5214	        /* AOF fsync error. */
5215	        int aof_bio_fsync_status;
5216	        atomicGet(server.aof_bio_fsync_status,aof_bio_fsync_status);
5217	        if (aof_bio_fsync_status == C_ERR) {
5218	            atomicGet(server.aof_bio_fsync_errno,server.aof_last_write_errno);
5219	            return DISK_ERROR_TYPE_AOF;
5220	        }
5221	    }
5222	
5223	    return DISK_ERROR_TYPE_NONE;
5224	}
