5238	/* The PING command. It works in a different way if the client is in
5239	 * in Pub/Sub mode. */
5240	void pingCommand(client *c) {
5241	    /* The command takes zero or one arguments. */
5242	    if (c->argc > 2) {
5243	        addReplyErrorArity(c);
5244	        return;
5245	    }
5246	
5247	    if (c->flags & CLIENT_PUBSUB && c->resp == 2) {
5248	        addReply(c,shared.mbulkhdr[2]);
5249	        addReplyBulkCBuffer(c,"pong",4);
5250	        if (c->argc == 1)
5251	            addReplyBulkCBuffer(c,"",0);
5252	        else
5253	            addReplyBulk(c,c->argv[1]);
5254	    } else {
5255	        if (c->argc == 1)
5256	            addReply(c,shared.pong);
5257	        else
5258	            addReplyBulk(c,c->argv[1]);
5259	    }
5260	}
