5711	void getKeysSubcommandImpl(client *c, int with_flags) {
5712	    struct redisCommand *cmd = lookupCommand(c->argv+2,c->argc-2);
5713	    getKeysResult result = GETKEYS_RESULT_INIT;
5714	    int j;
5715	
5716	    if (!cmd || !commandVisibleForClient(c, cmd)) {
5717	        addReplyError(c,"Invalid command specified");
5718	        return;
5719	    } else if (!doesCommandHaveKeys(cmd)) {
5720	        addReplyError(c,"The command has no key arguments");
5721	        return;
5722	    } else if ((cmd->arity > 0 && cmd->arity != c->argc-2) ||
5723	               ((c->argc-2) < -cmd->arity))
5724	    {
5725	        addReplyError(c,"Invalid number of arguments specified for command");
5726	        return;
5727	    }
5728	
5729	    if (!getKeysFromCommandWithSpecs(cmd,c->argv+2,c->argc-2,GET_KEYSPEC_DEFAULT,&result)) {
5730	        if (cmd->flags & CMD_NO_MANDATORY_KEYS) {
5731	            addReplyArrayLen(c,0);
5732	        } else {
5733	            addReplyError(c,"Invalid arguments specified for command");
5734	        }
5735	    } else {
5736	        addReplyArrayLen(c,result.numkeys);
5737	        for (j = 0; j < result.numkeys; j++) {
5738	            if (!with_flags) {
5739	                addReplyBulk(c,c->argv[result.keys[j].pos+2]);
5740	            } else {
5741	                addReplyArrayLen(c,2);
5742	                addReplyBulk(c,c->argv[result.keys[j].pos+2]);
5743	                addReplyFlagsForKeyArgs(c,result.keys[j].flags);
5744	            }
5745	        }
5746	    }
5747	    getKeysFreeResult(&result);
5748	}
