5795	typedef enum {
5796	    COMMAND_LIST_FILTER_MODULE,
5797	    COMMAND_LIST_FILTER_ACLCAT,
5798	    COMMAND_LIST_FILTER_PATTERN,
5799	} commandListFilterType;
5800	
5801	typedef struct {
5802	    commandListFilterType type;
5803	    sds arg;
5804	    struct {
5805	        int valid;
5806	        union {
5807	            uint64_t aclcat;
5808	            void *module_handle;
5809	        } u;
5810	    } cache;
5811	} commandListFilter;
