5813	int shouldFilterFromCommandList(struct redisCommand *cmd, commandListFilter *filter) {
5814	    switch (filter->type) {
5815	        case (COMMAND_LIST_FILTER_MODULE):
5816	            if (!filter->cache.valid) {
5817	                filter->cache.u.module_handle = moduleGetHandleByName(filter->arg);
5818	                filter->cache.valid = 1;
5819	            }
5820	            return !moduleIsModuleCommand(filter->cache.u.module_handle, cmd);
5821	        case (COMMAND_LIST_FILTER_ACLCAT): {
5822	            if (!filter->cache.valid) {
5823	                filter->cache.u.aclcat = ACLGetCommandCategoryFlagByName(filter->arg);
5824	                filter->cache.valid = 1;
5825	            }
5826	            uint64_t cat = filter->cache.u.aclcat;
5827	            if (cat == 0)
5828	                return 1; /* Invalid ACL category */
5829	            return (!(cmd->acl_categories & cat));
5830	            break;
5831	        }
5832	        case (COMMAND_LIST_FILTER_PATTERN):
5833	            return !stringmatchlen(filter->arg, sdslen(filter->arg), cmd->fullname, sdslen(cmd->fullname), 1);
5834	        default:
5835	            serverPanic("Invalid filter type %d", filter->type);
5836	    }
5837	}
