5847	        if (commandVisibleForClient(c, cmd) && !shouldFilterFromCommandList(cmd,&filter)) {
5848	            addReplyBulkCBuffer(c, cmd->fullname, sdslen(cmd->fullname));
5849	            (*numcmds)++;
