5879	/* COMMAND LIST [FILTERBY (MODULE <module-name>|ACLCAT <cat>|PATTERN <pattern>)] */
5880	void commandListCommand(client *c) {
5881	
5882	    /* Parse options. */
5883	    int i = 2, got_filter = 0;
5884	    commandListFilter filter = {0};
5885	    for (; i < c->argc; i++) {
5886	        int moreargs = (c->argc-1) - i; /* Number of additional arguments. */
5887	        char *opt = c->argv[i]->ptr;
5888	        if (!strcasecmp(opt,"filterby") && moreargs == 2) {
5889	            char *filtertype = c->argv[i+1]->ptr;
5890	            if (!strcasecmp(filtertype,"module")) {
5891	                filter.type = COMMAND_LIST_FILTER_MODULE;
5892	            } else if (!strcasecmp(filtertype,"aclcat")) {
5893	                filter.type = COMMAND_LIST_FILTER_ACLCAT;
5894	            } else if (!strcasecmp(filtertype,"pattern")) {
5895	                filter.type = COMMAND_LIST_FILTER_PATTERN;
5896	            } else {
5897	                addReplyErrorObject(c,shared.syntaxerr);
5898	                return;
5899	            }
5900	            got_filter = 1;
5901	            filter.arg = c->argv[i+2]->ptr;
5902	            i += 2;
5903	        } else {
5904	            addReplyErrorObject(c,shared.syntaxerr);
5905	            return;
5906	        }
5907	    }
5908	
5909	    int numcmds = 0;
5910	    void *replylen = addReplyDeferredLen(c);
5911	
5912	    if (got_filter) {
5913	        commandListWithFilter(c, server.commands, filter, &numcmds);
5914	    } else {
5915	        commandListWithoutFilter(c, server.commands, &numcmds);
5916	    }
5917	
5918	    setDeferredArrayLen(c,replylen,numcmds);
5919	}
