3700	 *
3701	 * dbid value of -1 is saved to indicate that the called do not want
3702	 * to replicate SELECT for this command (used for database neutral commands).
3703	 */
3704	static void propagateNow(int dbid, robj **argv, int argc, int target) {
3705	    if (!shouldPropagate(target))
3706	        return;
3707	
3708	    /* This needs to be unreachable since the dataset should be fixed during
3709	     * replica pause (otherwise data may be lost during a failover) */
3710	    serverAssert(!(isPausedActions(PAUSE_ACTION_REPLICA) &&
3711	                   (!server.client_pause_in_transaction)));
3712	
3713	    if (server.aof_state != AOF_OFF && target & PROPAGATE_AOF)
3714	        feedAppendOnlyFile(dbid,argv,argc);
3715	    if (target & PROPAGATE_REPL) {
3716	        replicationFeedSlaves(server.slaves,dbid,argv,argc);
3717	        asmFeedMigrationClient(argv, argc);
3718	    }
3719	}
