3721	/* Used inside commands to schedule the propagation of additional commands
3722	 * after the current command is propagated to AOF / Replication.
3723	 *
3724	 * dbid is the database ID the command should be propagated into.
3725	 * Arguments of the command to propagate are passed as an array of redis
3726	 * objects pointers of len 'argc', using the 'argv' vector.
3727	 *
3728	 * The function does not take a reference to the passed 'argv' vector,
3729	 * so it is up to the caller to release the passed argv (but it is usually
3730	 * stack allocated).  The function automatically increments ref count of
3731	 * passed objects, so the caller does not need to. */
3732	void alsoPropagate(int dbid, robj **argv, int argc, int target) {
3733	    robj **argvcopy;
3734	    int j;
3735	
3736	    if (!shouldPropagate(target))
3737	        return;
3738	
3739	    argvcopy = zmalloc(sizeof(robj*)*argc);
3740	    for (j = 0; j < argc; j++) {
3741	        argvcopy[j] = argv[j];
3742	        incrRefCount(argv[j]);
3743	    }
3744	    redisOpArrayAppend(&server.also_propagate,dbid,argvcopy,argc,target);
3745	}
