3747	/* It is possible to call the function forceCommandPropagation() inside a
3748	 * Redis command implementation in order to to force the propagation of a
3749	 * specific command execution into AOF / Replication. */
3750	void forceCommandPropagation(client *c, int flags) {
3751	    serverAssert(c->cmd->flags & (CMD_WRITE | CMD_MAY_REPLICATE));
3752	    if (flags & PROPAGATE_REPL) c->flags |= CLIENT_FORCE_REPL;
3753	    if (flags & PROPAGATE_AOF) c->flags |= CLIENT_FORCE_AOF;
3754	}
