3756	/* Avoid that the executed command is propagated at all. This way we
3757	 * are free to just propagate what we want using the alsoPropagate()
3758	 * API. */
3759	void preventCommandPropagation(client *c) {
3760	    c->flags |= CLIENT_PREVENT_PROP;
