3773	/* Log the last command a client executed into the slowlog. */
3774	void slowlogPushCurrentCommand(client *c, struct redisCommand *cmd, ustime_t duration) {
3775	    /* Some commands may contain sensitive data that should not be available in the slowlog. */
3776	    if (cmd->flags & CMD_SKIP_SLOWLOG)
3777	        return;
3778	
3779	    /* If command argument vector was rewritten, use the original
3780	     * arguments. */
3781	    robj **argv = c->original_argv ? c->original_argv : c->argv;
3782	    int argc = c->original_argv ? c->original_argc : c->argc;
3783	    if (slowlogPushEntryIfNeeded(c,argv,argc,duration)) {
3784	        server.stat_slowlog_count++;
3785	        server.stat_slowlog_time_us_sum += duration;
3786	        if (duration > server.stat_slowlog_time_us_max)
3787	            server.stat_slowlog_time_us_max = duration;
3788	        cmd->slowlog_count++;
3789	        cmd->slowlog_time_us_sum += duration;
3790	        if (duration > cmd->slowlog_time_us_max)
3791	            cmd->slowlog_time_us_max = duration;
3792	    }
3793	}
