3808	/* Handle the alsoPropagate() API to handle commands that want to propagate
3809	 * multiple separated commands. Note that alsoPropagate() is not affected
3810	 * by CLIENT_PREVENT_PROP flag. */
3811	static void propagatePendingCommands(void) {
3812	    if (server.also_propagate.numops == 0)
3813	        return;
3814	
3815	    int j;
3816	    redisOp *rop;
3817	
3818	    /* If we got here it means we have finished an execution-unit.
3819	     * If that unit has caused propagation of multiple commands, they
3820	     * should be propagated as a transaction */
3821	    int transaction = server.also_propagate.numops > 1;
3822	
3823	    /* In case a command that may modify random keys was run *directly*
3824	     * (i.e. not from within a script, MULTI/EXEC, RM_Call, etc.) we want
3825	     * to avoid using a transaction (much like active-expire) */
3826	    if (server.current_client &&
3827	        server.current_client->cmd &&
3828	        server.current_client->cmd->flags & CMD_TOUCHES_ARBITRARY_KEYS)
3829	    {
3830	        transaction = 0;
3831	    }
3832	
3833	    if (transaction) {
3834	        /* We use dbid=-1 to indicate we do not want to replicate SELECT.
3835	         * It'll be inserted together with the next command (inside the MULTI) */
3836	        propagateNow(-1,&shared.multi,1,PROPAGATE_AOF|PROPAGATE_REPL);
3837	    }
3838	
3839	    for (j = 0; j < server.also_propagate.numops; j++) {
3840	        rop = &server.also_propagate.ops[j];
3841	        serverAssert(rop->target);
3842	        propagateNow(rop->dbid,rop->argv,rop->argc,rop->target);
3843	    }
3844	
3845	    if (transaction) {
3846	        /* We use dbid=-1 to indicate we do not want to replicate select */
3847	        propagateNow(-1,&shared.exec,1,PROPAGATE_AOF|PROPAGATE_REPL);
3848	    }
3849	
3850	    redisOpArrayFree(&server.also_propagate);
3851	}
