3853	/* Performs operations that should be performed after an execution unit ends.
3854	 * Execution unit is a code that should be done atomically.
3855	 * Execution units can be nested and are not necessarily starts with Redis command.
3856	 *
3857	 * For example the following is a logical unit:
3858	 *   active expire ->
3859	 *      trigger del notification of some module ->
3860	 *          accessing a key ->
3861	 *              trigger key miss notification of some other module
3862	 *
3863	 * What we want to achieve is that the entire execution unit will be done atomically,
3864	 * currently with respect to replication and post jobs, but in the future there might
3865	 * be other considerations. So we basically want the `postUnitOperations` to trigger
3866	 * after the entire chain finished. */
3867	void postExecutionUnitOperations(void) {
3868	    if (server.execution_nesting)
3869	        return;
3870	
3871	    firePostExecutionUnitJobs();
3872	
3873	    /* If we are at the top-most call() and not inside a an active module
3874	     * context (e.g. within a module timer) we can propagate what we accumulated. */
3875	    propagatePendingCommands();
3876	
3877	    /* Module subsystem post-execution-unit logic */
3878	    modulePostExecutionUnitOperations();
3879	}
