3881	/* Increment the command failure counters (either rejected_calls or failed_calls).
3882	 * The decision which counter to increment is done using the flags argument, options are:
3883	 * * ERROR_COMMAND_REJECTED - update rejected_calls
3884	 * * ERROR_COMMAND_FAILED - update failed_calls
3885	 *
3886	 * The function also reset the prev_err_count to make sure we will not count the same error
3887	 * twice, its possible to pass a NULL cmd value to indicate that the error was counted elsewhere.
3888	 *
3889	 * The function returns true if stats was updated and false if not. */
3890	int incrCommandStatsOnError(struct redisCommand *cmd, int flags) {
3891	    /* hold the prev error count captured on the last command execution */
3892	    static long long prev_err_count = 0;
3893	    int res = 0;
3894	    if (cmd) {
3895	        if ((server.stat_total_error_replies - prev_err_count) > 0) {
3896	            if (flags & ERROR_COMMAND_REJECTED) {
3897	                cmd->rejected_calls++;
3898	                res = 1;
3899	            } else if (flags & ERROR_COMMAND_FAILED) {
3900	                cmd->failed_calls++;
3901	                res = 1;
3902	            }
3903	        }
3904	    }
3905	    prev_err_count = server.stat_total_error_replies;
3906	    return res;
3907	}
