3909	/* Returns true if the command is not internal, or the connection is internal. */
3910	static bool commandVisibleForClient(client *c, struct redisCommand *cmd) {
3911	    return (!(cmd->flags & CMD_INTERNAL)) || (c->flags & CLIENT_INTERNAL);
3912	}
3913	
3914	/* Call() is the core of Redis execution of a command.
3915	 *
3916	 * The following flags can be passed:
3917	 * CMD_CALL_NONE        No flags.
3918	 * CMD_CALL_PROPAGATE_AOF   Append command to AOF if it modified the dataset
3919	 *                          or if the client flags are forcing propagation.
3920	 * CMD_CALL_PROPAGATE_REPL  Send command to slaves if it modified the dataset
3921	 *                          or if the client flags are forcing propagation.
3922	 * CMD_CALL_PROPAGATE   Alias for PROPAGATE_AOF|PROPAGATE_REPL.
3923	 * CMD_CALL_FULL        Alias for SLOWLOG|STATS|PROPAGATE.
3924	 *
3925	 * The exact propagation behavior depends on the client flags.
3926	 * Specifically:
3927	 *
3928	 * 1. If the client flags CLIENT_FORCE_AOF or CLIENT_FORCE_REPL are set
3929	 *    and assuming the corresponding CMD_CALL_PROPAGATE_AOF/REPL is set
3930	 *    in the call flags, then the command is propagated even if the
3931	 *    dataset was not affected by the command.
3932	 * 2. If the client flags CLIENT_PREVENT_REPL_PROP or CLIENT_PREVENT_AOF_PROP
3933	 *    are set, the propagation into AOF or to slaves is not performed even
3934	 *    if the command modified the dataset.
3935	 *
3936	 * Note that regardless of the client flags, if CMD_CALL_PROPAGATE_AOF
3937	 * or CMD_CALL_PROPAGATE_REPL are not set, then respectively AOF or
3938	 * slaves propagation will never occur.
3939	 *
3940	 * Client flags are modified by the implementation of a given command
3941	 * using the following API:
3942	 *
3943	 * forceCommandPropagation(client *c, int flags);
3944	 * preventCommandPropagation(client *c);
3945	 * preventCommandAOF(client *c);
3946	 * preventCommandReplication(client *c);
3947	 *
3948	 */
3949	void call(client *c, int flags) {
3950	    long long dirty;
3951	    uint64_t client_old_flags = c->flags;
3952	    struct redisCommand *real_cmd = c->realcmd;
3953	    client *prev_client = server.executing_client;
3954	    server.executing_client = c;
3955	
3956	    /* When call() is issued during loading the AOF we don't want commands called
3957	     * from module, exec or LUA to go into the slowlog or to populate statistics. */
3958	    int update_command_stats = !isAOFLoadingContext();
3959	
3960	    /* We want to be aware of a client which is making a first time attempt to execute this command
3961	     * and a client which is reprocessing command again (after being unblocked).
3962	     * Blocked clients can be blocked in different places and not always it means the call() function has been
3963	     * called. For example this is required for avoiding double logging to monitors.*/
3964	    int reprocessing_command = (c->flags & CLIENT_REEXECUTING_COMMAND) ? 1 : 0;
3965	
3966	    /* Initialization: clear the flags that must be set by the command on
3967	     * demand, and initialize the array for additional commands propagation. */
3968	    c->flags &= ~(CLIENT_FORCE_AOF|CLIENT_FORCE_REPL|CLIENT_PREVENT_PROP);
3969	
3970	    /* Redis core is in charge of propagation when the first entry point
3971	     * of call() is processCommand().
3972	     * The only other option to get to call() without having processCommand
3973	     * as an entry point is if a module triggers RM_Call outside of call()
3974	     * context (for example, in a timer).
3975	     * In that case, the module is in charge of propagation. */
3976	
3977	    /* Call the command. */
3978	    dirty = server.dirty;
3979	    long long old_master_repl_offset = server.master_repl_offset;
3980	    incrCommandStatsOnError(NULL, 0);
3981	
3982	    /* Use monotonic clock if available, and update cached time if needed */
3983	    const int use_hw_clock = monotonicGetType() == MONOTONIC_CLOCK_HW;
3984	    monotime monotonic_start = 0;
3985	    if (use_hw_clock) {
3986	        monotonic_start = getMonotonicUs();
3987	        if (server.execution_nesting == 0) {
3988	            server.accum_call_count_since_ustime++;
3989	            /* Sync cached time when monotonic clock moves more than 10us
3990	             * or after 25 commands */
3991	            if (monotonic_start - server.monotonic_us_when_ustime > 10 ||
3992	                server.accum_call_count_since_ustime > 25)
3993	            {
3994	                updateCachedTime(0);
3995	                /* Recalculate monotonic_start after time update as ustime()
3996	                 * in updateCachedTime() might have taken some time */
3997	                monotonic_start = getMonotonicUs();
3998	                server.monotonic_us_when_ustime = monotonic_start;
3999	                server.accum_call_count_since_ustime = 0;
4000	            }
4001	        }
4002	    }
4003	
4004	    /* Pass current server.ustime to avoid ustime() call if monotonic clock is used
4005	     * and time will be updated before command execution based on monotonic clock. */
4006	    const long long call_timer = use_hw_clock ? server.ustime : ustime();
4007	    enterExecutionUnit(1, call_timer);
4008	
4009	    /* setting the CLIENT_EXECUTING_COMMAND flag so we will avoid
4010	     * sending client side caching message in the middle of a command reply.
4011	     * In case of blocking commands, the flag will be un-set only after successfully
4012	     * re-processing and unblock the client.*/
4013	    c->flags |= CLIENT_EXECUTING_COMMAND;
4014	
4015	    c->cmd->proc(c);
4016	
4017	    exitExecutionUnit();
4018	
4019	    /* In case client is blocked after trying to execute the command,
4020	     * it means the execution is not yet completed and we MIGHT reprocess the command in the future. */
4021	    if (!(c->flags & CLIENT_BLOCKED)) c->flags &= ~(CLIENT_EXECUTING_COMMAND);
4022	
4023	    /* In order to avoid performance implication due to querying the clock using a system call 3 times,
4024	     * we use a monotonic clock, when we are sure its cost is very low, and fall back to non-monotonic call otherwise. */
4025	    ustime_t duration;
4026	    if (use_hw_clock)
4027	        duration = getMonotonicUs() - monotonic_start;
4028	    else
4029	        duration = ustime() - call_timer;
4030	
4031	    c->duration += duration;
4032	    dirty = server.dirty-dirty;
4033	    if (dirty < 0) dirty = 0;
4034	
4035	    /* Update failed command calls if required. */
4036	
4037	    if (!incrCommandStatsOnError(real_cmd, ERROR_COMMAND_FAILED) && c->deferred_reply_errors) {
4038	        /* When call is used from a module client, error stats, and total_error_replies
4039	         * isn't updated since these errors, if handled by the module, are internal,
4040	         * and not reflected to users. however, the commandstats does show these calls
4041	         * (made by RM_Call), so it should log if they failed or succeeded. */
4042	        real_cmd->failed_calls++;
4043	    }
4044	
4045	    /* After executing command, we will close the client after writing entire
4046	     * reply if it is set 'CLIENT_CLOSE_AFTER_COMMAND' flag. */
4047	    if (c->flags & CLIENT_CLOSE_AFTER_COMMAND) {
4048	        c->flags &= ~CLIENT_CLOSE_AFTER_COMMAND;
4049	        c->flags |= CLIENT_CLOSE_AFTER_REPLY;
4050	    }
4051	
4052	    /* Note: the code below uses the real command that was executed
4053	     * c->cmd and c->lastcmd may be different, in case of MULTI-EXEC or
4054	     * re-written commands such as EXPIRE, GEOADD, etc. */
4055	
4056	    /* Record the latency this command induced on the main thread.
4057	     * unless instructed by the caller not to log. (happens when processing
4058	     * a MULTI-EXEC from inside an AOF). */
4059	    if (update_command_stats) {
4060	        char *latency_event = (real_cmd->flags & CMD_FAST) ?
4061	                               "fast-command" : "command";
4062	        latencyAddSampleIfNeeded(latency_event,duration/1000);
4063	        if (server.execution_nesting == 0)
4064	            durationAddSample(EL_DURATION_TYPE_CMD, duration);
4065	    }
4066	
4067	    /* Log the command into the Slow log if needed.
4068	     * If the client is blocked we will handle slowlog when it is unblocked. */
4069	    if (update_command_stats && !(c->flags & CLIENT_BLOCKED))
4070	        slowlogPushCurrentCommand(c, real_cmd, c->duration);
4071	
4072	    /* Send the command to clients in MONITOR mode if applicable,
4073	     * since some administrative commands are considered too dangerous to be shown.
4074	     * Other exceptions is a client which is unblocked and retrying to process the command
4075	     * or we are currently in the process of loading AOF. */
4076	    if (update_command_stats && !reprocessing_command &&
4077	        !(c->cmd->flags & (CMD_SKIP_MONITOR|CMD_ADMIN)))
4078	    {
4079	        robj **argv = c->original_argv ? c->original_argv : c->argv;
4080	        int argc = c->original_argv ? c->original_argc : c->argc;
4081	        replicationFeedMonitors(c,server.monitors,c->db->id,argv,argc);
4082	    }
4083	
4084	    /* Populate the per-command and per-slot statistics that we show in INFO commandstats and CLUSTER SLOT-STATS,
4085	     * respectively. If the client is blocked we will handle latency stats and duration when it is unblocked. */
4086	    if (update_command_stats && !(c->flags & CLIENT_BLOCKED)) {
4087	        real_cmd->calls++;
4088	        real_cmd->microseconds += c->duration;
4089	        if (server.latency_tracking_enabled && !(c->flags & CLIENT_BLOCKED))
4090	            updateCommandLatencyHistogram(&(real_cmd->latency_histogram), c->duration*1000);
4091	        clusterSlotStatsAddCpuDuration(c, c->duration);
4092	    }
4093	
4094	    /* Populate the per-key hotkey stats. Before updating stats for a command
4095	     * we need to do some setup on the hotkeyStats structure. We only do this
4096	     * once during the outer-most call in case of nesting. However, when we are
4097	     * inside a MULTI/EXEC block, we want to track each individual command.
4098	     * NOTE: even though we update the network bytes during nested calls we
4099	     * only update the duration, since the outer-most call records the whole
4100	     * duration. */
4101	    if (update_command_stats && !(c->flags & CLIENT_BLOCKED) &&
4102	        (!server.execution_nesting || server.in_exec))
4103	    {
4104	        /* First we need to prepare the hotkeyStats for updates */
4105	        hotkeyStatsPreCurrentCmd(server.hotkeys, c);
4106	
4107	        /* Update the current cmd's keys with the commands duration */
4108	        hotkeyMetrics metrics = {c->duration, 0};
4109	        hotkeyStatsUpdateCurrentCmd(server.hotkeys, metrics);
4110	    }
4111	
4112	    /* The duration needs to be reset after each call except for a blocked command,
4113	     * which is expected to record and reset the duration after unblocking. */
4114	    if (!(c->flags & CLIENT_BLOCKED)) {
4115	        c->duration = 0;
4116	    }
4117	
4118	    /* Propagate the command into the AOF and replication link.
4119	     * We never propagate EXEC explicitly, it will be implicitly
4120	     * propagated if needed (see propagatePendingCommands).
4121	     * Also, module commands take care of themselves */
4122	    if (flags & CMD_CALL_PROPAGATE &&
4123	        (c->flags & CLIENT_PREVENT_PROP) != CLIENT_PREVENT_PROP &&
4124	        c->cmd->proc != execCommand &&
4125	        !(c->cmd->flags & CMD_MODULE))
4126	    {
4127	        int propagate_flags = PROPAGATE_NONE;
4128	
4129	        /* Check if the command operated changes in the data set. If so
4130	         * set for replication / AOF propagation. */
4131	        if (dirty) propagate_flags |= (PROPAGATE_AOF|PROPAGATE_REPL);
4132	
4133	        /* If the client forced AOF / replication of the command, set
4134	         * the flags regardless of the command effects on the data set. */
4135	        if (c->flags & CLIENT_FORCE_REPL) propagate_flags |= PROPAGATE_REPL;
4136	        if (c->flags & CLIENT_FORCE_AOF) propagate_flags |= PROPAGATE_AOF;
4137	
4138	        /* However prevent AOF / replication propagation if the command
4139	         * implementation called preventCommandPropagation() or similar,
4140	         * or if we don't have the call() flags to do so. */
4141	        if (c->flags & CLIENT_PREVENT_REPL_PROP        ||
4142	            c->flags & CLIENT_MODULE_PREVENT_REPL_PROP ||
4143	            !(flags & CMD_CALL_PROPAGATE_REPL))
4144	                propagate_flags &= ~PROPAGATE_REPL;
4145	        if (c->flags & CLIENT_PREVENT_AOF_PROP        ||
4146	            c->flags & CLIENT_MODULE_PREVENT_AOF_PROP ||
4147	            !(flags & CMD_CALL_PROPAGATE_AOF))
4148	                propagate_flags &= ~PROPAGATE_AOF;
4149	
4150	        /* Call alsoPropagate() only if at least one of AOF / replication
4151	         * propagation is needed. */
4152	        if (propagate_flags != PROPAGATE_NONE)
4153	            alsoPropagate(c->db->id,c->argv,c->argc,propagate_flags);
4154	    }
4155	
4156	    /* Restore the old replication flags, since call() can be executed
4157	     * recursively. */
4158	    c->flags &= ~(CLIENT_FORCE_AOF|CLIENT_FORCE_REPL|CLIENT_PREVENT_PROP);
4159	    c->flags |= client_old_flags &
4160	        (CLIENT_FORCE_AOF|CLIENT_FORCE_REPL|CLIENT_PREVENT_PROP);
4161	
4162	    /* If the client has keys tracking enabled for client side caching,
4163	     * make sure to remember the keys it fetched via this command. For read-only
4164	     * scripts, don't process the script, only the commands it executes. */
4165	    if ((c->cmd->flags & CMD_READONLY) && (c->cmd->proc != evalRoCommand)
4166	        && (c->cmd->proc != evalShaRoCommand) && (c->cmd->proc != fcallroCommand))
4167	    {
4168	        /* We use the tracking flag of the original external client that
4169	         * triggered the command, but we take the keys from the actual command
4170	         * being executed. */
4171	        if (server.current_client &&
4172	            (server.current_client->flags & CLIENT_TRACKING) &&
4173	            !(server.current_client->flags & CLIENT_TRACKING_BCAST))
4174	        {
4175	            trackingRememberKeys(server.current_client, c);
4176	        }
4177	    }
4178	
4179	    if (!(c->flags & CLIENT_BLOCKED)) {
4180	        /* Modules may call commands in cron, in which case server.current_client
4181	         * is not set. */
4182	        if (server.current_client) {
4183	            server.current_client->commands_processed++;
4184	        }
4185	        server.stat_numcommands++;
4186	    }
4187	
4188	    /* Do some maintenance job and cleanup */
4189	    afterCommand(c);
4190	
4191	    /* The afterCommand updates the replication network bytes. At this point we
4192	     * are ready to update the ingress/egress net bytes and cleanup tracking
4193	     * of the current command. */
4194	    if (update_command_stats && !(c->flags & CLIENT_BLOCKED)) {
4195	        /* Update the current cmd's keys with the commands output bytes */
4196	        hotkeyMetrics metrics =
4197	            {0, c->net_output_bytes_curr_cmd + c->net_input_bytes_curr_cmd};
4198	        hotkeyStatsUpdateCurrentCmd(server.hotkeys, metrics);
4199	
4200	        /* Just like curr cmd setup we only do the cleanup in case we are not in
4201	         * a nested command. For MULTI/EXEC, we do cleanup for each individual
4202	         * command. */
4203	        if (!server.execution_nesting || server.in_exec)
4204	            hotkeyStatsPostCurrentCmd(server.hotkeys);
4205	    }
4206	
4207	    /* Clear the original argv.
4208	     * If the client is blocked we will handle slowlog when it is unblocked.
4209	     * NOTE: we free the origin argv only after hoykeyStatsPostCurrentCmd as
4210	     * hotkeyStats updates depend on original_argv. */
4211	    if (!(c->flags & CLIENT_BLOCKED))
4212	        freeClientOriginalArgv(c);
4213	
4214	    /* Remember the replication offset of the client, right after its last
4215	     * command that resulted in propagation. */
4216	    if (old_master_repl_offset != server.master_repl_offset)
4217	        c->woff = server.master_repl_offset;
4218	
4219	    /* Client pause takes effect after a transaction has finished. This needs
4220	     * to be located after everything is propagated. */
4221	    if (!server.in_exec && server.client_pause_in_transaction) {
4222	        server.client_pause_in_transaction = 0;
4223	    }
4224	
4225	    server.executing_client = prev_client;
4226	}
