4228	/* Used when a command that is ready for execution needs to be rejected, due to
4229	 * various pre-execution checks. it returns the appropriate error to the client.
4230	 * If there's a transaction is flags it as dirty, and if the command is EXEC,
4231	 * it aborts the transaction.
4232	 * The duration is reset, since we reject the command, and it did not record.
4233	 * Note: 'reply' is expected to end with \r\n */
4234	void rejectCommand(client *c, robj *reply) {
4235	    flagTransaction(c);
4236	    c->duration = 0;
4237	    if (c->cmd) c->cmd->rejected_calls++;
4238	    if (c->cmd && c->cmd->proc == execCommand) {
4239	        execCommandAbort(c, reply->ptr);
4240	    } else {
4241	        /* using addReplyError* rather than addReply so that the error can be logged. */
4242	        addReplyErrorObject(c, reply);
4243	    }
4244	}
4245	
4246	void rejectCommandSds(client *c, sds s) {
4247	    flagTransaction(c);
4248	    c->duration = 0;
4249	    if (c->cmd) c->cmd->rejected_calls++;
4250	    if (c->cmd && c->cmd->proc == execCommand) {
4251	        execCommandAbort(c, s);
4252	        sdsfree(s);
4253	    } else {
4254	        /* The following frees 's'. */
4255	        addReplyErrorSds(c, s);
4256	    }
4257	}
4258	
4259	void rejectCommandFormat(client *c, const char *fmt, ...) {
4260	    va_list ap;
4261	    va_start(ap,fmt);
4262	    sds s = sdscatvprintf(sdsempty(),fmt,ap);
4263	    va_end(ap);
4264	    /* Make sure there are no newlines in the string, otherwise invalid protocol
4265	     * is emitted (The args come from the user, they may contain any character). */
4266	    sdsmapchars(s, "\r\n", "  ",  2);
4267	    rejectCommandSds(c, s);
4268	}
