4270	/* This is called after a command in call, we can do some maintenance job in it. */
4271	void afterCommand(client *c) {
4272	    /* Should be done before trackingHandlePendingKeyInvalidations so that we
4273	     * reply to client before invalidating cache (makes more sense) */
4274	    postExecutionUnitOperations();
4275	
4276	    /* Flush pending tracking invalidations. */
4277	    trackingHandlePendingKeyInvalidations();
4278	
4279	    clusterSlotStatsAddNetworkBytesOutForUserClient(c);
4280	
4281	    /* Flush other pending push messages. only when we are not in nested call.
4282	     * So the messages are not interleaved with transaction response. */
4283	    if (!server.execution_nesting)
4284	        listJoin(c->reply, server.pending_push_messages);
4285	
4286	    /* Run debug assertions if any are enabled */
4287	    if (unlikely(server.dbg_assert_flags))
4288	        dbgRunAssertions(c->db);
4289	}
