4291	/* Check if c->cmd exists, fills `err` with details in case it doesn't.
4292	 * Return 1 if exists. */
4293	int commandCheckExistence(client *c, sds *err) {
4294	    if (c->cmd)
4295	        return 1;
4296	    if (!err)
4297	        return 0;
4298	    if (isContainerCommandBySds(c->argv[0]->ptr)) {
4299	        /* If we can't find the command but argv[0] by itself is a command
4300	         * it means we're dealing with an invalid subcommand. Print Help. */
4301	        sds cmd = sdsnew((char *)c->argv[0]->ptr);
4302	        sdstoupper(cmd);
4303	        *err = sdsnew(NULL);
4304	
4305	        if (c->argc < 2) {
4306	            *err = sdscatprintf(*err, "missing subcommand. Try %s HELP.", cmd);
4307	        } else {
4308	            *err = sdscatprintf(*err, "unknown subcommand '%.128s'. Try %s HELP.",
4309	                                (char *)c->argv[1]->ptr, cmd);
4310	        }
4311	
4312	        sdsfree(cmd);
4313	    } else {
4314	        *err = sdsnew(NULL);
4315	        *err = sdscatprintf(*err, "unknown command '%.128s'", (char *)c->argv[0]->ptr);
4316	
4317	        if (c->argc >= 2) {
4318	            sds args = sdsempty();
4319	            for (int i = 1; i < c->argc && sdslen(args) < 128; i++)
4320	                args = sdscatprintf(args, "'%.*s' ", 128 - (int)sdslen(args), (char *)c->argv[i]->ptr);
4321	            *err = sdscatprintf(*err, ", with args beginning with: %s", args);
4322	            sdsfree(args);
4323	        }
4324	    }
4325	    /* Make sure there are no newlines in the string, otherwise invalid protocol
4326	     * is emitted (The args come from the user, they may contain any character). */
4327	    sdsmapchars(*err, "\r\n", "  ",  2);
4328	    return 0;
4329	}
4330	
4331	/* Check if c->argc is valid for c->cmd, fills `err` with details in case it isn't.
4332	 * Return 1 if valid. */
4333	int commandCheckArity(struct redisCommand *cmd, int argc, sds *err) {
4334	    if ((cmd->arity > 0 && cmd->arity != argc) || (argc < -cmd->arity)) {
4335	        if (err) {
4336	            *err = sdsnew(NULL);
4337	            *err = sdscatprintf(*err, "wrong number of arguments for '%s' command", cmd->fullname);
4338	        }
4339	        return 0;
4340	    }
4341	
4342	    return 1;
4343	}
