4345	/* If we're executing a script, try to extract a set of command flags from
4346	 * it, in case it declared them. Note this is just an attempt, we don't yet
4347	 * know the script command is well formed.*/
4348	uint64_t getCommandFlags(client *c) {
4349	    uint64_t cmd_flags = c->cmd->flags;
4350	
4351	    if (c->cmd->proc == fcallCommand || c->cmd->proc == fcallroCommand) {
4352	        cmd_flags = fcallGetCommandFlags(c, cmd_flags);
4353	    } else if (c->cmd->proc == evalCommand || c->cmd->proc == evalRoCommand ||
4354	               c->cmd->proc == evalShaCommand || c->cmd->proc == evalShaRoCommand)
4355	    {
4356	        cmd_flags = evalGetCommandFlags(c, cmd_flags);
4357	    }
4358	
4359	    return cmd_flags;
4360	}
4361	
4362	void preprocessCommand(client *c, pendingCommand *pcmd) {
4363	    pcmd->slot = INVALID_CLUSTER_SLOT;
4364	    if (pcmd->argc == 0)
4365	        return;
4366	
4367	    /* Check if we can reuse the previous command instead of looking it up.
4368	     * The previous command is either the penultimate pending command (if it exists), or c->lastcmd. */
4369	    struct redisCommand *last_cmd = pcmd->prev ? pcmd->prev->cmd : c->lastcmd;
4370	
4371	    if (isCommandReusable(last_cmd, pcmd->argv[0]))
4372	        pcmd->cmd = last_cmd;
4373	    else
4374	        pcmd->cmd = lookupCommand(pcmd->argv, pcmd->argc);
4375	
4376	    if (!pcmd->cmd) {
4377	        pcmd->read_error = CLIENT_READ_COMMAND_NOT_FOUND;
4378	        return;
4379	    }
4380	
4381	    if ((pcmd->cmd->arity > 0 && pcmd->cmd->arity != pcmd->argc) ||
4382	        (pcmd->argc < -pcmd->cmd->arity))
4383	    {
4384	        pcmd->read_error = CLIENT_READ_BAD_ARITY;
4385	        return;
4386	    }
4387	
4388	    pcmd->keys_result = (getKeysResult)GETKEYS_RESULT_INIT;
4389	    int num_keys = extractKeysAndSlot(pcmd->cmd, pcmd->argv, pcmd->argc,
4390	                                      &pcmd->keys_result, &pcmd->slot);
4391	    if (num_keys < 0) {
4392	        /* We skip the checks below since We expect the command to be rejected in this case */
4393	        return;
4394	    } else if (num_keys > 0) {
4395	        /* Handle cross-slot keys: mark error and reset slot. */
4396	        if (pcmd->slot == CLUSTER_CROSSSLOT) {
4397	            pcmd->read_error = CLIENT_READ_CROSS_SLOT;
4398	            pcmd->slot = INVALID_CLUSTER_SLOT;
4399	        }
4400	    }
4401	    pcmd->flags |= PENDING_CMD_KEYS_RESULT_VALID;
4402	}
4403	
4404	/* If this function gets called we already read a whole
4405	 * command, arguments are in the client argv/argc fields.
4406	 * processCommand() execute the command or prepare the
4407	 * server for a bulk read from the client.
4408	 *
4409	 * If C_OK is returned the client is still alive and valid and
4410	 * other operations can be performed by the caller. Otherwise
4411	 * if C_ERR is returned the client was destroyed (i.e. after QUIT). */
4412	int processCommand(client *c) {
4413	    if (!scriptIsTimedout()) {
4414	        /* Both EXEC and scripts call call() directly so there should be
4415	         * no way in_exec or scriptIsRunning() is 1.
4416	         * That is unless lua_timedout, in which case client may run
4417	         * some commands. */
4418	        serverAssert(!server.in_exec);
4419	        serverAssert(!scriptIsRunning());
4420	    }
4421	
4422	    /* in case we are starting to ProcessCommand and we already have a command we assume
4423	     * this is a reprocessing of this command, so we do not want to perform some of the actions again. */
4424	    int client_reprocessing_command = c->cmd ? 1 : 0;
4425	
4426	    /* only run command filter if not reprocessing command */
4427	    if (!client_reprocessing_command) {
4428	        moduleCallCommandFilters(c);
4429	        reqresAppendRequest(c);
4430	    }
4431	
4432	    /* If we're inside a module blocked context yielding that wants to avoid
4433	     * processing clients, postpone the command. */
4434	    if (server.busy_module_yield_flags != BUSY_MODULE_YIELD_NONE &&
4435	        !(server.busy_module_yield_flags & BUSY_MODULE_YIELD_CLIENTS))
4436	    {
4437	        blockPostponeClient(c);
4438	        return C_OK;
4439	    }
4440	
4441	    /* Now lookup the command and check ASAP about trivial error conditions
4442	     * such as wrong arity, bad command name and so forth.
4443	     * In case we are reprocessing a command after it was blocked,
4444	     * we do not have to repeat the same checks */
4445	    if (!client_reprocessing_command) {
4446	        /* check if we can reuse the last command instead of looking up if we already have that info */
4447	        struct redisCommand *cmd = c->lookedcmd;
4448	
4449	        /* The command may have been modified by modules (e.g., in CommandFilters callbacks),
4450	         * so we need to look it up again. */
4451	        if (!cmd) {
4452	            if (isCommandReusable(c->lastcmd, c->argv[0]))
4453	                cmd = c->lastcmd;
4454	            else
4455	                cmd = lookupCommand(c->argv, c->argc);
4456	        }
4457	
4458	        if (!cmd) {
4459	            /* Handle possible security attacks. */
4460	            if (!strcasecmp(c->argv[0]->ptr,"host:") || !strcasecmp(c->argv[0]->ptr,"post")) {
4461	                securityWarningCommand(c);
4462	                return C_ERR;
4463	            }
4464	        }
4465	
4466	        /* Internal commands seem unexistent to non-internal connections.
4467	         * masters and AOF loads are implicitly internal. */
4468	        if (cmd && (cmd->flags & CMD_INTERNAL) && !((c->flags & CLIENT_INTERNAL) || mustObeyClient(c))) {
4469	            cmd = NULL;
4470	        }
4471	
4472	        c->cmd = c->lastcmd = c->realcmd = cmd;
4473	        sds err;
4474	        if (!commandCheckExistence(c, &err)) {
4475	            rejectCommandSds(c, err);
4476	            return C_OK;
4477	        }
4478	        if (!commandCheckArity(c->cmd, c->argc, &err)) {
4479	            rejectCommandSds(c, err);
4480	            return C_OK;
4481	        }
4482	
4483	
4484	        /* Check if the command is marked as protected and the relevant configuration allows it */
4485	        if (c->cmd->flags & CMD_PROTECTED) {
4486	            if ((c->cmd->proc == debugCommand && !allowProtectedAction(server.enable_debug_cmd, c)) ||
4487	                (c->cmd->proc == moduleCommand && !allowProtectedAction(server.enable_module_cmd, c)))
4488	            {
4489	                rejectCommandFormat(c,"%s command not allowed. If the %s option is set to \"local\", "
4490	                                      "you can run it from a local connection, otherwise you need to set this option "
4491	                                      "in the configuration file, and then restart the server.",
4492	                                      c->cmd->proc == debugCommand ? "DEBUG" : "MODULE",
4493	                                      c->cmd->proc == debugCommand ? "enable-debug-command" : "enable-module-command");
4494	                return C_OK;
4495	
4496	            }
4497	        }
4498	    }
4499	
4500	    const uint64_t cmd_flags = getCommandFlags(c);
4501	
4502	    int is_read_command = (cmd_flags & CMD_READONLY) ||
4503	                           (c->cmd->proc == execCommand && (c->mstate.cmd_flags & CMD_READONLY));
4504	    int is_write_command = (cmd_flags & CMD_WRITE) ||
4505	                           (c->cmd->proc == execCommand && (c->mstate.cmd_flags & CMD_WRITE));
4506	    int is_denyoom_command = (cmd_flags & CMD_DENYOOM) ||
4507	                             (c->cmd->proc == execCommand && (c->mstate.cmd_flags & CMD_DENYOOM));
4508	    int is_denystale_command = !(cmd_flags & CMD_STALE) ||
4509	                               (c->cmd->proc == execCommand && (c->mstate.cmd_inv_flags & CMD_STALE));
4510	    int is_denyloading_command = !(cmd_flags & CMD_LOADING) ||
4511	                                 (c->cmd->proc == execCommand && (c->mstate.cmd_inv_flags & CMD_LOADING));
4512	    int is_may_replicate_command = (cmd_flags & (CMD_WRITE | CMD_MAY_REPLICATE)) ||
4513	                                   (c->cmd->proc == execCommand && (c->mstate.cmd_flags & (CMD_WRITE | CMD_MAY_REPLICATE)));
4514	    int is_deny_async_loading_command = (cmd_flags & CMD_NO_ASYNC_LOADING) ||
4515	                                        (c->cmd->proc == execCommand && (c->mstate.cmd_flags & CMD_NO_ASYNC_LOADING));
4516	    int obey_client = mustObeyClient(c);
4517	
4518	    if (authRequired(c)) {
4519	        /* AUTH and HELLO and no auth commands are valid even in
4520	         * non-authenticated state. */
4521	        if (!(c->cmd->flags & CMD_NO_AUTH)) {
4522	            rejectCommand(c,shared.noautherr);
4523	            return C_OK;
4524	        }
4525	    }
4526	
4527	    if (c->flags & CLIENT_MULTI && c->cmd->flags & CMD_NO_MULTI) {
4528	        rejectCommandFormat(c,"Command not allowed inside a transaction");
4529	        return C_OK;
4530	    }
4531	
4532	    /* Check if the user can run this command according to the current
4533	     * ACLs. */
4534	    int acl_errpos;
4535	    int acl_retval = ACLCheckAllPerm(c,&acl_errpos);
4536	    if (acl_retval != ACL_OK) {
4537	        addACLLogEntry(c,acl_retval,(c->flags & CLIENT_MULTI) ? ACL_LOG_CTX_MULTI : ACL_LOG_CTX_TOPLEVEL,acl_errpos,NULL,NULL);
4538	        sds msg = getAclErrorMessage(acl_retval, c->user, c->cmd, c->argv[acl_errpos]->ptr, 0);
4539	        rejectCommandFormat(c, "-NOPERM %s", msg);
4540	        sdsfree(msg);
4541	        return C_OK;
4542	    }
4543	
4544	    /* If cluster is enabled perform the cluster redirection here.
4545	     * However we don't perform the redirection if:
4546	     * 1) The sender of this command is our master.
4547	     * 2) The command has no key arguments. */
4548	    if (server.cluster_enabled &&
4549	        !mustObeyClient(c) &&
4550	        !(!(c->cmd->flags&CMD_MOVABLE_KEYS) && c->cmd->key_specs_num == 0 &&
4551	          c->cmd->proc != execCommand))
4552	    {
4553	        int error_code;
4554	        clusterNode *n = getNodeByQuery(c,c->cmd,c->argv,c->argc,
4555	            &c->slot,getClientCachedKeyResult(c),c->read_error,cmd_flags,&error_code);
4556	        if (n == NULL || !clusterNodeIsMyself(n)) {
4557	            if (c->cmd->proc == execCommand) {
4558	                discardTransaction(c);
4559	            } else {
4560	                flagTransaction(c);
4561	            }
4562	            clusterRedirectClient(c,n,c->slot,error_code);
4563	            c->duration = 0;
4564	            c->cmd->rejected_calls++;
4565	            return C_OK;
4566	        }
4567	    }
4568	
4569	    /* Check if the command keys are all in the same slot for cluster compatibility */
4570	    if (server.cluster_compatibility_sample_ratio && !server.cluster_enabled &&
4571	        !(!(c->cmd->flags&CMD_MOVABLE_KEYS) && c->cmd->key_specs_num == 0 &&
4572	          c->cmd->proc != execCommand) && SHOULD_CLUSTER_COMPATIBILITY_SAMPLE())
4573	    {
4574	        c->cluster_compatibility_check_slot = -1;
4575	        if (!areCommandKeysInSameSlot(c, &c->cluster_compatibility_check_slot)) {
4576	            server.stat_cluster_incompatible_ops++;
4577	            /* If we find cross slot keys, reset slot to -2 to indicate we won't
4578	             * check this command again. That is useful for script, since we need
4579	             * this variable to decide if we continue checking accessing keys. */
4580	            c->cluster_compatibility_check_slot = -2;
4581	        }
4582	    }
4583	
4584	    /* Disconnect some clients if total clients memory is too high. We do this
4585	     * before key eviction, after the last command was executed and consumed
4586	     * some client output buffer memory. */
4587	    evictClients();
4588	    if (server.current_client == NULL) {
4589	        /* If we evicted ourself then abort processing the command */
4590	        return C_ERR;
4591	    }
4592	
4593	    /* Handle the maxmemory directive.
4594	     *
4595	     * Note that we do not want to reclaim memory if we are here re-entering
4596	     * the event loop since there is a busy Lua script running in timeout
4597	     * condition, to avoid mixing the propagation of scripts with the
4598	     * propagation of DELs due to eviction. */
4599	    if (server.maxmemory && !isInsideYieldingLongCommand()) {
4600	        int out_of_memory = (performEvictions() == EVICT_FAIL);
4601	
4602	        /* performEvictions may evict keys, so we need flush pending tracking
4603	         * invalidation keys. If we don't do this, we may get an invalidation
4604	         * message after we perform operation on the key, where in fact this
4605	         * message belongs to the old value of the key before it gets evicted.*/
4606	        trackingHandlePendingKeyInvalidations();
4607	
4608	        /* performEvictions may flush slave output buffers. This may result
4609	         * in a slave, that may be the active client, to be freed. */
4610	        if (server.current_client == NULL) return C_ERR;
4611	
4612	        if (out_of_memory && is_denyoom_command) {
4613	            rejectCommand(c, shared.oomerr);
4614	            return C_OK;
4615	        }
4616	
4617	        /* Save out_of_memory result at command start, otherwise if we check OOM
4618	         * in the first write within script, memory used by lua stack and
4619	         * arguments might interfere. We need to save it for EXEC and module
4620	         * calls too, since these can call EVAL, but avoid saving it during an
4621	         * interrupted / yielding busy script / module. */
4622	        server.pre_command_oom_state = out_of_memory;
4623	    }
4624	
4625	    /* Make sure to use a reasonable amount of memory for client side
4626	     * caching metadata. */
4627	    if (server.tracking_clients) trackingLimitUsedSlots();
4628	
4629	    /* Don't accept write commands if there are problems persisting on disk
4630	     * unless coming from our master, in which case check the replica ignore
4631	     * disk write error config to either log or crash. */
4632	    int deny_write_type = writeCommandsDeniedByDiskError();
4633	    if (deny_write_type != DISK_ERROR_TYPE_NONE &&
4634	        (is_write_command || c->cmd->proc == pingCommand))
4635	    {
4636	        if (obey_client) {
4637	            if (!server.repl_ignore_disk_write_error && c->cmd->proc != pingCommand) {
4638	                serverPanic("Replica was unable to write command to disk.");
4639	            } else {
4640	                static mstime_t last_log_time_ms = 0;
4641	                const mstime_t log_interval_ms = 10000;
4642	                if (server.mstime > last_log_time_ms + log_interval_ms) {
4643	                    last_log_time_ms = server.mstime;
4644	                    serverLog(LL_WARNING, "Replica is applying a command even though "
4645	                                          "it is unable to write to disk.");
4646	                }
4647	            }
4648	        } else {
4649	            sds err = writeCommandsGetDiskErrorMessage(deny_write_type);
4650	            /* remove the newline since rejectCommandSds adds it. */
4651	            sdssubstr(err, 0, sdslen(err)-2);
4652	            rejectCommandSds(c, err);
4653	            return C_OK;
4654	        }
4655	    }
4656	
4657	    /* Don't accept write commands if there are not enough good slaves and
4658	     * user configured the min-slaves-to-write option. */
4659	    if (is_write_command && !checkGoodReplicasStatus()) {
4660	        rejectCommand(c, shared.noreplicaserr);
4661	        return C_OK;
4662	    }
