26	static int checkStringLength(client *c, long long size, long long append) {
27	    if (mustObeyClient(c))
28	        return C_OK;
29	    /* 'uint64_t' cast is there just to prevent undefined behavior on overflow */
30	    long long total = (uint64_t)size + append;
31	    /* Test configured max-bulk-len representing a limit of the biggest string object,
32	     * and also test for overflow. */
33	    if (total > server.proto_max_bulk_len || total < size || total < append) {
34	        addReplyError(c,"string exceeds maximum allowed size (proto-max-bulk-len)");
35	        return C_ERR;
36	    }
37	    return C_OK;
38	}
