275	/* Extended string command arguments structure */
276	typedef struct {
277	    int flags;
278	    int unit;
279	    int expire_pos;  /* Position of EX/PX flag for replication rewriting */
280	    robj *expire;
281	    robj *match_value; /* For IFEQ/IFNE/IFDEQ/IFDNE conditions */
282	} extendedStringArgs;
283	
284	/*
285	 * The parseExtendedStringArgumentsOrReply() function performs the common validation for extended
286	 * string arguments used in SET, GET and MSETEX commands.
287	 *
288	 * Get specific commands - PERSIST/DEL
289	 * Set specific commands - XX/NX/GET/IFEQ/IFNE/IFDEQ/IFDNE
290	 * Common commands - EX/EXAT/PX/PXAT/KEEPTTL
291	 *
292	 * Function takes pointers to client, start_pos for where to begin parsing, extendedStringArgs
293	 * structure to populate, and command_type which can be COMMAND_GET, COMMAND_SET, or COMMAND_MSETEX.
294	 *
295	 * If there are any syntax violations C_ERR is returned else C_OK is returned.
296	 *
297	 * The args structure is updated upon parsing the arguments. Unit and expire are updated if there are any
298	 * EX/EXAT/PX/PXAT arguments. Unit is updated to millisecond if PX/PXAT is set.
299	 * match_value is updated if any of IFEQ/IFNE/IFDEQ/IFDNE is set.
300	 */
301	int parseExtendedStringArgumentsOrReply(client *c, int start_pos, extendedStringArgs *args, int command_type) {
302	    /* Initialize arguments to defaults */
303	    memset(args, 0, sizeof(*args));
304	    args->expire_pos = -1;
305	    args->unit = UNIT_SECONDS;
306	
307	    int j = start_pos;
308	   /* We can have either none or exactly one of these conditionals as they are
309	     * mutually exclusive. We'll make sure to check if none of the other flags
310	     * are already set if we are going to set one of them. This is done via the
311	     * check:
312	     *
313	     * if (opt == OBJ_SET_XXX && !(*flags & (cond_mut_excl & ~OBJ_SET_XXX)))
314	     *
315	     * A bit ugly - but concise.
316	     */
317	    int cond_mut_excl = OBJ_SET_NX | OBJ_SET_XX | OBJ_SET_IFEQ | OBJ_SET_IFNE |
318	                        OBJ_SET_IFDEQ | OBJ_SET_IFDNE;
319	    for (; j < c->argc; j++) {
320	        char *opt = c->argv[j]->ptr;
321	        robj *next = (j == c->argc-1) ? NULL : c->argv[j+1];
322	
323	        if ((opt[0] == 'n' || opt[0] == 'N') &&
324	            (opt[1] == 'x' || opt[1] == 'X') && opt[2] == '\0' &&
325	            !(args->flags & OBJ_SET_XX) && (command_type == COMMAND_SET || command_type == COMMAND_MSETEX))
326	        {
327	            args->flags |= OBJ_SET_NX;
328	        } else if ((opt[0] == 'x' || opt[0] == 'X') &&
329	                   (opt[1] == 'x' || opt[1] == 'X') && opt[2] == '\0' &&
330	                   !(args->flags & OBJ_SET_NX) && (command_type == COMMAND_SET || command_type == COMMAND_MSETEX))
331	        {
332	            args->flags |= OBJ_SET_XX;
333	        } else if ((opt[0] == 'g' || opt[0] == 'G') &&
334	                   (opt[1] == 'e' || opt[1] == 'E') &&
335	                   (opt[2] == 't' || opt[2] == 'T') && opt[3] == '\0' &&
336	                   (command_type == COMMAND_SET))
337	        {
338	            args->flags |= OBJ_SET_GET;
339	        } else if (!strcasecmp(opt, "KEEPTTL") && !(args->flags & OBJ_PERSIST) &&
340	            !(args->flags & OBJ_EX) && !(args->flags & OBJ_EXAT) &&
341	            !(args->flags & OBJ_PX) && !(args->flags & OBJ_PXAT) &&
342	            (command_type == COMMAND_SET || command_type == COMMAND_MSETEX))
343	        {
344	            args->flags |= OBJ_KEEPTTL;
345	        } else if (!strcasecmp(opt,"PERSIST") && (command_type == COMMAND_GET) &&
346	               !(args->flags & OBJ_EX) && !(args->flags & OBJ_EXAT) &&
347	               !(args->flags & OBJ_PX) && !(args->flags & OBJ_PXAT) &&
348	               !(args->flags & OBJ_KEEPTTL))
349	        {
350	            args->flags |= OBJ_PERSIST;
351	        } else if ((opt[0] == 'e' || opt[0] == 'E') &&
352	                   (opt[1] == 'x' || opt[1] == 'X') && opt[2] == '\0' &&
353	                   !(args->flags & OBJ_KEEPTTL) && !(args->flags & OBJ_PERSIST) &&
354	                   !(args->flags & OBJ_EXAT) && !(args->flags & OBJ_PX) &&
355	                   !(args->flags & OBJ_PXAT) && next)
356	        {
357	            args->flags |= OBJ_EX;
358	            args->expire = next;
359	            args->expire_pos = j;
360	            j++;
361	        } else if ((opt[0] == 'p' || opt[0] == 'P') &&
362	                   (opt[1] == 'x' || opt[1] == 'X') && opt[2] == '\0' &&
363	                   !(args->flags & OBJ_KEEPTTL) && !(args->flags & OBJ_PERSIST) &&
364	                   !(args->flags & OBJ_EX) && !(args->flags & OBJ_EXAT) &&
365	                   !(args->flags & OBJ_PXAT) && next)
366	        {
367	            args->flags |= OBJ_PX;
368	            args->unit = UNIT_MILLISECONDS;
369	            args->expire = next;
370	            args->expire_pos = j;
371	            j++;
372	        } else if ((opt[0] == 'e' || opt[0] == 'E') &&
373	                   (opt[1] == 'x' || opt[1] == 'X') &&
374	                   (opt[2] == 'a' || opt[2] == 'A') &&
375	                   (opt[3] == 't' || opt[3] == 'T') && opt[4] == '\0' &&
376	                   !(args->flags & OBJ_KEEPTTL) && !(args->flags & OBJ_PERSIST) &&
377	                   !(args->flags & OBJ_EX) && !(args->flags & OBJ_PX) &&
378	                   !(args->flags & OBJ_PXAT) && next)
379	        {
380	            args->flags |= OBJ_EXAT;
381	            args->expire = next;
382	            j++;
383	        } else if ((opt[0] == 'p' || opt[0] == 'P') &&
384	                   (opt[1] == 'x' || opt[1] == 'X') &&
385	                   (opt[2] == 'a' || opt[2] == 'A') &&
386	                   (opt[3] == 't' || opt[3] == 'T') && opt[4] == '\0' &&
387	                   !(args->flags & OBJ_KEEPTTL) && !(args->flags & OBJ_PERSIST) &&
388	                   !(args->flags & OBJ_EX) && !(args->flags & OBJ_EXAT) &&
389	                   !(args->flags & OBJ_PX) && next)
390	        {
391	            args->flags |= OBJ_PXAT;
392	            args->unit = UNIT_MILLISECONDS;
393	            args->expire = next;
394	            j++;
395	        } else if (!strcasecmp(opt, "ifeq") && next &&
396	                   !(args->flags & (cond_mut_excl & ~OBJ_SET_IFEQ)) &&
397	                   (command_type == COMMAND_SET))
398	        {
399	            args->flags |= OBJ_SET_IFEQ;
400	            args->match_value = next;
401	            j++;
402	        } else if (!strcasecmp(opt, "ifne") && next &&
403	                   !(args->flags & (cond_mut_excl & ~OBJ_SET_IFNE)) &&
404	                   (command_type == COMMAND_SET))
405	        {
406	            args->flags |= OBJ_SET_IFNE;
407	            args->match_value = next;
408	            j++;
409	        } else if (!strcasecmp(opt, "ifdeq") && next &&
410	                   !(args->flags & (cond_mut_excl & ~OBJ_SET_IFDEQ)) &&
411	                   (command_type == COMMAND_SET))
412	        {
413	            args->flags |= OBJ_SET_IFDEQ;
414	            args->match_value = next;
415	            j++;
416	        } else if (!strcasecmp(opt, "ifdne") && next &&
417	                   !(args->flags & (cond_mut_excl & ~OBJ_SET_IFDNE)) &&
418	                   (command_type == COMMAND_SET))
419	        {
420	            args->flags |= OBJ_SET_IFDNE;
421	            args->match_value = next;
422	            j++;
423	        } else {
424	            addReplyErrorObject(c,shared.syntaxerr);
425	            return C_ERR;
426	        }
427	    }
428	    return C_OK;
429	}
