431	/* SET key value [NX] [XX] [KEEPTTL] [GET] [EX <seconds>] [PX <milliseconds>]
432	 *     [EXAT <seconds-timestamp>][PXAT <milliseconds-timestamp>]
433	 *     [IFEQ <match-value>|IFNE <match-value>|IFDEQ <match-digest>|
434	 *      IFDNE <match-digest>]*/
435	void setCommand(client *c) {
436	    extendedStringArgs args;
437	
438	    if (parseExtendedStringArgumentsOrReply(c, 3, &args, COMMAND_SET) != C_OK) {
439	        return;
440	    }
441	
442	    c->argv[2] = tryObjectEncoding(c->argv[2]);
443	    setGenericCommand(c, args.flags, c->argv[1], &(c->argv[2]), args.expire, args.unit, args.match_value, NULL, NULL);
444	}
