446	void setnxCommand(client *c) {
447	    c->argv[2] = tryObjectEncoding(c->argv[2]);
448	    setGenericCommand(c, OBJ_SET_NX, c->argv[1], &(c->argv[2]), NULL, 0, NULL, shared.cone, shared.czero);
449	}
