479	/*
480	 * GETEX <key> [PERSIST][EX seconds][PX milliseconds][EXAT seconds-timestamp][PXAT milliseconds-timestamp]
481	 *
482	 * The getexCommand() function implements extended options and variants of the GET command. Unlike GET
483	 * command this command is not read-only.
484	 *
485	 * The default behavior when no options are specified is same as GET and does not alter any TTL.
486	 *
487	 * Only one of the below options can be used at a given time.
488	 *
489	 * 1. PERSIST removes any TTL associated with the key.
490	 * 2. EX Set expiry TTL in seconds.
491	 * 3. PX Set expiry TTL in milliseconds.
492	 * 4. EXAT Same like EX instead of specifying the number of seconds representing the TTL
493	 *      (time to live), it takes an absolute Unix timestamp
494	 * 5. PXAT Same like PX instead of specifying the number of milliseconds representing the TTL
495	 *      (time to live), it takes an absolute Unix timestamp
496	 *
497	 * Command would either return the bulk string, error or nil.
498	 */
499	void getexCommand(client *c) {
500	    extendedStringArgs args;
501	
502	    if (parseExtendedStringArgumentsOrReply(c, 2, &args, COMMAND_GET) != C_OK) {
503	        return;
504	    }
505	
506	    kvobj *o;
507	
508	    if ((o = lookupKeyReadOrReply(c,c->argv[1],shared.null[c->resp])) == NULL)
509	        return;
510	
511	    if (checkType(c,o,OBJ_STRING)) {
512	        return;
513	    }
514	
515	    /* Validate the expiration time value first */
516	    long long milliseconds = 0;
517	    int relative_ttl = (args.flags & (OBJ_EX|OBJ_PX)) != 0; /* EX/PX are relative; EXAT/PXAT are absolute. */
518	    if (args.expire && getExpireMillisecondsOrReply(c, args.expire, relative_ttl, args.unit, &milliseconds) != C_OK) {
519	        return;
520	    }
521	
522	    /* We need to do this before we expire the key or delete it */
523	    addReplyBulk(c,o);
524	
525	    /* This command is never propagated as is. It is either propagated as PEXPIRE[AT],DEL,UNLINK or PERSIST.
526	     * This why it doesn't need special handling in feedAppendOnlyFile to convert relative expire time to absolute one. */
527	    if (((args.flags & OBJ_PXAT) || (args.flags & OBJ_EXAT)) && checkAlreadyExpired(milliseconds)) {
528	        /* When PXAT/EXAT absolute timestamp is specified, there can be a chance that timestamp
529	         * has already elapsed so delete the key in that case. */
530	        int deleted = dbGenericDelete(c->db, c->argv[1], server.lazyfree_lazy_expire, DB_FLAG_KEY_EXPIRED);
531	        serverAssert(deleted);
532	        robj *aux = server.lazyfree_lazy_expire ? shared.unlink : shared.del;
533	        rewriteClientCommandVector(c,2,aux,c->argv[1]);
534	        keyModified(c, c->db, c->argv[1], NULL, 1);
535	        notifyKeyspaceEvent(NOTIFY_GENERIC, "del", c->argv[1], c->db->id);
536	        server.dirty++;
537	    } else if (args.expire) {
538	        o = setExpire(c,c->db,c->argv[1],milliseconds);
539	        /* Propagate as PXEXPIREAT millisecond-timestamp if there is
540	         * EX/PX/EXAT/PXAT flag and the key has not expired. */
541	        robj *milliseconds_obj = createStringObjectFromLongLong(milliseconds);
542	        rewriteClientCommandVector(c,3,shared.pexpireat,c->argv[1],milliseconds_obj);
543	        decrRefCount(milliseconds_obj);
544	        keyModified(c, c->db, c->argv[1], o, 1);
545	        notifyKeyspaceEvent(NOTIFY_GENERIC,"expire",c->argv[1],c->db->id);
546	        server.dirty++;
547	    } else if (args.flags & OBJ_PERSIST) {
548	        if (removeExpire(c->db, c->argv[1])) {
549	            keyModified(c, c->db, c->argv[1], o, 1);
550	            rewriteClientCommandVector(c, 2, shared.persist, c->argv[1]);
551	            notifyKeyspaceEvent(NOTIFY_GENERIC,"persist",c->argv[1],c->db->id);
552	            server.dirty++;
553	        }
554	    }
555	}
