580	void setrangeCommand(client *c) {
581	    int64_t oldLen = -1, newLen;
582	    long offset;
583	    sds value = c->argv[3]->ptr;
584	    const size_t value_len = sdslen(value);
585	
586	    if (getLongFromObjectOrReply(c,c->argv[2],&offset,NULL) != C_OK)
587	        return;
588	
589	    if (offset < 0) {
590	        addReplyError(c,"offset is out of range");
591	        return;
592	    }
593	
594	    dictEntryLink link;
595	    kvobj *kv = lookupKeyWriteWithLink(c->db, c->argv[1], &link);
596	    if (kv == NULL) {
597	        /* Return 0 when setting nothing on a non-existing string */
598	        if (value_len == 0) {
599	            addReply(c,shared.czero);
600	            return;
601	        }
602	
603	        /* Return when the resulting string exceeds allowed size */
604	        if (checkStringLength(c,offset,value_len) != C_OK)
605	            return;
606	
607	        newLen = offset+value_len;
608	        robj *o = createObject(OBJ_STRING,sdsnewlen(NULL, newLen));
609	        kv = dbAddByLink(c->db, c->argv[1], &o, &link);
610	    } else {
611	        /* Key exists, check type */
612	        if (checkType(c,kv,OBJ_STRING))
613	            return;
614	
615	        /* Return existing string length when setting nothing */
616	        oldLen = stringObjectLen(kv);
617	        if (value_len == 0) {
618	            addReplyLongLong(c, oldLen);
619	            return;
620	        }
621	
622	        /* Return when the resulting string exceeds allowed size */
623	        if (checkStringLength(c,offset,value_len) != C_OK)
624	            return;
625	
626	        /* Create a copy when the object is shared or encoded. */
627	        kv = dbUnshareStringValueByLink(c->db, c->argv[1], kv, link);
628	
629	        newLen = max(oldLen, (int64_t) (offset + value_len));
630	        updateKeysizesHist(c->db, OBJ_STRING, oldLen, newLen);            
631	    }
632	
633	    if (value_len > 0) {
634	        size_t oldsize = 0;
635	        if (server.memory_tracking_enabled)
636	            oldsize = kvobjAllocSize(kv);
637	        kv->ptr = sdsgrowzero(kv->ptr,offset+value_len);
638	        if (server.memory_tracking_enabled)
639	            updateSlotAllocSize(c->db, getKeySlot(c->argv[1]->ptr), kv, oldsize, kvobjAllocSize(kv));
640	        memcpy((char*)kv->ptr+offset,value,value_len);
641	        keyModified(c,c->db,c->argv[1],kv,1);
642	        notifyKeyspaceEvent(NOTIFY_STRING,
643	            "setrange",c->argv[1],c->db->id);
644	        server.dirty++;
645	    }
646	
647	    addReplyLongLong(c,newLen);
648	}
