650	void getrangeCommand(client *c) {
651	    kvobj *o;
652	    long long start, end;
653	    char *str, llbuf[32];
654	    size_t strlen;
655	
656	    if (getLongLongFromObjectOrReply(c,c->argv[2],&start,NULL) != C_OK)
657	        return;
658	    if (getLongLongFromObjectOrReply(c,c->argv[3],&end,NULL) != C_OK)
659	        return;
660	    if ((o = lookupKeyReadOrReply(c,c->argv[1],shared.emptybulk)) == NULL ||
661	        checkType(c,o,OBJ_STRING)) return;
662	
663	    if (o->encoding == OBJ_ENCODING_INT) {
664	        str = llbuf;
665	        strlen = ll2string(llbuf,sizeof(llbuf),(long)o->ptr);
666	    } else {
667	        str = o->ptr;
668	        strlen = sdslen(str);
669	    }
670	
671	    /* Convert negative indexes */
672	    if (start < 0 && end < 0 && start > end) {
673	        addReply(c,shared.emptybulk);
674	        return;
675	    }
676	    if (start < 0) start = strlen+start;
677	    if (end < 0) end = strlen+end;
678	    if (start < 0) start = 0;
679	    if (end < 0) end = 0;
680	    if ((unsigned long long)end >= strlen) end = strlen-1;
681	
682	    /* Precondition: end >= 0 && end < strlen, so the only condition where
683	     * nothing can be returned is: start > end. */
684	    if (start > end || strlen == 0) {
685	        addReply(c,shared.emptybulk);
686	    } else {
687	        addReplyBulkCBuffer(c,(char*)str+start,end-start+1);
688	    }
689	}
