691	/* Batch size for intra-command key prefetching. */
692	#define PREFETCH_BATCH_SIZE 16
693	
694	/* Pick the next prefetch batch starting at argv[start] and warm it via
695	 * dictPrefetchKeys. 'stride' is 1 for keys-only args (MGET) or 2 for
696	 * key/value pairs (MSET). Returns the chosen batch size in items. */
697	static int prefetchKeysBatch(client *c, int slot, int start, int stride) {
698	    int batch = (c->argc - start) / stride;
699	
700	    /* If at least two full batches remain, take one; otherwise fall
701	     * through with batch = remaining keys, doing them in one go. */
702	    if (batch >= PREFETCH_BATCH_SIZE*2) batch = PREFETCH_BATCH_SIZE;
703	
704	    dict *d = kvstoreGetDict(c->db->keys, slot);
705	    if (d != NULL && dictSize(d) > 0) {
706	        void *keys[PREFETCH_BATCH_SIZE*2];
707	        dict *dicts[PREFETCH_BATCH_SIZE*2];
708	        for (int k = 0; k < batch; k++) {
709	            keys[k]  = c->argv[start + k * stride]->ptr;
710	            dicts[k] = d;
711	        }
712	        dictPrefetchKeys(dicts, keys, batch);
713	    }
714	    return batch;
715	}
