717	void mgetCommand(client *c) {
718	    int numkeys = c->argc - 1;
719	
720	    addReplyArrayLen(c, numkeys);
721	
722	    /* MGET requires all keys in the same slot in cluster mode. Reuse the
723	     * slot already computed by the cross-command batching path when
724	     * available, otherwise fall back to recomputing from argv[1]. */
725	    int slot = 0;
726	    if (server.cluster_enabled) {
727	        pendingCommand *pcmd = c->current_pending_cmd;
728	        slot = (pcmd && pcmd->slot != INVALID_CLUSTER_SLOT) ?
729	                pcmd->slot : getKeySlot(c->argv[1]->ptr);
730	    }
731	
732	    /* Decide whether to prefetch within this command. Skip if disabled by
733	     * config (prefetch_batch_max_size == 0), or if the cross-command batch
734	     * path already warmed our keys — running both paths would just contend
735	     * for cache bandwidth. */
736	    int already_prefetched = c->current_pending_cmd &&
737	        (c->current_pending_cmd->flags & PENDING_CMD_KEYS_PREFETCHED);
738	    int do_prefetch = server.prefetch_batch_max_size && !already_prefetched && numkeys > 1;
739	
740	    int j = 1;
741	    while (j < c->argc) {
742	        /* If prefetching, take one batch; otherwise take all items. */
743	        int batch = do_prefetch ? prefetchKeysBatch(c, slot, j, 1) : c->argc - j;
744	
745	        for (int k = 0; k < batch; k++) {
746	            kvobj *o = lookupKeyRead(c->db, c->argv[j + k]);
747	            if (o == NULL || o->type != OBJ_STRING)
748	                addReplyNull(c);
749	            else
750	                addReplyBulk(c, o);
751	        }
752	        j += batch;
753	    }
754	}
