756	void msetGenericCommand(client *c, int nx) {
757	    if ((c->argc % 2) == 0) {
758	        addReplyErrorArity(c);
759	        return;
760	    }
761	
762	    int numkeys = (c->argc - 1) / 2;
763	
764	    /* Same gating as mgetCommand, see comment there. */
765	    int slot = 0;
766	    if (server.cluster_enabled) {
767	        pendingCommand *pcmd = c->current_pending_cmd;
768	        slot = (pcmd && pcmd->slot != INVALID_CLUSTER_SLOT) ?
769	                pcmd->slot : getKeySlot(c->argv[1]->ptr);
770	    }
771	    int already_prefetched = c->current_pending_cmd &&
772	        (c->current_pending_cmd->flags & PENDING_CMD_KEYS_PREFETCHED);
773	    int do_prefetch = server.prefetch_batch_max_size && !already_prefetched && numkeys > 1;
774	
775	    /* Handle the NX flag. The MSETNX semantic is to return zero and don't
776	     * set anything if at least one key already exists. */
777	    if (nx) {
778	        int j = 1;
779	        while (j < c->argc) {
780	            /* If prefetching, take one batch; otherwise take all items. */
781	            int batch = do_prefetch ? prefetchKeysBatch(c, slot, j, 2)
782	                                    : (c->argc - j) / 2;
783	            for (int k = 0; k < batch; k++) {
784	                if (lookupKeyWrite(c->db, c->argv[j + k * 2]) != NULL) {
785	                    addReply(c, shared.czero);
786	                    return;
787	                }
788	            }
789	            j += batch * 2;
790	        }
791	    }
792	
793	    /* If nx is set, the NX loop above already prefetched. */
794	    do_prefetch = do_prefetch && !nx;
795	
796	    int j = 1;
797	    while (j < c->argc) {
798	        int batch = do_prefetch ? prefetchKeysBatch(c, slot, j, 2)
799	                                : (c->argc - j) / 2;
800	        for (int k = 0; k < batch; k++) {
801	            int i = j + k * 2;
802	            c->argv[i + 1] = tryObjectEncoding(c->argv[i + 1]);
803	            setKey(c, c->db, c->argv[i], &(c->argv[i + 1]), 0);
804	            incrRefCount(c->argv[i + 1]);
805	            notifyKeyspaceEvent(NOTIFY_STRING, "set", c->argv[i], c->db->id);
806	        }
807	        j += batch * 2;
808	    }
809	    server.dirty += numkeys;
810	    addReply(c, nx ? shared.cone : shared.ok);
811	}
