821	void msetexCommand(client *c) {
822	    /* Parse numkeys parameter */
823	    long kv_count;
824	    if (getRangeLongFromObjectOrReply(c, c->argv[1], 1, INT_MAX,
825	        &kv_count, "invalid numkeys value") != C_OK)
826	    {
827	        return;
828	    }
829	
830	    /* Validate we have enough arguments: command + numkeys + (key-value pairs) * 2
831	     * Be careful to avoid overflow when calculating kv_count * 2 */
832	    if ((long long)kv_count * 2 + 2 > c->argc) {
833	        addReplyError(c, "wrong number of key-value pairs");
834	        return;
835	    }
836	
837	    extendedStringArgs args;
838	    if (parseExtendedStringArgumentsOrReply(c, kv_count * 2 + 2, &args, COMMAND_MSETEX) != C_OK) {
839	        return;
840	    }
841	
842	    /* Validate the expiration time value first */
843	    long long milliseconds = 0;
844	    int relative_ttl = (args.flags & (OBJ_EX|OBJ_PX)) != 0; /* EX/PX are relative; EXAT/PXAT are absolute. */
845	    if (args.expire && getExpireMillisecondsOrReply(c, args.expire, relative_ttl, args.unit, &milliseconds) != C_OK) {
846	        return;
847	    }
848	
849	    if (args.flags & (OBJ_SET_NX | OBJ_SET_XX)) {
850	        /* Check NX/XX conditions for each key - pattern from setGenericCommand */
851	        for (int j = 0; j < kv_count; j++) {
852	            int key_idx = (j * 2) + 2;
853	            robj *found = lookupKeyWrite(c->db, c->argv[key_idx]);
854	
855	            if ((args.flags & OBJ_SET_NX && found) ||
856	                (args.flags & OBJ_SET_XX && !found))
857	            {
858	                addReply(c, shared.czero);
859	                return;
860	            }
861	        }
862	    }
863	
864	    /* Set all key-value pairs */
865	    for (int j = 0; j < kv_count; j++) {
866	        int key_idx = (j * 2) + 2;
867	        int val_idx = key_idx + 1;
868	
869	        c->argv[val_idx] = tryObjectEncoding(c->argv[val_idx]);
870	
871	        /* Handle KEEPTTL - preserve existing TTL */
872	        int setkey_flags = 0;
873	        if (args.flags & OBJ_KEEPTTL) {
874	            setkey_flags |= SETKEY_KEEPTTL;
875	        }
876	
877	        setKey(c, c->db, c->argv[key_idx], &(c->argv[val_idx]), setkey_flags);
878	        incrRefCount(c->argv[val_idx]);
879	
880	        /* Set expiration for each key (but not for KEEPTTL) */
881	        if (args.expire && !(args.flags & OBJ_KEEPTTL)) {
882	            setExpire(c, c->db, c->argv[key_idx], milliseconds);
883	            notifyKeyspaceEvent(NOTIFY_GENERIC,"expire",c->argv[key_idx],c->db->id);
884	        }
885	        notifyKeyspaceEvent(NOTIFY_STRING,"set",c->argv[key_idx],c->db->id);
886	    }
887	
888	    /* Handle replication rewriting for relative expiration times */
889	    if (args.expire && !(args.flags & OBJ_PXAT) && !(args.flags & OBJ_EXAT) && args.expire_pos != -1) {
890	        /* Convert EX/PX (relative) to PXAT (absolute) for consistent replication */
891	        robj *milliseconds_obj = createStringObjectFromLongLong(milliseconds);
892	        rewriteClientCommandArgument(c, args.expire_pos, shared.pxat);
893	        rewriteClientCommandArgument(c, args.expire_pos + 1, milliseconds_obj);
894	        decrRefCount(milliseconds_obj);
895	    }
896	
897	    server.dirty += kv_count;
898	    addReply(c, shared.cone);
899	}
