901	void incrDecrCommand(client *c, long long incr) {
902	    long long value, oldvalue;
903	    robj *new;
904	    dictEntryLink link;
905	    kvobj *o = lookupKeyWriteWithLink(c->db, c->argv[1], &link);
906	    if (checkType(c,o,OBJ_STRING)) return;
907	    if (getLongLongFromObjectOrReply(c,o,&value,NULL) != C_OK) return;
908	
909	    oldvalue = value;
910	    if ((incr < 0 && oldvalue < 0 && incr < (LLONG_MIN-oldvalue)) ||
911	        (incr > 0 && oldvalue > 0 && incr > (LLONG_MAX-oldvalue))) {
912	        addReplyError(c,"increment or decrement would overflow");
913	        return;
914	    }
915	    value += incr;
916	
917	    if (o && o->refcount == 1 && o->encoding == OBJ_ENCODING_INT &&
918	        value >= LONG_MIN && value <= LONG_MAX)
919	    {
920	        new = o;
921	        o->ptr = (void*)((long)value);
922	        updateKeysizesHist(c->db, OBJ_STRING,
923	                           (int64_t) sdigits10(oldvalue),
924	                           (int64_t) sdigits10(value));
925	    } else {
926	        new = createStringObjectFromLongLongForValue(value);
927	        if (o) {
928	            /* replace value in db and also update keysizes hist */
929	            dbReplaceValueWithLink(c->db, c->argv[1], &new, link);
930	        } else {
931	            /* Add new key to db and also update keysizes hist */
932	            dbAddByLink(c->db, c->argv[1], &new, &link);
933	        }
934	    }
935	    addReplyLongLongFromStr(c,new);
936	    keyModified(c,c->db,c->argv[1],new,1);
937	    notifyKeyspaceEvent(NOTIFY_STRING,"incrby",c->argv[1],c->db->id);
938	    server.dirty++;
939	}
