968	void incrbyfloatCommand(client *c) {
969	    long double incr, value;
970	
971	    dictEntryLink link;
972	    kvobj *o = lookupKeyWriteWithLink(c->db,c->argv[1],&link);
973	    if (checkType(c,o,OBJ_STRING)) return;
974	    if (getLongDoubleFromObjectOrReply(c,o,&value,NULL) != C_OK ||
975	        getLongDoubleFromObjectOrReply(c,c->argv[2],&incr,NULL) != C_OK)
976	        return;
977	
978	    value += incr;
979	    if (isnan(value) || isinf(value)) {
980	        addReplyError(c,"increment would produce NaN or Infinity");
981	        return;
982	    }
983	    robj *new = createStringObjectFromLongDouble(value,1);
984	    if (o)
985	        dbReplaceValueWithLink(c->db, c->argv[1], &new, link);
986	    else
987	        dbAddByLink(c->db, c->argv[1], &new, &link);
988	    keyModified(c,c->db,c->argv[1],new,1);
989	    notifyKeyspaceEvent(NOTIFY_STRING,"incrbyfloat",c->argv[1],c->db->id);
990	    server.dirty++;
991	    addReplyBulk(c,new);
992	
993	    /* Always replicate INCRBYFLOAT as a SET command with the final value
994	     * in order to make sure that differences in float precision or formatting
995	     * will not create differences in replicas or after an AOF restart. */
996	    rewriteClientCommandArgument(c,0,shared.set);
997	    rewriteClientCommandArgument(c,2,new);
998	    rewriteClientCommandArgument(c,3,shared.keepttl);
999	}
