1001	/* INCREX option flags. */
1002	#define OBJ_INCREX_BYFLOAT (1<<0)  /* Set if float-point increment is given */
1003	#define OBJ_INCREX_BYINT   (1<<1)  /* Set if integer increment is given */
1004	#define OBJ_INCREX_LBOUND  (1<<2)  /* Set if lower bound of increx result is given */
1005	#define OBJ_INCREX_UBOUND  (1<<3)  /* Set if upper bound of increx result is given */
1006	#define OBJ_INCREX_SATURATE (1<<4) /* Saturate the result to LBOUND/UBOUND/type limits when out of bounds. */
1007	#define OBJ_INCREX_ENX     (1<<5)  /* Set expiration only when the key has no expiry */
1008	#define OBJ_INCREX_PERSIST (1<<6)  /* Set if we need to remove the ttl */
1009	#define OBJ_INCREX_EX      (1<<7)  /* Set if time in seconds is given */
1010	#define OBJ_INCREX_PX      (1<<8)  /* Set if time in ms is given */
1011	#define OBJ_INCREX_EXAT    (1<<9)  /* Set if timestamp in second is given */
1012	#define OBJ_INCREX_PXAT    (1<<10) /* Set if timestamp in ms is given */
1013	
1014	/* INCREX argument structure */
1015	typedef struct {
1016	    int flags;             /* OBJ_INCREX_* bits set during parsing. */
1017	    int unit;              /* UNIT_SECONDS or UNIT_MILLISECONDS for EX/PX/EXAT/PXAT. */
1018	    long long expire_ms;   /* Absolute expire timestamp in ms (0 if no expiration given). */
1019	    long long incr_ll;     /* BYINT increment value (defaults to 1). */
1020	    long long ub_ll;       /* BYINT upper bound (defaults to LLONG_MAX). */
1021	    long long lb_ll;       /* BYINT lower bound (defaults to LLONG_MIN). */
1022	    long double incr_ld;   /* BYFLOAT increment value (defaults to 0). */
1023	    long double ub_ld;     /* BYFLOAT upper bound (defaults to LDBL_MAX). */
1024	    long double lb_ld;     /* BYFLOAT lower bound (defaults to -LDBL_MAX). */
1025	} incrExArgs;
1026	
1027	/* The parseIncrExArgumentsOrReply() function performs validation for INCREX command.
1028	 * If there are any syntax violations C_ERR is returned else C_OK is returned. */
1029	static int parseIncrExArgumentsOrReply(client *c, int start_pos, incrExArgs *args) {
1030	    memset(args, 0, sizeof(*args));
1031	    args->unit = UNIT_SECONDS;
1032	    args->incr_ll = 1;
1033	    args->lb_ll = LLONG_MIN;
1034	    args->ub_ll = LLONG_MAX;
1035	    args->lb_ld = -LDBL_MAX;
1036	    args->ub_ld = LDBL_MAX;
1037	
1038	    /* LBOUND/UBOUND values are parsed after the loop because their target type
1039	     * depends on whether BYINT or BYFLOAT was given, which may appear later. */
1040	    robj *lower_bound = NULL, *upper_bound = NULL, *expire = NULL;
1041	
1042	    /* Mask of all mutually-exclusive expiration-related flags. */
1043	    const int expire_flags = OBJ_INCREX_EX|OBJ_INCREX_PX|OBJ_INCREX_EXAT|OBJ_INCREX_PXAT|OBJ_INCREX_PERSIST;
1044	
1045	    for (int j = start_pos; j < c->argc; j++) {
1046	        char *opt = c->argv[j]->ptr;
1047	        robj *next = (j == c->argc-1) ? NULL : c->argv[j+1];
1048	
1049	        if (!strcasecmp(opt, "BYINT") && next && !(args->flags & (OBJ_INCREX_BYINT|OBJ_INCREX_BYFLOAT))) {
1050	            if (getLongLongFromObjectOrReply(c, next, &args->incr_ll,
1051	                    "Increment is not an integer or out of range") != C_OK)
1052	            {
1053	                return C_ERR;
1054	            }
1055	            args->flags |= OBJ_INCREX_BYINT;
1056	            j++;
1057	        } else if (!strcasecmp(opt, "BYFLOAT") && next && !(args->flags & (OBJ_INCREX_BYINT|OBJ_INCREX_BYFLOAT))) {
1058	            if (getLongDoubleFromObjectOrReply(c, next, &args->incr_ld,
1059	                    "Increment is not a valid float") != C_OK)
1060	            {
1061	                return C_ERR;
1062	            }
1063	            if (isinf(args->incr_ld)) {
1064	                addReplyError(c, "BYFLOAT increment cannot be Infinity");
1065	                return C_ERR;
1066	            }
1067	            args->flags |= OBJ_INCREX_BYFLOAT;
1068	            j++;
1069	        } else if (!strcasecmp(opt, "LBOUND") && next && !(args->flags & OBJ_INCREX_LBOUND)) {
1070	            args->flags |= OBJ_INCREX_LBOUND;
1071	            lower_bound = next;
1072	            j++;
1073	        } else if (!strcasecmp(opt, "UBOUND") && next && !(args->flags & OBJ_INCREX_UBOUND)) {
1074	            args->flags |= OBJ_INCREX_UBOUND;
1075	            upper_bound = next;
1076	            j++;
1077	        } else if (!strcasecmp(opt, "SATURATE") && !(args->flags & OBJ_INCREX_SATURATE)) {
1078	            args->flags |= OBJ_INCREX_SATURATE;
1079	        } else if (!strcasecmp(opt, "ENX") && !(args->flags & (OBJ_INCREX_ENX|OBJ_INCREX_PERSIST))) {
1080	            args->flags |= OBJ_INCREX_ENX;
1081	        } else if (!strcasecmp(opt, "PERSIST") && !(args->flags & (expire_flags|OBJ_INCREX_ENX))) {
1082	            args->flags |= OBJ_INCREX_PERSIST;
1083	        } else if (!strcasecmp(opt, "EX") && !(args->flags & expire_flags) && next) {
1084	            args->flags |= OBJ_INCREX_EX;
1085	            expire = next;
1086	            j++;
1087	        } else if (!strcasecmp(opt, "PX") && !(args->flags & expire_flags) && next) {
1088	            args->flags |= OBJ_INCREX_PX;
1089	            args->unit = UNIT_MILLISECONDS;
1090	            expire = next;
1091	            j++;
1092	        } else if (!strcasecmp(opt, "EXAT") && !(args->flags & expire_flags) && next) {
1093	            args->flags |= OBJ_INCREX_EXAT;
1094	            expire = next;
1095	            j++;
1096	        } else if (!strcasecmp(opt, "PXAT") && !(args->flags & expire_flags) && next) {
1097	            args->flags |= OBJ_INCREX_PXAT;
1098	            args->unit = UNIT_MILLISECONDS;
1099	            expire = next;
1100	            j++;
1101	        } else {
1102	            addReplyErrorObject(c, shared.syntaxerr);
1103	            return C_ERR;
1104	        }
1105	    }
1106	
1107	    /* Resolve LBOUND/UBOUND values now that BYINT/BYFLOAT is known. */
1108	    if (args->flags & OBJ_INCREX_BYFLOAT) {
1109	        if (lower_bound && getLongDoubleFromObjectOrReply(c, lower_bound, &args->lb_ld,
1110	                "LBOUND is not a valid float") != C_OK)
1111	        {
1112	            return C_ERR;
1113	        }
1114	        if (upper_bound && getLongDoubleFromObjectOrReply(c, upper_bound, &args->ub_ld,
1115	                "UBOUND is not a valid float") != C_OK)
1116	        {
1117	            return C_ERR;
1118	        }
1119	        if (args->lb_ld > args->ub_ld) {
1120	            addReplyError(c, "LBOUND can't be greater than UBOUND");
1121	            return C_ERR;
1122	        }
1123	    } else {
1124	        if (lower_bound && getLongLongFromObjectOrReply(c, lower_bound, &args->lb_ll,
1125	                "LBOUND is not an integer or out of range") != C_OK)
1126	        {
1127	            return C_ERR;
1128	        }
1129	        if (upper_bound && getLongLongFromObjectOrReply(c, upper_bound, &args->ub_ll,
1130	                "UBOUND is not an integer or out of range") != C_OK)
1131	        {
1132	            return C_ERR;
1133	        }
1134	        if (args->lb_ll > args->ub_ll) {
1135	            addReplyError(c, "LBOUND can't be greater than UBOUND");
1136	            return C_ERR;
1137	        }
1138	    }
1139	
1140	    /* ENX requires an expiration option. */
1141	    if ((args->flags & OBJ_INCREX_ENX) && !(args->flags & expire_flags)) {
1142	        addReplyError(c, "ENX flag requires an expiration");
1143	        return C_ERR;
1144	    }
1145	
1146	    if (expire) {
1147	        int relative_ttl = (args->flags & (OBJ_INCREX_EX|OBJ_INCREX_PX)) != 0;
1148	        if (getExpireMillisecondsOrReply(c, expire, relative_ttl, args->unit, &args->expire_ms) != C_OK)
1149	            return C_ERR;
1150	    }
1151	    return C_OK;
1152	}
