1154	/*
1155	 * INCREX <key> [BYFLOAT increment | BYINT increment] [LBOUND lowerbound]
1156	 *   [UBOUND upperbound] [SATURATE]
1157	 *   [EX seconds | PX milliseconds | EXAT seconds-timestamp | PXAT milliseconds-timestamp | PERSIST] [ENX]
1158	 *
1159	 * Increments the numeric value of a key and optionally updates its expiration time.
1160	 *
1161	 * Increment options:
1162	 * Defaults to incrementing by 1 (like INCR) if no increment option is given.
1163	 * At most one of the following may be specified:
1164	 * - BYINT:   Increment by an integer (like INCRBY).
1165	 * - BYFLOAT: Increment by a float (like INCRBYFLOAT). Returns an error if the result is NaN or Infinity.
1166	 *
1167	 * Range options:
1168	 * LBOUND and UBOUND optionally restrict the result to a range. The behavior
1169	 * when the result would land outside that range (or, with no explicit bound,
1170	 * would overflow the type limits) is controlled by SATURATE:
1171	 * - Default:    the operation is rejected (the key value and TTL are left
1172	 *               unchanged) and the reply is the current value with an applied
1173	 *               increment of 0.
1174	 * - SATURATE:   the result is capped at UBOUND / floored at LBOUND (or
1175	 *               saturated to the type limits when no explicit bound is given)
1176	 *               instead of being rejected.
1177	 *
1178	 * Expiration options:
1179	 * At most one of the following may be specified:
1180	 * - EX:      Set expiration in seconds.
1181	 * - PX:      Set expiration in milliseconds.
1182	 * - EXAT:    Set expiration to an absolute Unix timestamp (seconds).
1183	 * - PXAT:    Set expiration to an absolute Unix timestamp (milliseconds).
1184	 * - PERSIST: Remove the key's TTL.
1185	 *
1186	 * If no expiration option is given, the key's existing TTL is preserved.
1187	 * ENX restricts expiration updates to keys that currently have no TTL.
1188	 *
1189	 * Reply:
1190	 * - (Array) of two Bulk Strings on success:
1191	 *   1. The new value of the key after the increment.
1192	 *   2. The actual increment applied.
1193	 *
1194	 * Note: When the result is saturated by LBOUND/UBOUND, the expiration is still updated normally.
1195	 */
1196	void increxCommand(client *c) {
1197	    kvobj *o = NULL;
1198	    robj *new = NULL;
1199	    dictEntryLink link;
1200	    long long value_ll, oldvalue_ll = 0;
1201	    long double value_ld, oldvalue_ld = 0;
1202	
1203	    incrExArgs args;
1204	    if (parseIncrExArgumentsOrReply(c, 2, &args) != C_OK)
1205	        return;
1206	
1207	    o = lookupKeyWriteWithLink(c->db, c->argv[1], &link);
1208	    if (checkType(c, o, OBJ_STRING)) return;
1209	
1210	    int byfloat = args.flags & OBJ_INCREX_BYFLOAT;
1211	    /* By default the operation is rejected on out-of-bounds:
1212	     * leave the key unchanged and reply [current_value, 0]. */
1213	    int sat_mode = args.flags & OBJ_INCREX_SATURATE;
1214	    if (byfloat) {
1215	        long double lb = args.lb_ld, ub = args.ub_ld;
1216	        if (getLongDoubleFromObjectOrReply(c, o, &value_ld, NULL) != C_OK)
1217	            return;
1218	
1219	        /* Reject if the existing value is already Infinity (the increment is
1220	         * checked at parse time in parseIncrExArgumentsOrReply). */
1221	        if (isinf(value_ld)) {
1222	            addReplyError(c, "value cannot be Infinity");
1223	            return;
1224	        }
1225	
1226	        oldvalue_ld = value_ld;
1227	        value_ld += args.incr_ld;
1228	        int overflow = isinf(value_ld);
1229	        if (overflow || value_ld > ub || value_ld < lb) {
1230	            /* Result is infinite or out of [LBOUND, UBOUND]:
1231	             * default: reject (leave key untouched, reply [current_value, 0]);
1232	             * SATURATE: clamp to +/-LDBL_MAX or the breached bound. */
1233	            if (!sat_mode) {
1234	                addReplyArrayLen(c, 2);
1235	                addReplyHumanLongDouble(c, oldvalue_ld);
1236	                addReplyHumanLongDouble(c, 0);
1237	                return;
1238	            }
1239	
1240	            /* SATURATE: clamp the result. */
1241	            if (overflow)
1242	                value_ld = (args.incr_ld >= 0) ? ub : lb;
1243	            else
1244	                value_ld = value_ld > ub ? ub : lb;
1245	        }
1246	
1247	        long double delta = value_ld - oldvalue_ld;
1248	        if (isinf(delta)) {
1249	            /* The applied delta cannot be represented as a valid long double. This can
1250	             * only happen under SATURATE when the saturated result and the
1251	             * prior value sit at opposite ends of the type range. */
1252	            addReplyError(c, "applied increment would be Infinity");
1253	            return;
1254	        }
1255	
1256	        addReplyArrayLen(c, 2);
1257	        addReplyHumanLongDouble(c, value_ld);
1258	        addReplyHumanLongDouble(c, delta);
1259	    } else {
1260	        long long lb = args.lb_ll, ub = args.ub_ll;
1261	        if (getLongLongFromObjectOrReply(c, o, &value_ll, NULL) != C_OK)
1262	            return;
1263	
1264	        oldvalue_ll = value_ll;
1265	        int overflow = add_overflow_ll(oldvalue_ll, args.incr_ll, &value_ll);
1266	        if (overflow || value_ll > ub || value_ll < lb) {
1267	            /* Result overflows long long or is out of [LBOUND, UBOUND]:
1268	             * default: reject (leave key untouched, reply [current_value, 0]);
1269	             * SATURATE: clamp to LLONG_MAX/LLONG_MIN or the breached bound. */
1270	            if (!sat_mode) {
1271	                addReplyArrayLen(c, 2);
1272	                addReplyLongLong(c, oldvalue_ll);
1273	                addReplyLongLong(c, 0);
1274	                return;
1275	            }
1276	
1277	            /* SATURATE: clamp the result. */
1278	            if (overflow)
1279	                value_ll = (args.incr_ll >= 0) ? ub : lb;
1280	            else
1281	                value_ll = value_ll > ub ? ub : lb;
1282	        }
1283	
1284	        long long delta = 0;
1285	        if (sub_overflow_ll(value_ll, oldvalue_ll, &delta)) {
1286	            /* The applied delta cannot be represented as a long long. This can
1287	             * only happen under SATURATE when the saturated result and the
1288	             * prior value sit at opposite ends of the type range. */
1289	            addReplyError(c, "applied increment would overflow");
1290	            return;
1291	        }
1292	
1293	        addReplyArrayLen(c, 2);
1294	        addReplyLongLong(c, value_ll);
1295	        addReplyLongLong(c, delta);
1296	    }
1297	
1298	    /* If the expire time is already elapsed, it is propagated as DEL/UNLINK */
1299	    int has_expiry = o && (kvobjGetExpire(o) != -1);
1300	    int set_new_expire = args.expire_ms && (!(args.flags & OBJ_INCREX_ENX) || !has_expiry);
1301	    if (set_new_expire && checkAlreadyExpired(args.expire_ms)) {
1302	        if (o) {
1303	            int deleted = dbGenericDelete(c->db, c->argv[1], server.lazyfree_lazy_expire, DB_FLAG_KEY_EXPIRED);
1304	            serverAssert(deleted);
1305	            robj *aux = server.lazyfree_lazy_expire ? shared.unlink : shared.del;
1306	            rewriteClientCommandVector(c, 2, aux, c->argv[1]);
1307	            keyModified(c, c->db, c->argv[1], NULL, 1);
1308	            notifyKeyspaceEvent(NOTIFY_GENERIC, "del", c->argv[1], c->db->id);
1309	            server.dirty++;
1310	        }
1311	        server.stat_expiredkeys++;
1312	        return;
1313	    }
1314	
1315	    if (!byfloat && o && o->refcount == 1 && o->encoding == OBJ_ENCODING_INT &&
1316	        value_ll >= LONG_MIN && value_ll <= LONG_MAX)
1317	    {
1318	        new = o;
1319	        o->ptr = (void*)((long)value_ll);
1320	        updateKeysizesHist(c->db, OBJ_STRING, (int64_t)sdigits10(oldvalue_ll), (int64_t)sdigits10(value_ll));
1321	    } else {
1322	        if (byfloat)
1323	            new = createStringObjectFromLongDouble(value_ld, 1);
1324	        else
1325	            new = createStringObjectFromLongLongForValue(value_ll);
1326	        if (o)
1327	            dbReplaceValueWithLink(c->db, c->argv[1], &new, link);
1328	        else
1329	            dbAddByLink(c->db, c->argv[1], &new, &link);
1330	    }
1331	
1332	    /* Replicate INCREX as SET with the final value to avoid float precision
1333	     * or formatting drift across replicas / AOF restart. The TTL clause is:
1334	     *   PERSIST          -> SET <key> <result>
1335	     *   sets a new TTL   -> SET <key> <result> PXAT <timestamp>
1336	     *   otherwise        -> SET <key> <result> KEEPTTL  (no expire option,
1337	     *                       or ENX hit on a key that already has a TTL) */
1338	    int persist_notify = 0, expire_notify = 0;
1339	    if (args.flags & OBJ_INCREX_PERSIST) {
1340	        persist_notify = removeExpire(c->db, c->argv[1]);
1341	        rewriteClientCommandVector(c, 3, shared.set, c->argv[1], new);
1342	    } else if (set_new_expire) {
1343	        new = setExpire(c, c->db, c->argv[1], args.expire_ms);
1344	        expire_notify = 1;
1345	        robj *milliseconds_obj = createStringObjectFromLongLong(args.expire_ms);
1346	        rewriteClientCommandVector(c, 5, shared.set, c->argv[1], new, shared.pxat, milliseconds_obj);
1347	        decrRefCount(milliseconds_obj);
1348	    } else {
1349	        rewriteClientCommandVector(c, 4, shared.set, c->argv[1], new, shared.keepttl);
1350	    }
1351	
1352	    keyModified(c, c->db, c->argv[1], new, 1);
1353	    server.dirty++;
1354	
1355	    notifyKeyspaceEvent(NOTIFY_STRING, byfloat ? "incrbyfloat" : "incrby", c->argv[1], c->db->id);
1356	    if (persist_notify)
1357	        notifyKeyspaceEvent(NOTIFY_GENERIC, "persist", c->argv[1], c->db->id);
1358	    if (expire_notify)
1359	        notifyKeyspaceEvent(NOTIFY_GENERIC, "expire", c->argv[1], c->db->id);
1360	
1361	    /* A KSN handler may reallocate the kvobj and replace it in the dict. The local
1362	     * pointers `o`/`new` may then point to a stale object and must not be dereferenced;
1363	     * null them out. The object is not freed though if rewriteClientCommandVector()
1364	     * above incremented its refcount, so c->argv keeps it alive for command propagation. */
1365	    KSN_INVALIDATE_KVOBJ(o);
1366	    KSN_INVALIDATE_KVOBJ(new);
1367	}
