1369	void appendCommand(client *c) {
1370	    size_t totlen;
1371	    robj *append;
1372	    kvobj *o;
1373	    size_t oldsize = 0;
1374	
1375	    dictEntryLink link;
1376	    o = lookupKeyWriteWithLink(c->db,c->argv[1],&link);
1377	    if (o == NULL) {
1378	        /* Create the key */
1379	        c->argv[2] = tryObjectEncoding(c->argv[2]);
1380	        o = dbAddByLink(c->db, c->argv[1], &c->argv[2], &link);
1381	        incrRefCount(c->argv[2]);
1382	        totlen = stringObjectLen(c->argv[2]);
1383	    } else {
1384	        /* Key exists, check type */
1385	        if (checkType(c,o,OBJ_STRING))
1386	            return;
1387	
1388	        /* "append" is an argument, so always an sds */
1389	        append = c->argv[2];
1390	        size_t append_len = sdslen(append->ptr);
1391	        if (checkStringLength(c,stringObjectLen(o),append_len) != C_OK)
1392	            return;
1393	
1394	        /* Append the value */
1395	        o = dbUnshareStringValueByLink(c->db,c->argv[1],o,link);
1396	        if (server.memory_tracking_enabled)
1397	            oldsize = kvobjAllocSize(o);
1398	        o->ptr = sdscatlen(o->ptr,append->ptr,append_len);
1399	        if (server.memory_tracking_enabled)
1400	            updateSlotAllocSize(c->db, getKeySlot(c->argv[1]->ptr), o, oldsize, kvobjAllocSize(o));
1401	        totlen = sdslen(o->ptr);
1402	        int64_t oldlen = totlen - append_len;
1403	        updateKeysizesHist(c->db, OBJ_STRING, oldlen, totlen);
1404	    }
1405	    keyModified(c,c->db,c->argv[1],o,1);
1406	    notifyKeyspaceEvent(NOTIFY_STRING,"append",c->argv[1],c->db->id);
1407	    server.dirty++;
1408	
1409	    addReplyLongLong(c,totlen);
1410	}
