1419	/* LCS key1 key2 [LEN] [IDX] [MINMATCHLEN <len>] [WITHMATCHLEN] */
1420	void lcsCommand(client *c) {
1421	    uint32_t i, j;
1422	    long long minmatchlen = 0;
1423	    sds a = NULL, b = NULL;
1424	    int getlen = 0, getidx = 0, withmatchlen = 0;
1425	
1426	    kvobj *obja = lookupKeyRead(c->db, c->argv[1]);
1427	    kvobj *objb = lookupKeyRead(c->db, c->argv[2]);
1428	    if ((obja && obja->type != OBJ_STRING) ||
1429	        (objb && objb->type != OBJ_STRING))
1430	    {
1431	        addReplyError(c,
1432	            "The specified keys must contain string values");
1433	        /* Don't cleanup the objects, we need to do that
1434	         * only after calling getDecodedObject(). */
1435	        obja = NULL;
1436	        objb = NULL;
1437	        goto cleanup;
1438	    }
1439	    obja = obja ? getDecodedObject(obja) : createStringObject("",0);
1440	    objb = objb ? getDecodedObject(objb) : createStringObject("",0);
1441	    a = obja->ptr;
1442	    b = objb->ptr;
1443	
1444	    for (j = 3; j < (uint32_t)c->argc; j++) {
1445	        char *opt = c->argv[j]->ptr;
1446	        int moreargs = (c->argc-1) - j;
1447	
1448	        if (!strcasecmp(opt,"IDX")) {
1449	            getidx = 1;
1450	        } else if (!strcasecmp(opt,"LEN")) {
