149	static void dbgAssertHist(kvstore *kvs, keysizesHist hist,
150	                          size_t (*fn)(kvobj *), const char *name) {
151	    /* Scan DB and build expected histogram by scanning all keys */
152	    int64_t scanHist[MAX_KEYSIZES_TYPES][MAX_KEYSIZES_BINS] = {{0}};
153	    dictEntry *de;
154	    kvstoreIterator kvs_it;
155	    kvstoreIteratorInit(&kvs_it, kvs);
156	    while ((de = kvstoreIteratorNext(&kvs_it)) != NULL) {
157	        kvobj *kv = dictGetKV(de);
158	        if (kv->type < OBJ_TYPE_BASIC_MAX) {
159	            int64_t len = fn(kv);
160	            scanHist[kv->type][(len == 0) ? 0 : log2ceil(len) + 1]++;
161	        }
162	    }
163	    kvstoreIteratorReset(&kvs_it);
164	    for (int type = 0; type < OBJ_TYPE_BASIC_MAX; type++) {
165	        volatile int64_t *keysizesHist = hist[type];
166	        for (int i = 0; i < MAX_KEYSIZES_BINS; i++) {
167	            if (scanHist[type][i] == keysizesHist[i])
168	                continue;
169	
170	            /* print scanStr vs. expected histograms for debugging */
171	            char scanStr[500] = {0}, keysizesStr[500] = {0};
172	            int l1 = 0, l2 = 0;
173	            for (int j = 0; (j < MAX_KEYSIZES_BINS) && (l1 < 500) && (l2 < 500); j++) {
174	                if (scanHist[type][j])
175	                    l1 += snprintf(scanStr + l1, sizeof(scanStr) - l1,
176	                                        "[%d]=%"PRId64" ", j, scanHist[type][j]);
177	                if (keysizesHist[j])
178	                    l2 += snprintf(keysizesStr + l2, sizeof(keysizesStr) - l2,
179	                                            "[%d]=%"PRId64" ", j, keysizesHist[j]);
180	            }
181	            serverPanic("%s: type=%d\nscanStr=%s\nkeysizes=%s\n",
182	                        name, type, scanStr, keysizesStr);
183	        }
184	    }
185	}
