508	/* This is a special version of dbAdd() that is used only when loading
509	 * keys from the RDB file: the key is passed as an SDS string that is
510	 * copied by the function and freed by the caller.
511	 *
512	 * Moreover this function will not abort if the key is already busy, to
513	 * give more control to the caller, nor will signal the key as ready
514	 * since it is not useful in this context.
515	 *
516	 * If added to db, returns pointer to the object, Otherwise NULL is returned.
517	 */
518	kvobj *dbAddRDBLoad(redisDb *db, sds key, robj **valref, const KeyMetaSpec *keyMetaSpec) {
519	    /* Add new kvobj to the db. */
520	    int slot = getKeySlot(key);
521	
522	    dictEntryLink link, bucket;
523	    link = kvstoreDictFindLink(db->keys, slot, key, &bucket);
524	
525	    /* If already exists, return NULL */
526	    if (link != NULL)
527	        return NULL;
528	
529	    /* Create kvobj with metadata bits from KeyMetaSpec */
530	    robj *val = *valref;
531	    kvobj *kv = kvobjSet(key, val, keyMetaSpec->metabits);
532	    initObjectLRUOrLFU(kv);
533	    kvstoreDictSetAtLink(db->keys, slot, kv, &bucket, 1);
534	
535	    /* Handle metadata (expiration and modules metadata) */
536	    if (keyMetaSpec->metabits) {
537	        if (keyMetaSpec->metabits & KEY_META_MASK_EXPIRE) {
538	            /* Expiry is always the first meta (from last) */
539	            long long expire = keyMetaSpec->meta[KEY_META_ID_MAX - 1];
540	            kvobj *newkv = setExpireByLink(NULL, db, key, expire, bucket);
541	            serverAssert(newkv == kv);
542	        }
543	
544	        /* memcpy modules metadata to beginning of kvobj */
545	        if (keyMetaSpec->metabits & KEY_META_MASK_MODULES)
546	            memcpy(kvobjGetAllocPtr(kv),
547	                   keyMetaSpec->meta + KEY_META_ID_MAX - keyMetaSpec->numMeta,
548	                   keyMetaSpec->numMeta * sizeof(uint64_t));
549	    }
550	
551	    updateKeysizesHist(db, kv->type, -1, (int64_t) getObjectLength(kv));
552	    if (server.memory_tracking_enabled)
553	        updateSlotAllocSize(db, slot, kv, -1, kvobjAllocSize(kv));
554	    return *valref = kv;
555	}
