557	/**
558	 * Overwrite an existing key's value in db with a new value.
559	 *
560	 * - If the reference count of 'valref' is 1 the ownership of the value is
561	 *   transferred to this function. The value may be reallocated, potentially
562	 *   invalidating any external references to it. The (potentially reallocated)
563	 *   value is stored in the database, and the 'valref' pointer is updated to
564	 *   reflect the new allocation, if one occurs.
565	 * - The reference counter of the value referenced by 'valref' is not incremented
566	 *   so the caller must refrain from releasing it using decrRefCount after this
567	 *   function is called.
568	 * - This function does not modify the expire time of the existing key.
569	 * - The 'overwrite' flag is an indication whether this is done as part of a
570	 *   complete replacement of their key, which can be thought as a deletion and
571	 *   replacement (in which case we need to emit deletion signals), or just an
572	 *   update of a value of an existing key (when false).
573	 * - The `link` is optional, can save lookup, if provided.
574	 */
575	static void dbSetValue(redisDb *db, robj *key, robj **valref, dictEntryLink link, 
576	                       int overwrite, int updateKeySizes, int keepTTL) {
577	    int freeModuleMeta = 0;
578	    robj *val = *valref;
579	    int slot = getKeySlot(key->ptr);
580	    size_t oldsize = 0;
581	    if (!link) {
582	        link = kvstoreDictFindLink(db->keys, slot, key->ptr, NULL);
583	        serverAssertWithInfo(NULL, key, link != NULL); /* expected to exist */
584	    }
585	    kvobj *old = dictGetKV(*link);
586	    kvobj *kvNew;
587	
588	    int64_t oldlen = (int64_t) getObjectLength(old);
589	    int oldtype = old->type;
590	
591	    /* if hash with HFEs, take care to remove from global HFE DS before attempting
592	     * to manipulate and maybe free kvOld object */
593	    if (old->type == OBJ_HASH)
594	        estoreRemove(db->subexpires, slot, old);
595	
596	    if (old->type == OBJ_STREAM)
597	        streamKeyRemoved(db, key, old);
598	
599	    long long oldExpire = getExpire(db, key->ptr, old);
600	
601	    /* All metadata will be kept if not `overwrite` for the new object  */
602	    uint32_t newKeyMetaBits = old->metabits;
603	    /* clear expire if not keepTTL or no old expire */
604	    if ((!keepTTL) || (oldExpire == -1))
605	        newKeyMetaBits &= ~KEY_META_MASK_EXPIRE; 
606	
607	    if (overwrite) {
608	        /* On overwrite, discard module metadata excluding expire if set */
609	        newKeyMetaBits &= KEY_META_MASK_EXPIRE;
610	        /* RM_StringDMA may call dbUnshareStringValue which may free val, so we
611	         * need to incr to retain old */
612	        incrRefCount(old);
613	
614	        /* Free related metadata. Ignore builtin metadata (currently only expire) */
615	        if (getModuleMetaBits(old->metabits)) {
616	            keyMetaOnUnlink(db, key, old);
617	            freeModuleMeta = 1;
618	        }
619	
620	        /* Although the key is not really deleted from the database, we regard
621	         * overwrite as two steps of unlink+add, so we still need to call the unlink
622	         * callback of the module. */
623	        moduleNotifyKeyUnlink(key,old,db->id,DB_FLAG_KEY_OVERWRITE);
624	        /* We want to try to unblock any module clients or clients using a blocking XREADGROUP */
625	        signalDeletedKeyAsReady(db,key,old->type);
626	        decrRefCount(old);
627	        /* Because of RM_StringDMA, old may be changed, so we need get old again */
628	        old = dictGetKV(*link);
629	    }
630	    if (server.memory_tracking_enabled)
631	        oldsize = kvobjAllocSize(old);
632	
633	    if ((old->refcount == 1 && old->encoding != OBJ_ENCODING_EMBSTR) &&
634	        (val->refcount == 1 && val->encoding != OBJ_ENCODING_EMBSTR) && (!freeModuleMeta))
635	    {
636	        /* Keep old object in the database. Just swap it's ptr, type and
637	         * encoding with the content of val. */
638	        robj tmp = *old;
639	        old->type = val->type;
640	        old->encoding = val->encoding;
641	        old->ptr = val->ptr;
642	        val->type = tmp.type;
643	        val->encoding = tmp.encoding;
644	        val->ptr = tmp.ptr;
645	        /* Set new to old to keep the old object. Set old to val to be freed below. */
646	        kvNew = old;
647	        old = val;
648	
649	        /* Handle TTL in the optimization path */
650	        if ((!keepTTL) && (oldExpire >= 0))
651	            removeExpire(db, key);
652	    } else {
653	        /* Replace the old value at its location in the key space. */
654	        val->lru = old->lru;
655	        
656	        kvNew = kvobjSet(key->ptr, val, newKeyMetaBits);
657	        kvstoreDictSetAtLink(db->keys, slot, kvNew, &link, 0);
658	
659	        /* if expiry replace the old value at its location in the expire space. */
660	        if (oldExpire != -1) {
661	            if (keepTTL) {
662	                kvobjSetExpire(kvNew, oldExpire); /* kvNew not reallocated here */
663	                dictEntryLink exLink = kvstoreDictFindLink(db->expires, slot,
664	                                                           key->ptr, NULL);
665	                serverAssertWithInfo(NULL, key, exLink != NULL);
666	                kvstoreDictSetAtLink(db->expires, slot, kvNew, &exLink, 0);
667	            } else {
668	                kvstoreDictDelete(db->expires, slot, key->ptr);
669	            }
670	        }
671	
672	        if (newKeyMetaBits & KEY_META_MASK_MODULES)
673	            keyMetaTransition(old, kvNew);
674	    }
675	
676	    /* Remove old key and add new key to KEYSIZES histogram */
677	    int64_t newlen = (int64_t) getObjectLength(kvNew);
678	    if (updateKeySizes) {
679	        /* Save one call if old and new are the same type */
680	        if (oldtype == kvNew->type) {
681	            updateKeysizesHist(db, oldtype, oldlen, newlen);
682	        } else {
683	            updateKeysizesHist(db, oldtype, oldlen, -1);
684	            updateKeysizesHist(db, kvNew->type, -1, newlen);
685	        }
686	    }
687	
688	    if (server.memory_tracking_enabled) {
689	        /* Save one call if old and new are the same type */
690	        if (oldtype == kvNew->type) {
691	            updateSlotAllocSize(db, slot, kvNew, oldsize, kvobjAllocSize(kvNew));
692	        } else {
693	            updateSlotAllocSize(db, slot, old, oldsize, -1);
694	            updateSlotAllocSize(db, slot, kvNew, -1, kvobjAllocSize(kvNew));
695	        }
696	    }
697	
698	    if (server.io_threads_num > 1 && old->encoding == OBJ_ENCODING_RAW && old->refcount == 1) {
699	        /* In multi-threaded mode, the OBJ_ENCODING_RAW string object usually is
700	         * allocated in the IO thread, so we defer the free to the IO thread.
701	         * Besides, we never free a string object in BIO threads, so, even with
702	         * lazyfree-lazy-server-del enabled, a fallback to main thread freeing
703	         * due to defer free failure doesn't go against the config intention. */
704	        tryDeferFreeClientObject(server.current_client, DEFERRED_OBJECT_TYPE_ROBJ, old);
705	    } else if (server.lazyfree_lazy_server_del) {
706	        freeObjAsync(key, old, db->id);
707	    } else {
708	        decrRefCount(old);
709	    }
710	    *valref = kvNew;
711	}
