727	/* High level Set operation. This function can be used in order to set
728	 * a key, whatever it was existing or not, to a new object.
729	 *
730	 * 1) The value may be reallocated when adding it to the database. The value
731	 *    pointer 'valref' is updated to point to the reallocated object. The
732	 *    reference count of the value object is *not* incremented.
733	 * 2) clients WATCHing for the destination key notified.
734	 * 3) The expire time of the key is reset (the key is made persistent),
735	 *    unless 'SETKEY_KEEPTTL' is enabled in flags.
736	 * 4) The key lookup can take place outside this interface outcome will be
737	 *    delivered with 'SETKEY_ALREADY_EXIST' or 'SETKEY_DOESNT_EXIST'
738	 *
739	 * All the new keys in the database should be created via this interface.
740	 * The client 'c' argument may be set to NULL if the operation is performed
741	 * in a context where there is no clear client performing the operation. */
742	void setKey(client *c, redisDb *db, robj *key, robj **valref, int flags) {
743	    setKeyByLink(c, db, key, valref, flags, NULL);
744	}
745	
746	/* Like setKey(), but accepts an optional link
747	 *
748	 * - If flags is set with SETKEY_ALREADY_EXIST, then `link` must be provided
749	 * - If flags is set with SETKEY_DOESNT_EXIST, then `link` is optional. If
750	 *   provided, it will point to the bucket where the key should be added.
751	 * - If flag is not set (0) then add or update key, and `link` must be NULL
752	 * On return, link get updated, by need, to the inserted kvobj.
753	 */
754	void setKeyByLink(client *c, redisDb *db, robj *key, robj **valref, int flags, dictEntryLink *plink) {
755	    dictEntryLink dummy = NULL, *link = plink ? plink : &dummy;
756	    int exists;
757	    kvobj *oldval = NULL;
758	
759	    if (flags & SETKEY_ALREADY_EXIST) {
760	        debugServerAssert((*link) != NULL);
761	        oldval = dictGetKV(**link);
762	        exists = 1;
763	    } else if (flags & SETKEY_DOESNT_EXIST) {
764	        /* link is optional */
765	        exists = 0;
766	    } else {
767	        /* Add or update key */
768	        oldval = lookupKeyWriteWithLink(db, key, link);
769	        exists = oldval != NULL;
770	    }
771	
772	    if (exists) {
773	        int oldtype = oldval->type;
774	        int newtype = (*valref)->type;
775	
776	        /* Update the value of an existing key */
777	        dbSetValue(db, key, valref, *link, 1, 1, flags & SETKEY_KEEPTTL);
778	
779	        /* Notify keyspace events for override and type change */
780	        notifyKeyspaceEvent(NOTIFY_OVERWRITTEN, "overwritten", key, db->id);
781	        if (oldtype != newtype)
782	            notifyKeyspaceEvent(NOTIFY_TYPE_CHANGED, "type_changed", key, db->id);
783	    } else {
784	        /* Add the new key to the database */
785	        dbAddByLink(db, key, valref, link);
786	    }
787	
788	    /* Signal key modification and update LRM timestamp. */
789	    keyModified(c,db,key,*valref,!(flags & SETKEY_NO_SIGNAL));
790	}
