843	/* Helper for sync and async delete. */
844	int dbGenericDelete(redisDb *db, robj *key, int async, int flags) {
845	    dictEntryLink link;
846	    int table;
847	    int slot = getKeySlot(key->ptr);
848	    link = kvstoreDictTwoPhaseUnlinkFind(db->keys, slot, key->ptr, &table);
849	
850	    if (link) {
851	        kvobj *kv = dictGetKV(*link);
852	
853	        int64_t oldlen = (int64_t) getObjectLength(kv);
854	        int type = kv->type;
855	
856	        /* If hash object with expiry on fields, remove it from HFE DS of DB */
857	        if (type == OBJ_HASH)
858	            estoreRemove(db->subexpires, slot, kv);
859	
860	        /* If stream with IDMP tracking, remove it from stream_idmp_keys */
861	        if (type == OBJ_STREAM)
862	            streamKeyRemoved(db, key, kv);
863	
864	        /* RM_StringDMA may call dbUnshareStringValue which may free kv, so we
865	         * need to incr to retain kv */
866	        incrRefCount(kv); /* refcnt=1->2 */
867	        /* Metadata hook: notify unlink for key metadata cleanup. */
868	        if (getModuleMetaBits(kv->metabits)) keyMetaOnUnlink(db, key, kv);
869	        /* Tells the module that the key has been unlinked from the database. */
870	        moduleNotifyKeyUnlink(key, kv, db->id, flags);
871	        /* We want to try to unblock any module clients or clients using a blocking XREADGROUP */
872	        signalDeletedKeyAsReady(db,key,type);
873	        /* We should call decr before freeObjAsync. If not, the refcount may be
874	         * greater than 1, so freeObjAsync doesn't work */
875	        decrRefCount(kv);
876	
877	        /* Because of dbUnshareStringValue, the val in db may change. */
878	        kv = dictGetKV(*link);
879	        
880	        /* if expirable, delete an entry from the expires dict is not decrRefCount of kvobj */
881	        if (kvobjGetExpire(kv) != -1)
882	            kvstoreDictDelete(db->expires, slot, key->ptr);
883	
884	        if (async) {
885	            if (server.memory_tracking_enabled)
886	                updateSlotAllocSize(db, slot, kv, kvobjAllocSize(kv), -1);
887	            freeObjAsync(key, kv, db->id);
888	            /* Set the key to NULL in the main dictionary. */
889	            kvstoreDictSetAtLink(db->keys, slot, NULL, &link, 0);
890	        }
891	        kvstoreDictTwoPhaseUnlinkFree(db->keys, slot, link, table);
892	
893	        /* remove key from histogram */
894	        if(!(flags & DB_FLAG_NO_UPDATE_KEYSIZES))
895	            updateKeysizesHist(db, type, oldlen, -1);
896	        return 1;
897	    } else {
898	        return 0;
899	    }
900	}
