930	/* Prepare the string object stored at 'key' to be modified destructively
931	 * to implement commands like SETBIT or APPEND.
932	 *
933	 * An object is usually ready to be modified unless one of the two conditions
934	 * are true:
935	 *
936	 * 1) The object 'o' is shared (refcount > 1), we don't want to affect
937	 *    other users.
938	 * 2) The object encoding is not "RAW".
939	 *
940	 * If the object is found in one of the above conditions (or both) by the
941	 * function, an unshared / not-encoded copy of the string object is stored
942	 * at 'key' in the specified 'db'. Otherwise the object 'o' itself is
943	 * returned.
944	 *
945	 * USAGE:
946	 *
947	 * The object 'o' is what the caller already obtained by looking up 'key'
948	 * in 'db', the usage pattern looks like this:
949	 *
950	 * o = lookupKeyWrite(db,key);
951	 * if (checkType(c,o,OBJ_STRING)) return;
952	 * o = dbUnshareStringValue(db,key,o);
953	 *
954	 * At this point the caller is ready to modify the object, for example
955	 * using an sdscat() call to append some data, or anything else.
956	 */
957	kvobj *dbUnshareStringValue(redisDb *db, robj *key, kvobj *kv) {
958	    return dbUnshareStringValueByLink(db,key,kv,NULL);
959	}
960	
961	/* Like dbUnshareStringValue(), but accepts a optional link,
962	 * which can be used if we already have one, thus saving the dbFind call. */
963	kvobj *dbUnshareStringValueByLink(redisDb *db, robj *key, kvobj *o, dictEntryLink link) {
964	    serverAssert(o->type == OBJ_STRING);
965	    if (o->refcount != 1 || o->encoding != OBJ_ENCODING_RAW) {
966	        robj *decoded = getDecodedObject(o);
967	        o = createRawStringObject(decoded->ptr, sdslen(decoded->ptr));
968	        decrRefCount(decoded);
969	        dbReplaceValueWithLink(db, key, &o, link);
970	    }
971	    return o;
972	}
