974	/* Remove all keys from the database(s) structure. The dbarray argument
975	 * may not be the server main DBs (could be a temporary DB).
976	 *
977	 * The dbnum can be -1 if all the DBs should be emptied, or the specified
978	 * DB index if we want to empty only a single database.
979	 * The function returns the number of keys removed from the database(s). */
980	long long emptyDbStructure(redisDb *dbarray, int dbnum, int async,
981	                           void(callback)(dict*))
982	{
983	    long long removed = 0;
984	    int startdb, enddb;
985	
986	    if (dbnum == -1) {
987	        startdb = 0;
988	        enddb = server.dbnum-1;
989	    } else {
990	        startdb = enddb = dbnum;
991	    }
992	
993	    for (int j = startdb; j <= enddb; j++) {
994	        removed += kvstoreSize(dbarray[j].keys);
995	        if (async) {
996	            emptyDbAsync(&dbarray[j]);
997	        } else {
998	            /* Destroy sub-expires before deleting the kv-objects since ebuckets
999	             * data structure is embedded in the stored kv-objects. */
1000	            estoreEmpty(dbarray[j].subexpires);
1001	            kvstoreEmpty(dbarray[j].keys, callback);
1002	            kvstoreEmpty(dbarray[j].expires, callback);
1003	            dictEmpty(dbarray[j].stream_idmp_keys, callback);
1004	        }
1005	        /* Because all keys of database are removed, reset average ttl. */
1006	        dbarray[j].avg_ttl = 0;
1007	        dbarray[j].expires_cursor = 0;
1008	    }
1009	
1010	    return removed;
1011	}
