1198	/* Return the set of flags to use for the emptyData() call for FLUSHALL
1199	 * and FLUSHDB commands.
1200	 *
1201	 * sync: flushes the database in an sync manner.
1202	 * async: flushes the database in an async manner.
1203	 * no option: determine sync or async according to the value of lazyfree-lazy-user-flush.
1204	 *
1205	 * On success C_OK is returned and the flags are stored in *flags, otherwise
1206	 * C_ERR is returned and the function sends an error to the client. */
1207	int getFlushCommandFlags(client *c, int *flags) {
1208	    /* Parse the optional ASYNC option. */
1209	    if (c->argc == 2 && !strcasecmp(c->argv[1]->ptr,"sync")) {
1210	        *flags = EMPTYDB_NO_FLAGS;
1211	    } else if (c->argc == 2 && !strcasecmp(c->argv[1]->ptr,"async")) {
1212	        *flags = EMPTYDB_ASYNC;
1213	    } else if (c->argc == 1) {
1214	        *flags = server.lazyfree_lazy_user_flush ? EMPTYDB_ASYNC : EMPTYDB_NO_FLAGS;
1215	    } else {
1216	        addReplyErrorObject(c,shared.syntaxerr);
1217	        return C_ERR;
