1234	     * for large databases, flushdb blocks for long anyway, so a bit more won't
1235	     * harm and this way the flush and purge will be synchronous. */
1236	    if (!(flags & EMPTYDB_ASYNC)) {
1237	        /* Only clear the current thread cache.
1238	         * Ignore the return call since this will fail if the tcache is disabled. */
