1259	/* CB function on blocking ASYNC FLUSH/TRIM completion.
1260	 * We will unblock the client and send the proper reply if provided. */
1261	void kvsAsyncFreeDoneCB(uint64_t client_id, void *userdata) {
1262	
1263	    /* If ASM Trim context provided, apply histogram delta */
1264	    asmTrimCtx *ctx = userdata;
1265	    if (ctx) {
1266	        kvstoreMetadata *meta = kvstoreGetMetadata(server.db[0].keys);
1267	        /* Apply histogram delta only if target_kvstore hasn't changed */
1268	        if (ctx->target_kvstore == server.db[0].keys && meta) {
1269	            for (int type = 0; type < MAX_KEYSIZES_TYPES; type++) {
1270	                for (int bin = 0; bin < MAX_KEYSIZES_BINS; bin++) {
1271	                    meta->keysizes_hist[type][bin] -= ctx->delta_keysizes_hist[type][bin];
1272	                    meta->allocsizes_hist[type][bin] -= ctx->delta_allocsizes_hist[type][bin];
1273	                }
1274	            }
1275	        }
1276	        /* Decrement counter unconditionally to track job completion. If kvstore was
1277	         * replaced (e.g., by FLUSHALL), the new histogram is already consistent (reset
1278	         * to 0 for empty DB), so it's safe to resume assertions when counter reaches 0. */
1279	        asmBgTrimCounterDecr();
1280	    }
1281	
1282	    unblockClientForAsyncFlush(client_id, (ctx) ? ctx->slots : NULL);
1283	
1284	    /* Release context and slots */
1285	    asmTrimCtxRelease(ctx);
1286	}
