1438	/* DELEX key [IFEQ match-value|IFNE match-value|IFDEQ match-digest|IFDNE match-digest]
1439	 *
1440	 * Conditionally removes the specified key. A key is ignored if it does not
1441	 * exist.
1442	 * If no condition is specified the behavior is the same as DEL command.
1443	 * If condition is specified the key must be of STRING type.
1444	 *
1445	 * IFEQ/IFNE conditions check the match-value against the value of the key
1446	 * IFDEQ/IFDNE conditions check the match-digest against the digest of the key's value.*/
1447	void delexCommand(client *c) {
1448	    kvobj *o;
1449	    int deleted = 0, should_delete = 0;
1450	
1451	    /* If there are no conditions specified we just delete the key */
1452	    if (c->argc == 2) {
1453	        delGenericCommand(c, server.lazyfree_lazy_server_del);
1454	        return;
1455	    }
1456	
1457	    /* If we have more than two arguments the next two are condition and
1458	     * match-value */
1459	    if (c->argc != 4) {
1460	        addReplyErrorArity(c);
1461	        return;
1462	    }
1463	
1464	    robj *key = c->argv[1];
1465	    o = lookupKeyRead(c->db, key);
1466	    if (o == NULL) {
1467	        addReplyLongLong(c, 0);
1468	        return;
1469	    }
1470	
1471	    /* If any conditions are specified the only supported key type for now is
1472	     * string */
1473	    if (o->type != OBJ_STRING) {
1474	        addReplyError(c, "Key should be of string type if conditions are specified");
1475	        return;
1476	    }
1477	
1478	    char *condition = c->argv[2]->ptr;
1479	    if (!strcasecmp("ifeq", condition)) {
1480	        robj *valueobj = getDecodedObject(o);
1481	        sds match_value = c->argv[3]->ptr;
1482	        if (sdscmp(valueobj->ptr, match_value) == 0)
1483	            should_delete = 1;
1484	
1485	        decrRefCount(valueobj);
1486	    } else if (!strcasecmp("ifne", condition)) {
1487	        robj *valueobj = getDecodedObject(o);
1488	        sds match_value = c->argv[3]->ptr;
1489	        if (sdscmp(valueobj->ptr, match_value) != 0)
1490	           should_delete = 1;
1491	
1492	        decrRefCount(valueobj);
1493	    } else if (!strcasecmp("ifdeq", condition)) {
1494	        if (validateHexDigest(c, c->argv[3]->ptr) != C_OK)
1495	            return;
1496	
1497	        sds current_digest = stringDigest(o);
1498	        if (strcasecmp(current_digest, c->argv[3]->ptr) == 0)
1499	            should_delete = 1;
1500

80	 * Arguments:
81	 *   valref: A pointer to the robj to be set. This argument may be updated by the function.
82	 *           The object is expected to have a refcount of 1, allowing its ownership to be
83	 *           transferred directly to the database to avoid making a copy. If needed, the
84	 *           function will replace *valref with a new allocation and increment its refcount
85	 *           so that both the database and the caller maintain valid references.
86	 */
87	void setGenericCommand(client *c, int flags, robj *key, robj **valref, robj *expire,
88	                       int unit, robj *match_value, robj *ok_reply, robj *abort_reply)
89	{
90	    long long milliseconds = 0; /* initialized to avoid any harmless warning */
91	    int found = 0;
92	    int setkey_flags = 0;
93	    int relative_ttl = (flags & (OBJ_EX|OBJ_PX)) != 0; /* EX/PX are relative; EXAT/PXAT are absolute. */
94	
95	    if (expire && getExpireMillisecondsOrReply(c, expire, relative_ttl, unit, &milliseconds) != C_OK) {
96	        return;
97	    }
98	
99	    if (flags & OBJ_SET_GET) {
100	        if (getGenericCommand(c) == C_ERR) return;
101	    }
102	
103	    dictEntryLink link = NULL;
104	    found = (lookupKeyWriteWithLink(c->db,key,&link) != NULL);
105	
106	    if ((flags & OBJ_SET_NX && found) ||
107	        (flags & (OBJ_SET_XX | OBJ_SET_IFEQ | OBJ_SET_IFDEQ) && !found))
